INSERT INTO `skill_content` (`id`, `url`, `title`, `description`, `og_title`, `og_description`, `preview_text`, `html_content`, `id_lang`, `id_skill`) VALUES
(2, 'rychlejsi-porizeni-fotografii-zbozi-pred-expedici', 'Rychlejší pořízení fotografií zboží před expedicí', 'Požadované řešení umožňuje rychle a jednoduše pořídit fotografie zboží při expedici. Fotografie jsou pořizovány s předstihem a ukládány do databáze přímo z Raspberry Pi.', 'Rychlejší pořízení fotografií zboží před expedicí', 'Rychlé a efektivní pořízení fotografií zboží při expedici díky použití Raspberry Pi a kamer konfigurovaných z FileMakeru.', 'Požadované řešení umožňuje rychle a jednoduše pořídit fotografie zboží při expedici. Fotografie jsou pořizovány s předstihem a ukládány do databáze přímo z Raspberry Pi.', '<p>Požadovaným řešením bylo <strong>jednoduše</strong> a <strong>rychle</strong> <strong>vyfotit</strong> stav zásilky <strong>při expedici</strong> zboží ze skladu. Při výdeji se musela každá paleta se zbožím obejít a ručně vyfotit tabletem ze všech stran. Pořízená data poté byla ukládána přes WiFi do databáze na serveru, což <strong>bylo</strong> také <strong>časově</strong> <strong>náročné</strong>.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Cameras_and_box.jpg\" alt=\"Rychlé a jednoduché fotografování stavu zásilky při expedici\" /></div>\n<p>V našem řešení jsme použili <strong>několik</strong> <strong>kamer</strong>, které se připojí k Raspberry Pi. Kamery je tak možné  <strong>přímo</strong> <strong>z FileMakeru</strong> konfigurovat a zaostřit na různé vzdálenosti. Stejně tak <strong>nastavit</strong> pro různé světelné podmínky. Kvůli velké vzdálenosti mezi kamerami a Raspberry Pi se používají <strong>aktivní</strong> <strong>USB kabely.</strong></p>\n<p>Aby se předešlo prodlevě při pořizování snímků na vyžádání, navrhli jsme <strong>ukládání snímků do cache. </strong>Kamery pořizují fotografie opakovaně podle definovaného časového intervalu (např. 1s) a <strong>ukládají je</strong> do cache, přičemž v okamžiku vyžádání jsou tyto fotografie okamžitě odeslány a uloženy do FileMakeru. Uživatel je tak schopen <strong>jedním dotykem</strong> na mobilním zařízení zaevidovat stav zboží do databáze.</p>\n<p>Značné <strong>zrychlení</strong> nastalo nejen díky tomu, že jsou fotografie pořízeny s předstihem, ale i proto, že jsou data odeslána z Raspberry <strong>přímo do databáze na serveru.</strong> Díky tomu nemusí obsluha s iPadem čekat na to, až se data odešlou z iPadu.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Cameras_and_box_diagram.svg\" alt=\"Diagram systému pro rychlé fotografování zboží před expedicí\" /></div>\n<p><strong>Stejné Raspberry Pi</strong> bude spolupracovat i s dalšími zařízeními, které jsou podrobně popsány v našem dalším řešení. Další informace najdete v této ukázce.</p>\n\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"https://www.arducam.com/product/arducam-imx298-usb-camera-with-case-b026801/\">Kamery</a></li>\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n    <li><a href=\"https://www.raspberrypi.org\" target=\"_blank\">Raspberry Pi</a></li>\n    <li><a href=\"/xgode\">Xgode</a></li>\n</ul>', 'cs', 1),
(3, 'taking-photos-of-goods-before-shipping', 'Taking Photos of Goods before Shipping', 'The solution enables quick and easy photography of goods during dispatch. Photos are taken in advance and stored directly in the database from the Raspberry Pi.', 'Taking photos of goods before shipping', 'Quick and efficient photography of goods during dispatch using Raspberry Pi and cameras configured from FileMaker.', 'The solution enables quick and easy photography of goods during dispatch. Photos are taken in advance and stored directly in the database from the Raspberry Pi.', '<p>The required solution was to <strong>quickly</strong> and <strong>easily</strong> <strong>photograph</strong> the condition of the shipment <strong>during</strong> <strong>the</strong> <strong>dispatch</strong> of goods from the warehouse. Each pallet of goods had to be walked around and manually photographed with a tablet from all sides during the dispatch process. The captured data was then stored via WiFi in a database on a server, which was also<strong> time-consuming. </strong></p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Cameras_and_box.jpg\" alt=\"Quick and easy photographing of shipment condition during dispatch\" /></div>\n<p>In our solution, we used <strong>several</strong> <strong>cameras</strong> connected to a Raspberry Pi. These cameras can be <strong>configured</strong> and focused on different distances directly from FileMaker. They can also be <strong>adjusted</strong> for various lighting conditions. Due to the large distance between the cameras and the Raspberry Pi, <strong>active USB cables</strong> are used.</p>\n<p>To avoid delays in capturing images on demand, we designed a <strong>caching system</strong> for storing images. The cameras repeatedly take photos at defined time intervals (e.g., every 1 second) and <strong>store them in the cache</strong>. When an image is requested, these photos are immediately sent and saved to FileMaker. This allows the user to record the condition of the goods in the database with a <strong>single touch</strong> on a mobile device.</p>\n<p>Significant <strong>acceleration</strong> was achieved not only because the photos are taken in advance but also because the data is sent <strong>directly</strong> from the Raspberry Pi <strong>to the server database</strong>. As a result, the operator with the iPad doesn’t have to wait for the data to be sent from the iPad.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Cameras_and_box_diagram.svg\" alt=\"Diagram of the system for quick photographing of goods before dispatch\" /></div>\n<p><strong>The same Raspberry Pi</strong> will also collaborate with other devices, which are described in detail in our next solution. You can find more information in this example.</p>\n\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"https://www.arducam.com/product/arducam-imx298-usb-camera-with-case-b026801/\">Cameras</a></li>\n    <li>\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n    <li><a href=\"https://www.raspberrypi.org\" target=\"_blank\">Raspberry Pi</a></li>\n    <li><a href=\"/xgode\">Xgode</a></li>\n</ul>', 'en', 1),
(4, 'zapujcka-sdilenych-pracovnich-prostredku', 'Zápůjčka sdílených pracovních prostředků', 'Cílem bylo vytvořit efektivní systém pro správu sdílených pracovních prostředků, jako jsou iPhony, iPady, RFID čtečky a další, který zajišťuje přehled o jejich zapůjčení a údržbě.', 'Zápůjčka sdílených pracovních prostředků\r\n', 'Efektivní systém pro správu sdílených pracovních prostředků, zahrnující evidenci zapůjčení, kontrolu stavu zařízení a jejich údržbu.', 'Efektivní systém pro správu sdílených pracovních prostředků, zahrnující evidenci zapůjčení, kontrolu stavu zařízení a jejich údržbu.', '<p>Cílem bylo vytvořit <strong>efektivní systém pro správu sdílených pracovních prostředků</strong> ve skříni, která zahrnuje zařízení jako iPhony, iPady, RFID čtečky, tiskárny, váhy… Bylo potřeba zajistit, aby se zařízení neztrácela, evidovat jejich pozici, stav zapůjčení, termíny vrácení, jejich pravidelnou údržbu a mít <strong>přehled</strong> o všech uplynulých údržbách. V neposlední řadě bylo důležité mít možnost evidence kompletního obsahu balení při vrácení, sledování odpovědnosti za poškození a <strong>kontrolu stavu</strong> zařízení při jejich zapůjčení a vrácení.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Shared_resources.jpg\" alt=\"Efektivní správa sdílených pracovních prostředků\" /></div>\n<p>Pro realizaci řešení jsme navrhli vytvořit systém, který bude zahrnovat několik klíčových komponent. Použili jsme <strong>RFID čtečku</strong> s několika anténami, které jsme rozmístili ve skříni tak, aby signál pokryl všechna zařízení. Musíme ovšem počítat s možností, že ve skříni budou i balíčky s RFID kartami, které musí anténa ignorovat. Proto povedeme seznam přidaných balíčků do skříně, které bude anténa <strong>specificky načítat</strong>.</p>\n<p>Každou položku jsme opatřili vytištěným <strong>RFID štítkem s QR kódem</strong> (Tiskárna Zebra ZQ630), jehož načtením se otevře webová aplikace, kde lze pracovní prostředek jednoduše zapůjčit nebo vrátit. Během zápůjčky má uživatel možnost zdokumentovat stav zařízení, což napomáhá dřívějšímu <strong>odhalení poškození</strong> zařízení nebo jejich nekompletnosti.</p>\n<p>Systém také umožňuje <strong>nastavení lhůty pro kontrolu</strong> zařízení formou e-mailu se seznamem zařízení, která je potřeba zkontrolovat. Dále je možné ve stavu zapůjčení zobrazit návod k použití zařízení společně se souvisejícími soubory. Součástí řešení jsou také <strong>pushover notifikace a e-maily.</strong> Notifikace a e-maily upozorňují na položky, které ve skříni chybí a nejsou zapůjčeny nebo v případě poškození zařízení je správce také informován.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Shared_resources_diagram.svg\" alt=\"Diagram RFID systému pro správu pracovních prostředků\" /></div>\n<p>Jedním z klíčových aspektů našeho řešení je schopnost v jediném kroku zapsat nový předmět do databáze, vytisknout štítek pro krabici s zařízením a zařadit ho tak do seznamu, ve kterém jsou všechny <strong>povolené štítky.</strong></p>\n<p>Díky tomuto řešení každý zaměstnanec ví, jaká zařízení jsou v <strong>daný moment</strong> k dispozici a kde je nalezne. Správce tak má mnohem lepší přehled o stavu všech zařízení a nad svěřeným majetkem lepší kontrolu.</p>\n\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n    <li><a href=\"https://www.python.org\" target=\"_blank\">Python</a></li>\n    <li><a href=\"https://www.barcodesinc.com/caen-rfid/part-r1170l.htm?tab=product_qa\">qIDmini</a></li>\n    <li><a href=\"https://www.zebra.com/gb/en/products/spec-sheets/printers/mobile/zq630-series-rfid.html\">Zebra ZQ630</a></li>\n    <li><a href=\"/apple-ipad\">iPad</a></li>\n    <li><a href=\"/xgode\">Xgode</a></li>\n    <li><a href=\"/gonector\">Gonector</a></li>\n</ul>', 'cs', 2),
(5, 'borrowing-shared-resources', 'Borrowing Shared Resources', 'An efficient system for managing shared work resources, including tracking borrowing status, return deadlines, and device maintenance, ensuring devices are not lost.', 'Borrowing shared resources', 'Efficient system for managing shared work resources, with features for tracking, maintenance, and device condition inspection.', 'Efficient system for managing shared work resources, with features for tracking, maintenance, and device condition inspection.', '<p>The goal was to create an <strong>efficient system for managing shared work resources</strong> stored in a cabinet, which includes devices such as iPhones, iPads, RFID readers, printers, scales, etc. It was necessary to <strong>ensure that the devices would not be lost</strong>, to track their location, borrowing status, return deadlines, and regular maintenance, as well as to keep a record of all past maintenance. Additionally, it was important to have the <strong>ability to document the complete contents</strong> of the packaging upon return, monitor responsibility for damages, and inspect the condition of the devices when they are lent out and returned.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Shared_resources.jpg\" alt=\"Efficient management of shared work resources\" /></div>\n<p>To implement the solution, we proposed creating a system that includes several key components. We used an <strong>RFID reader with multiple antennas</strong>, which we placed in the cabinet to ensure the signal covers all devices. However, we have to count with the possibility that there could be boxes with RFID cards in the cabinet that the antenna must ignore. Therefore, we will maintain a list of added packages in the cabinet that the antenna will <strong>specifically read</strong>.</p>\n<p>Each item was equipped with a printed <strong>RFID tag with a QR code.</strong> (Printer Zebra ZQ630) Scanning the QR code opens a web application where the equipment can be easily borrowed or returned. During the borrowing process, the user has the <strong>option to document the condition of the device</strong>, which helps in the early detection of any damage or incompleteness of the devices.</p>\n<p>The system also allows setting a deadline for device inspection via an email containing a list of devices that need to be checked. Additionally, during the period when an item is borrowed, users can view the device’s user manual along with related files.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Shared_resources_diagram.svg\" alt=\"Diagram of RFID system for resource management\" /></div>\n<p>The solution also includes <strong>pushover notifications and emails.</strong> These notifications and emails alert users about items missing from the cabinet that have not been borrowed, or inform the administrator in case of device damage.</p>\n<p>One of the key aspects of our solution is the ability to, in a <strong>single step</strong>, register a new item in the database, print a label for the device’s box, and include it in the list of all authorized tags.</p>\n<p>Thanks to this solution, every employee knows which devices are <strong>available</strong> at any given moment and where to find them. The administrator has a much better overview of the status of all devices and <strong>better control</strong> over the entrusted assets.</p>\n\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n    <li><a href=\"https://www.python.org\" target=\"_blank\">Python</a></li>\n    <li><a href=\"https://www.barcodesinc.com/caen-rfid/part-r1170l.htm?tab=product_qa\">RFID reader qIDmini</a></li>\n    <li><a href=\"https://www.zebra.com/gb/en/products/spec-sheets/printers/mobile/zq630-series-rfid.html\">Printer Zebra ZQ630</a></li>\n    <li><a href=\"/apple-ipad\">iPad</a></li>\n    <li><a href=\"/xgode\">Xgode</a></li>\n    <li><a href=\"/gonector\">Gonector</a></li>\n</ul>', 'en', 2),
(6, 'vysledky-vysetreni-pacientu-z-dicom-serveru-na-webu', 'Výsledky vyšetření pacientů z DICOM serveru na webu', 'Řešení pro zobrazení grafických výsledků vyšetření pacientů z DICOM serveru přímo ve webové aplikaci kliniky s důrazem na bezpečnost a rychlost zpracování dat.', 'Výsledky vyšetření pacientů z DICOM serveru na webu', 'Zobrazení grafických výsledků vyšetření pacientů pořízených různými zobrazovacími metodami z DICOM serveru přímo ve webové aplikaci kliniky.', 'Řešení pro zobrazení grafických výsledků vyšetření pacientů z DICOM serveru přímo ve webové aplikaci kliniky s důrazem na bezpečnost a rychlost zpracování dat.', '<p>Naším úkolem bylo navrhnout optimální řešení, jak přímo ve webové aplikaci kliniky <strong>zobrazit grafické výsledky vyšetření</strong> pacientů pořízené různými zobrazovacími metodami, jako je rentgen, CT, magnetická rezonance nebo ultrazvuk. Bylo nutné zohlednit požadavky na bezpečnost, ale také rychlost při zpracování velkého množství obrazových dat ve specializovaném <strong>formátu DICOM</strong>, který je právě obvyklým výstupním formátem medicínských vyšetřovacích přístrojů a zároveň protokolem, kterým spolu medicínská zařízení komunikují.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]X-ray_head.jpg\" alt=\"Výsledky vyšetření pacientů pořízené různými zobrazovacími metodami\" /></div>\n<p>Pro získávání dat z <strong>DICOM serveru</strong> jsme zvolili technologii Python, která může být provozována v linuxovém prostředí a existuje pro ni dobře udržovaná knihovna pro práci s protokolem <strong>DICOM</strong>. Pro zajištění robustnosti jsme navrhli architekturu služby složenou ze 3 komponent. Metoda <strong>“Request Handler”</strong> bude přijímat HTTP požadavků z webového serveru a zařazovat je do fronty pro stahování dat. <strong>“Queue Manager”</strong> bude kontrolovat frontu požadavků, spouštět procesy pro jejich zpracování a informovat webovou aplikaci o dokončení stahování, případně o chybových stavech. Metoda <strong>“File Processer”</strong> bude určena výhradně pro samotné stahování dat a poběží ve více instancích podle aktuálního vytížení serveru.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Patients_examination_DICOM_diagram.svg\" alt=\"Diagram architektury pro správu a zobrazení dat z DICOM serveru\" /></div>\n<p>Pro zobrazení dat na webu jsme vybrali JavaScriptovou knihovnu <strong>Cornerstone3D</strong>, která umožňuje <strong>DICOM</strong> soubory nejen zobrazovat, ale můžeme u nich například měnit jas, kontrast nebo použít pravítko pro měření vzdáleností mezi zobrazenými částmi pacientova těla.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]DICOM_viewer.jpg\" alt=\"JavaScriptový prohlížeč DICOM souborů integrovaný do webové aplikace\" /></div>\n<p>Díky zahrnutí prohlížeče formátu DICOM do vlastní webové aplikace můžeme bez snížení nároků na kvalitu uživatelského rozhraní <strong>precizně spravovat přístupy</strong> k datům tak, aby každý lékař kliniky viděl pouze vyšetření svých pacientů. Připojení k aplikaci bude zabezpečeno pomocí technologie HTTPS a standardním zabezpečením webového serveru, na kterém aplikace poběží.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]QR_scanning.jpg\" alt=\"Jednorázový přístup ke sdílení výsledků vyšetření pomocí QR kódu\" /></div>\n<p>Pro <strong>zvýšení komfortu pacientů</strong> jsme zároveň navrhli funkci jednorázového přístupu s omezenou platností, který umožní pacientovi zobrazit konkrétní vyšetření libovolné další osobě, např. jinému lékaři. Tento <strong>jednorázový přístup</strong> může být vygenerován a vytištěn na papír nebo uložen do PDF dokumentu. Dokument bude obsahovat přístupové údaje v textové podobě a zároveň <strong>QR kódem</strong> pro snadné použití na mobilním zařízení. Po naskenování QR kódu bude uživatel okamžitě přesměrován a přihlášen do systému. Alternativně se může uživatel přihlásit ručně zadáním dočasných přístupových údajů.</p>\n\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n    <li><a href=\"/konzultace-filemaker\">FileMaker Server</a></li>\n    <li><a href=\"https://www.dicomstandard.org\" target=\"_blank\">DICOM</a></li>\n    <li><a href=\"https://www.python.org\" target=\"_blank\">Python</a></li>\n    <li><a href=\"https://www.w3schools.com/js/\" target=\"_blank\">JavaScript</a></li>\n    <li><a href=\"https://www.php.net\" target=\"_blank\">PHP</a></li>\n    <li><a href=\"https://www.osirix-viewer.com\" target=\"_blank\">Osirix</a></li>\n</ul>', 'cs', 3),
(7, 'results-of-patient-examinations-from-dicom-server-on-web', 'Results of patient examinations from DICOM server on web', 'A solution for displaying graphical results of patient examinations from the DICOM server directly within the clinic\'s web application, focusing on security and data processing speed.', 'Results of patient examinations from DICOM server on web', 'A solution for displaying graphical results of patient examinations from the DICOM server directly within the clinic\'s web application, focusing on security and data processing speed.', 'Displaying graphical results of patient examinations captured using various imaging methods from the DICOM server directly within the clinic’s web application.', '<p>Our task was to design an optimal solution for <strong>displaying graphical results of patient examinations</strong>, captured using various imaging methods such as X-ray, CT, MRI, or ultrasound, directly within the clinic’s web application. It was necessary to consider both security requirements and the speed of processing large volumes of image data in the specialized <strong>DICOM format</strong>, which is the standard output format of medical imaging devices and the protocol through which medical devices communicate with each other.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]X-ray_head.jpg\" alt=\"Results of patient examinations captured using various imaging methods\" /></div>\n<p>For data retrieval from the <strong>DICOM server</strong>, we chose Python as the technology, which can be run in a Linux environment and has a well-maintained library for working with the <strong>DICOM protocol.</strong> To ensure robustness, we designed a service architecture composed of three components. The <strong>“Request Handler”</strong> method will receive HTTP requests from the web server and enqueue them for data download. The <strong>“Queue Manager”</strong> will monitor the request queue, initiate processes for handling them, and notify the web application upon download completion or in case of errors. The <strong>“File Processor”</strong> method will be dedicated exclusively to the data download itself and will run in multiple instances depending on the current server load.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Patients_examination_DICOM_diagram.svg\" alt=\"Architecture diagram for managing and displaying data from the DICOM server\" /></div>\n<p>For displaying data on the web, we selected the JavaScript library <strong>Cornerstone3D</strong>, which not only allows DICOM files to be viewed but also provides features such as adjusting brightness and contrast, or using a ruler to measure distances between displayed parts of the patient’s body.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]DICOM_viewer.jpg\" alt=\"JavaScript DICOM file viewer integrated into a web application\" /></div>\n<p>By including a <strong>DICOM format viewer</strong> into our custom web application, we can precisely manage data access without compromising the quality of the user interface, ensuring that each clinician only sees the examinations of their own patients. Connection to the application will be secured using HTTPS technology and standard web server security measures on which the application will run.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]QR_scanning.jpg\" alt=\"One-time access feature for sharing examination results via QR code\" /></div>\n<p>To enhance <strong>patient comfort</strong>, we also designed a feature for <strong>one-time access</strong> with limited validity, allowing the patient to share a specific examination with any other person, such as another doctor. This <strong>one-time access</strong> can be generated and printed on paper or saved as a PDF document. The document will include access credentials in text form as well as a <strong>QR code</strong> for easy use on a mobile device. Upon scanning the QR code, the user will be immediately redirected and logged into the system. Alternatively, the user can manually log in using the temporary access credentials.</p>\n\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n    <li><a href=\"/filemaker-consulting\">FileMaker Server</a></li>\n    <li><a href=\"https://www.dicomstandard.org\" target=\"_blank\">DICOM</a></li>\n    <li><a href=\"https://www.python.org\" target=\"_blank\">Python</a></li>\n    <li><a href=\"https://www.w3schools.com/js/\" target=\"_blank\">JavaScript</a></li>\n    <li><a href=\"https://www.php.net\" target=\"_blank\">PHP</a></li>\n    <li><a href=\"https://www.osirix-viewer.com\" target=\"_blank\">Osirix</a></li>\n</ul>\n', 'en', 3),
(8, 'globalni-pohled-na-produkty-na-e-shopu', 'Globální pohled na produkty na e-shopu', 'Vytvoření aplikace pro kompletní a snadno dostupný přehled o všech produktech na e-shopu s možností filtrování, řazení a hromadné práce s daty.', 'Globální pohled na produkty na e-shopu', 'Aplikace zajišťující kompletní přehled o všech produktech na e-shopu s možností filtrování, řazení a upozornění na nesrovnalosti v cenách.', 'Vytvoření aplikace pro kompletní a snadno dostupný přehled o všech produktech na e-shopu s možností filtrování, řazení a hromadné práce s daty.', '<p>Cílem bylo vytvořit <strong>aplikaci pro seznam všech produktů</strong> nabízených na e-shopu, která zajistí kompletní a <strong>snadno dostupný</strong> přehled o všech produktech. Platforma, kterou používáme, je pronajatá a neposkytovala všechny možnosti, které bychom potřebovali. Konkrétně <strong>komplexní přehled</strong> o všech produktech, na kterém by se dalo hromadně pracovat s daty.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]E-shop_illustration.jpg\" alt=\"Seznam všech produktů na e-shopu\" /></div>\n<p>Navrhli jsme vytvořit FileMaker databázi, která slouží jako <strong>globální pohled</strong> na všechny produkty. Umožňuje používání <strong>filtrů a řazení</strong> produktů podle zvolených kritérií. Aplikace hlídá duplicity a správné zařazení produktů do kategorií. Kromě toho implementujeme funkci <strong>exportu produktů</strong> na základě vyfiltrovaných dat, což nám usnadní další zpracování - například hromadný import upravených dat o produktech do e-shopu.</p>\n<p>Aplikace také bude <strong>upozorňovat</strong> na poměr <strong>naší ceny a doporučené ceny</strong> dodavatelem nebo ceny přímo od výrobců. Dle situace aplikace nevyhovující ceny zvýrazní, což nám umožní okamžitě identifikovat a řešit nesrovnalosti v cenách. Díky tomu uvidíme případné chyby na první pohled a budeme je moci řešit.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]E-shop_solution_diagram.svg\" alt=\"Diagram FileMaker databáze pro globální přehled o produktech\" /></div>\n\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n    <li><a href=\"https://www.json.org/json-en.html\" target=\"_blank\">JSON</a></li>\n</ul>', 'cs', 4),
(9, 'global-products-overview', 'Global products overview', 'Creating an application that provides a complete and easily accessible overview of all products on the e-shop with filtering, sorting, and bulk data management capabilities.', 'Global products overview', 'An application providing a complete overview of all e-shop products with filtering, sorting, and alerts for price discrepancies.', 'An application providing a complete overview of all e-shop products with filtering, sorting, and alerts for price discrepancies.', '<p>The goal was to create an application that provides a complete and <strong>easily accessible overview</strong> of all products offered on the e-shop. The platform we use is leased and did not offer all the functionalities we needed, specifically a comprehensive overview of all products that would allow bulk data management.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]E-shop_illustration.jpg\" alt=\"List of all products on the e-shop\" /></div>\n<p>We proposed creating a FileMaker database that serves as a <strong>global overview</strong> of all products. It allows the use of filters and sorting of products according to selected criteria. The application monitors duplicates and ensures the correct categorization of products. Additionally, we are implementing a function for <strong>exporting products</strong> based on filtered data, which will make further processing easier—such as bulk importing of modified product data into the e-shop.</p>\n<p>The application will also <strong>alert us</strong> about the ratio of our price compared to the supplier’s recommended price or the manufacturer’s price. Depending on the situation, the application will highlight prices that do not meet the criteria, enabling us to immediately identify and address pricing discrepancies. This way, we can spot potential errors at a glance and address them promptly.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]E-shop_solution_diagram.svg\" alt=\"Diagram of the FileMaker database for global product overview\" /></div>\n\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n    <li><a href=\"https://www.json.org/json-en.html\" target=\"_blank\">JSON</a></li>\n</ul>', 'en', 4),
(10, 'transakce-z-napojovych-automatu-primo-do-filemakeru', 'Transakce z nápojových automatů přímo do FileMakeru', 'Řešení pro získávání dat z nápojových automatů do iOS zařízení pomocí vlastního hardwaru a softwaru, včetně IrDA komunikace a Bluetooth.', 'Transakce z nápojových automatů přímo do FileMakeru', 'Řešení pro získávání dat z nápojových automatů do iOS zařízení pomocí vlastního hardwaru a softwaru, včetně IrDA komunikace a Bluetooth.', 'Řešení pro získávání dat z nápojových automatů do iOS zařízení pomocí vlastního hardwaru a softwaru, včetně IrDA komunikace a Bluetooth.', '<p>Cílem bylo získat z <strong>automatu</strong> data do <strong>iOS</strong> zařízení. Zákazník chtěl komunikaci zprovoznit ve FileMaker Go. Také používal zařízení Enginko, se kterým ale nemohl obsloužit všechny automaty. Proto u nás poptával řešení, které umožní <strong>bezproblémovou komunikaci</strong> z FileMaker Go a zároveň bude podporovat všechny automaty. Výzvou bylo vytvořit si vlastní zařízení pro získávání historie transakcí.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Vending_machine.jpg\" alt=\"Získávání dat z nápojových automatů do iOS zařízení\" /></div>\n<p>Pro realizaci řešení jsme zvolili vytvoření <strong>vlastního hardwaru</strong>, složeného z IrDA 3 click modulu společně s deskou Seed XIAO nRF52840. IrDA modul jsme zvolili proto, že zvládne komunikovat na potřebných frekvencích podporovaných našimi automaty. Seed XIAO jsme zvolili, protože s ním máme již <strong>bohaté zkušenosti</strong> a má již zabudovaný Bluetooth modul, i modul pro správu dobíjení lithiových baterií s ochranou proti přepětí a podpětí baterie. Zařízení jsme navrhli zkompletovat do <strong>vlastního plastového pouzdra</strong>, které vytiskneme na 3D tiskárně.</p>\n<p>Pro obsluhu zařízení jsme navrhli vlastní firmware napsaný v C++, který se bude starat o komunikaci s automatem přes IrDA infračervené signály a s iOS zařízením přes Bluetooth, druhou stranu komunikace přes Bluetooth obstará <strong>náš plug-in SimpleTalk</strong>, zapouzdřený do nativní aplikace sestavenou pomocí našeho nástroje <strong>Xgode</strong>.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Vending_machine_diagram.svg\" alt=\"Diagram řešení pro získávání transakcí z nápojových automatů\" /></div>\n\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/xgode\">Xgode</a></li>\n    <li><a href=\"/simpletalk\">SimpleTalk</a></li>\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n    <li><a href=\"https://en.wikipedia.org/wiki/Infrared_Data_Association\" target=\"_blank\">IrDA communication module</a></li>\n    <li><a href=\"https://www.mikroe.com/irda-3-click\" target=\"_blank\">IrDA 3 click module</a></li>\n    <li><a href=\"https://wiki.seeedstudio.com/XIAO_BLE/\" target=\"_blank\">Seed XIAO</a></li>\n    <li><a href=\"/integrace-hardware\" target=\"_blank\">C++</a></li>\n    <li><a href=\"https://www.bluetooth.com/learn-about-bluetooth/tech-overview/\" target=\"_blank\">Bluetooth</a></li>\n    <li><a href=\"https://www.prusa3d.com/product/original-prusa-mk4-2/\" target=\"_blank\">Original Prusa MK4 3D Printer</a></li>\n</ul>', 'cs', 5),
(11, 'transactions-from-beverage-vending-machines-directly-into-filemaker', 'Transactions from beverage vending machines directly into FileMaker', 'A solution for retrieving data from beverage vending machines into iOS devices using custom hardware and software, including IrDA communication and Bluetooth.', 'Transactions from beverage vending machines directly into FileMaker', 'A custom solution for retrieving transaction history from vending machines and communicating with iOS devices via FileMaker Go.', 'A solution for retrieving data from beverage vending machines into iOS devices using custom hardware and software, including IrDA communication and Bluetooth.', '<p>The goal was to obtain data from the <strong>vending machine</strong> into an <strong>iOS</strong> device. The customer wanted to enable communication in FileMaker Go. They also used Enginko devices, but could not service all the machines with them. Therefore, they wanted a solution from us that would allow <strong>seamless communication</strong> with FileMaker Go while supporting all vending machines. The challenge was to create a custom piece of hardware for retrieving transaction history.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Vending_machine.jpg\" alt=\"Retrieving data from vending machines into iOS devices\" /></div>\n<p>For the implementation of the solution, we decided to create our <strong>own hardware</strong>, consisting of an IrDA 3 click module together with a Seed XIAO nRF52840 board. We chose the IrDA module because it can communicate at the necessary frequencies supported by our vending machines. We selected the Seed XIAO because we have <strong>extensive experience</strong> with it, and it already has a built-in Bluetooth module as well as a module for managing lithium battery charging with protection against overvoltage and undervoltage. We designed the device to be assembled into our <strong>own plastic case</strong>, which we will print on a 3D printer.</p>\n<p>For operating the device, we designed our own firmware <strong>written in C++</strong>, which will handle communication with the vending machine via IrDA infrared signals and with the iOS device via <strong>Bluetooth</strong>. The other side of the Bluetooth communication will be managed by our SimpleTalk plug-in, encapsulated into a native application built using our Xgode tool.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Vending_machine_diagram.svg\" alt=\"Solution diagram for retrieving transactions from vending machines\" /></div>\n\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"/xgode\">Xgode</a></li>\n    <li><a href=\"/simpletalk\">SimpleTalk</a></li>\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n    <li><a href=\"https://en.wikipedia.org/wiki/Infrared_Data_Association\" target=\"_blank\">IrDA communication module</a></li>\n    <li><a href=\"https://www.mikroe.com/irda-3-click\" target=\"_blank\">IrDA 3 click module</a></li>\n    <li><a href=\"https://wiki.seeedstudio.com/XIAO_BLE/\" target=\"_blank\">Seed XIAO</a></li>\n    <li><a href=\"/hardware-integration\" target=\"_blank\">C++</a></li>\n    <li><a href=\"https://www.bluetooth.com/learn-about-bluetooth/tech-overview/\" target=\"_blank\">Bluetooth</a></li>\n    <li><a href=\"https://www.prusa3d.com/product/original-prusa-mk4-2/\" target=\"_blank\">Original Prusa MK4 3D Printer</a></li>\n</ul>', 'en', 5),
(12, 'automatizovane-vazeni-expedovaneho-zbozi', 'Automatizované vážení expedovaného zboží', 'Řešení pro rychlé a bezchybné načítání hmotnosti zboží do existující FileMaker databáze pomocí propojení váhy Cardinal 190 s Raspberry Pi.', 'Automatizované vážení expedovaného zboží', 'Automatizovaný proces načítání hmotnosti zboží do databáze pomocí Raspberry Pi a váhy Cardinal 190, s minimálním rizikem chyb.', 'Automatizovaný proces načítání hmotnosti zboží do databáze pomocí Raspberry Pi a váhy Cardinal 190, s minimálním rizikem chyb.', '<p>Cílem bylo na jedno stisknutí <strong>rychle a bez chyb</strong> načíst hmotnost zboží do existující FileMaker databáze. Tímto automatizovaným procesem ušetřit obsluze čas a <strong>minimalizovat počet chyb</strong> při ručním zadávání.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Weighing_goods.jpg\" alt=\"Automatizované načítání hmotnosti zboží do databáze\" /></div>\n<p>Náš zákazník disponoval váhou Cardinal 190, ze které potřeboval získávat data. Proto jsme mu doporučili dokoupení komunikačního modulu. V našem řešení jsme tedy navrhli <strong>propojit Raspberry Pi s indikátorem váhy Cardinal 190.</strong> Díky tomu je umožněno nejen získání hmotnosti, ale také vynulování váhy přímo z mobilního zařízení. Obsluha takto může jednoduše <strong>jedním dotykem</strong> na mobilním zařízení načíst hmotnost, čímž eliminuje riziko chyby při ručním přepisování váhy.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Weighing_goods_diagram.svg\" alt=\"Diagram řešení pro automatizované vážení zboží\" /></div>\n<p>Toto řešení bude doplněno i o kamery, kdy jedním tlačítkem nejen zapíšeme váhu do databáze, ale také uložíme ve stejný okamžik fotky stavu zboží. Více o řešení s kamerami si můžete přečíst v této ukázce.</p>\n\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n    <li><a href=\"https://www.raspberrypi.org\" target=\"_blank\">Raspberry Pi</a></li>\n    <li><a href=\"https://cardinalscale.com/product/product-overview/Weight-Indicators/190-Storm\">Cardinal 190</a></li>\n</ul>', 'cs', 6),
(13, 'automated-weighing-of-dispatched-goods', 'Automated weighing of dispatched goods', 'A solution for quickly and accurately recording the weight of goods into the existing FileMaker database by connecting the Cardinal 190 scale with Raspberry Pi.', 'Automated weighing of dispatched goods', 'Automated process for recording goods weight into the database using Raspberry Pi and the Cardinal 190 scale, minimizing the risk of errors.', 'Automated process for recording goods weight into the database using Raspberry Pi and the Cardinal 190 scale, minimizing the risk of errors.', '<p>The goal was to <strong>quickly and accurately</strong> record the weight of the goods into the existing FileMaker database with a single press of a button. This automated process was intended to <strong>save time</strong> for the operator and <strong>minimize the number of errors</strong> associated with manual entry.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Weighing_goods.jpg\" alt=\"Automated recording of goods weight into the database\" /></div>\n<p>Our customer had a Cardinal 190 scale from which they needed to obtain data. Therefore, we recommended purchasing a communication module. In our solution, we proposed connecting the <strong>Raspberry Pi with the Cardinal 190 scale indicator.</strong> This allows not only for the retrieval of the weight but also for resetting the scale directly from a mobile device. The operator can <strong>easily</strong> read the weight with a <strong>single touch</strong> on the mobile device, thereby eliminating the risk of errors when manually transcribing the weight.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Weighing_goods_diagram.svg\" alt=\"Diagram of the solution for automated weighing of goods\" /></div>\n<p>This solution will also be complemented by cameras, allowing us to not only record the weight in the database with a single button press but also save photos of the goods’ condition at the same moment. You can read more about the camera solution in this example.</p>\n\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n    <li><a href=\"https://www.raspberrypi.org\" target=\"_blank\">Raspberry Pi</a></li>\n    <li><a href=\"https://cardinalscale.com/product/product-overview/Weight-Indicators/190-Storm\">Cardinal 190</a></li>\n</ul>', 'en', 6),
(16, 'priprava-konferenci', 'Příprava konferencí', 'Nástroj pro efektivní přípravu a průběh konferencí, včetně registrace, evidence účastníků, automatizace rozesílání informací a generování reportů z workshopů.', 'Příprava konferencí', 'Efektivní příprava konferencí s důrazem na hladký průběh registrace, správu účastníků a monitorování kapacit přednáškových místností.', 'Efektivní příprava konferencí s důrazem na hladký průběh registrace, správu účastníků a monitorování kapacit přednáškových místností.', '<p>Cílem bylo navrhnout nástroj pro <strong>efektivní přípravu a průběh konferencí</strong> a evidenci příchozích účastníků. Bylo potřeba usnadnit jim registraci a efektivně je při příchodu odbavit, protože se tvořily fronty. Součástí byla i <strong>automatizace rozesílání informací</strong> před a během konferencí, a <strong>výroba identifikačních visaček.</strong> Dále bylo nutné generovat <strong>reporty</strong> z workshopů a také vytváření dotazníků společně s jejich vyhodnocováním. Zásadní bylo také <strong>hlídání kapacity</strong> přednáškových místností a celé konference, aby nedocházelo k přeplnění nebo nedostatku místa na workshopech.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Conference_illustration.jpg\" alt=\"Příprava konferencí a evidence účastníků\" /></div>\n<p>V rámci našeho řešení probíhá <strong>kompletní příprava materiálů</strong> potřebných pro konferenci. Příprava zahrnuje seznam účastníků, tisk identifikačních visaček, program konference společně s programem a kapacit workshopů.</p>\n<p>Účastníci konference se <strong>registrují na webu</strong> a několik dní před začátkem akce obdrží v e-mailu vstupenku, kterou se prokáží při vstupu. Při příchodu jsou při načtení vstupenky účastníci zapsáni jako příchozí. Poté je každému účastníkovi předán balíček společně s <strong>identifikační badge</strong>. Pro účely načtení vstupenky budeme používat aplikaci, kterou si vytvoříme naším nástrojem Xgode.</p>\n<p>Pro konferenci je zajištěno několik obrazovek, které jsou připojeny k <strong>Raspberry Pi.</strong> Na nich jsou promítány informace o programu konference a počtu účastníků. Kromě aktuálního počtu účastníků budou informace o konferenci viditelné i když budeme offline, takže nejsme omezeni pouze na místa se stabilním připojením.</p>\n<p>Toto řešení zajistí <strong>kompletní přípravu materiálů</strong>, hladký průběh registrace, vyhodnocení dotazníků po konferenci a samozřejmě poskytne aktuální informace všem účastníkům během konference.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Conference_diagram.svg\" alt=\"Diagram řešení pro přípravu a průběh konferencí\" /></div>\n\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n    <li><a href=\"https://ucitelskysummit.cz\">Web</a></li>\n    <li><a href=\"https://www.raspberrypi.org\" target=\"_blank\">Raspberry Pi</a></li>\n    <li><a href=\"/xgode\">Xgode</a></li>\n</ul>', 'cs', 7),
(17, 'conference-preparation', 'Conference Preparation', 'A tool for efficient conference preparation and management, including registration, participant tracking, automated information distribution, and report generation from workshops.', 'Conference Preparation', 'Efficient conference preparation focused on smooth registration, participant management, and monitoring lecture room capacities.', 'Efficient conference preparation focused on smooth registration, participant management, and monitoring lecture room capacities.', '<p>The goal was to design a tool for the <strong>efficient preparation and management of conferences</strong>, as well as for tracking incoming participants. It was necessary to make the registration process <strong>easier</strong> and manage check-ins <strong>efficiently</strong>, as queues were forming. The tool also needed to automate the distribution of information before and during the conferences and facilitate the production of identification badges. Additionally, it was essential to generate <strong>reports from workshops</strong> and create <strong>surveys</strong> along with their evaluations. Monitoring the capacity of lecture rooms and the overall conference was also crucial to prevent overcrowding or a shortage of space in the workshops.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Conference_illustration.jpg\" alt=\"Conference preparation and participant management\" /></div>\n<p>Within our solution, the <strong>complete preparation of materials</strong> needed for the conference is carried out. This preparation includes the list of participants, printing of identification badges, the conference program along with the schedule and capacity of workshops.</p>\n<p>Participants <strong>register on the website</strong>, and a few days before the event, they receive a <strong>ticket via email</strong>, which they present upon entry. Upon arrival, the ticket is scanned, and the participant is recorded as present. Each participant is then given a package along with an identification badge. For the purpose of ticket scanning, we will use an application that we develop with our <strong>Xgode tool.</strong></p>\n<p>Several screens are provided for the conference, connected to <strong>Raspberry Pi</strong> devices. These screens display information about the conference program and the number of participants. In addition to showing the current number of participants, conference information will also be visible when offline, so we are not limited to locations with stable internet connectivity.</p>\n<p>This solution ensures the <strong>complete preparation of materials</strong>, a smooth registration process, the evaluation of surveys after the conference, and, of course, provides <strong>up-to-date information</strong> to all participants <strong>during</strong> the conference.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Conference_diagram.svg\" alt=\"Solution diagram for conference preparation and management\" /></div>\n\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n        <li><a href=\"https://ucitelskysummit.cz\">Web</a></li>\n    <li><a href=\"https://www.raspberrypi.org\" target=\"_blank\">Raspberry Pi</a></li>\n    <li><a href=\"/xgode\">Xgode</a></li>\n</ul>', 'en', 7),
(18, 'monitorovani-teploty-pri-vareni-piva', 'Monitorování teploty při vaření piva', 'Monitorování teploty při vaření piva je zásadní. Navrhli jsme systém, který sleduje teplotní data v reálném čase, zobrazuje je graficky a umožňuje vzdálený přístup pro optimální průběh výroby.', 'Monitorování teploty při vaření piva', 'Systém pro monitorování teploty při vaření piva v reálném čase a vzdálený přístup zajišťuje optimální kvalitu výroby.\r\n', 'Monitorování teploty při vaření piva je zásadní. Navrhli jsme systém, který sleduje teplotní data v reálném čase, zobrazuje je graficky a umožňuje vzdálený přístup pro optimální průběh výroby.', '<p>Při <strong>vaření piva</strong> je nutné přesně kontrolovat <strong>teplotu</strong>, zejména během procesů jako <strong>rmutování</strong>, nebo <strong>kvašení</strong> a <strong>chlazení</strong>. Cílem bylo navrhnout systém, který by nejen <strong>zaznamenával teplotní údaje</strong> po celou dobu procesu, ale také umožňoval jejich <strong>sledování v reálném čase</strong>, aby byl zajištěn <strong>optimální průběh vaření</strong> a dosažena požadovaná <strong>kvalita piva</strong>.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Temperature_of_beer.jpg\" alt=\"Kontrola teploty při vaření piva\" /></div>\n<p>Pro řešení jsme použili <strong>Raspberry Pi</strong>, na kterém běží <strong>skript v Pythonu</strong>, který komunikuje s <strong>teploměrem</strong>, a zároveň vytváří <strong>webový server</strong>, ke kterému je připojen <strong>teploměr DS18B2</strong>. Tímto jsme umožnili <strong>zaznamenávat teplotní data</strong> a zobrazovat je <strong>graficky</strong> prostřednictvím webového rozhraní na iPadu. Systém zároveň poskytuje možnost <strong>sledování rychlosti změn teploty</strong>, což sládkům napomáhá udržovat správnou teplotní křivku během celého procesu vaření.</p>\n<div class=\"diagram image-preview\"><img src=\"[[IMAGE_PATH]]Temperature_of_beer_diagram.svg\" alt=\"Grafická vizualizace teplotních dat\" /></div>\n<p>Díky <strong>vzdálenému přístupu</strong> k těmto datům je možné <strong>teplotu nepřetržitě monitorovat</strong> i mimo místo vaření, což se využívá primárně při dlouhodobých procesech jako je <strong>ležení piva</strong> nebo <strong>kvašení</strong>. Tento vzdálený přístup umožňuje <strong>sledovat vývoj teploty</strong> a reagovat na případné odchylky.</p>\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/konzultace-filemaker\" target=\"_blank\">FileMaker</a></li>\n    <li><a href=\"https://www.raspberrypi.org\" target=\"_blank\">Raspberry Pi</a></li>\n    <li><a href=\"https://www.python.org\" target=\"_blank\">Python</a></li>\n    <li><a href=\"https://www.analog.com/en/products/ds18b20.html\" target=\"_blank\">Thermometer - DS18B20</a></li>\n</ul>\n', 'cs', 8);
INSERT INTO `skill_content` (`id`, `url`, `title`, `description`, `og_title`, `og_description`, `preview_text`, `html_content`, `id_lang`, `id_skill`) VALUES
(19, 'temperature-monitoring-in-beer-brewing', 'Temperature Monitoring in Beer Brewing', 'Temperature monitoring in beer brewing is crucial. We designed a system that tracks temperature data in real-time, displays it graphically, and allows remote access for optimal brewing.', 'Temperature Monitoring in Beer Brewing', 'Real-time temperature monitoring system in beer brewing with remote access ensures optimal production quality.', 'Temperature monitoring in beer brewing is crucial. We designed a system that tracks temperature data in real-time, displays it graphically, and allows remote access for optimal brewing.', '<p>In <strong>brewing beer</strong>, it is essential to precisely control the <strong>temperature</strong>, especially during processes such as <strong>mashing</strong>, <strong>fermentation</strong>, and <strong>cooling</strong>. The goal was to design a system that would not only <strong>record temperature data</strong> throughout the entire process but also allow <strong>real-time monitoring</strong> to ensure the optimal brewing process and achieve the desired <strong>beer quality</strong>.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Temperature_of_beer.jpg\" alt=\"Temperature control in beer brewing\" /></div>\n<p>For this solution, we used a <strong>Raspberry Pi</strong> running a <strong>Python script</strong> that communicates with the <strong>thermometer</strong> and simultaneously creates a <strong>web server</strong> to which we also connected a <strong>DS18B2 thermometer</strong>. This setup allows us to <strong>record temperature data</strong> and display it <strong>graphically</strong> through a web interface on an iPad. The system also provides the ability to <strong>monitor the rate of temperature changes</strong>, helping brewers maintain the correct temperature curve throughout the brewing process.</p>\n<div class=\"diagram image-preview\"><img src=\"[[IMAGE_PATH]]Temperature_of_beer_diagram.svg\" alt=\"Graphical visualization of temperature data\" /></div>\n<p>Thanks to <strong>remote access</strong> to this data, it is possible to <strong>continuously monitor</strong> the temperature even outside the brewing site, which is primarily used during long-term processes such as <strong>beer lagering</strong> or <strong>fermentation</strong>. This remote access allows for tracking the <strong>temperature development</strong> and responding to any deviations.</p>\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"/filemaker-consulting\" target=\"_blank\">FileMaker</a></li>\n    <li><a href=\"https://www.raspberrypi.org\" target=\"_blank\">Raspberry Pi</a></li>\n    <li><a href=\"https://www.python.org\" target=\"_blank\">Python</a></li>\n    <li><a href=\"https://www.analog.com/en/products/ds18b20.html\" target=\"_blank\">Thermometer - DS18B20</a></li>\n</ul>\n', 'en', 8),
(20, 'rfid-pro-spravu-inventare', 'RFID pro správu inventáře', 'RFID řešení pro správu inventáře výrazně zjednodušuje a zrychluje proces inventur ve skladech s tisíci položkami. Automatické skenování RFID štítků eliminuje nutnost ručního skenování a fyzického vyhledávání zboží.', 'RFID pro správu inventáře', 'Automatizace správy inventáře s RFID technologií zrychluje a zpřesňuje inventury, což snižuje chybovost a zlepšuje přehled o skladovém zboží.', 'RFID řešení pro správu inventáře výrazně zjednodušuje a zrychluje proces inventur ve skladech s tisíci položkami. Automatické skenování RFID štítků eliminuje nutnost ručního skenování a fyzického vyhledávání zboží.', '<p>Provádění <strong>inventur</strong> bylo <strong>časově náročné</strong> a <strong>náchylné k chybám</strong>, zejména ve <strong>velkých skladech</strong> s tisíci položkami. Tradiční <strong>systémy čárových kódů</strong>, které vyžadovaly <strong>manuální skenování</strong>, se ukázaly jako <strong>neefektivní</strong> a <strong>pomalé</strong>. Navíc pracovníci museli <strong>fyzicky vyhledávat</strong> a <strong>identifikovat každou položku</strong>, což proces ještě více zpomalovalo a zvyšovalo <strong>riziko chyb</strong>.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]RFID_inventory_management.jpg\" alt=\"Snížení chybovosti a zrychlení inventury díky RFID technologii.\" /></div>\n<p>Implementovali jsme řešení, které výrazně <strong>zjednodušilo</strong> a <strong>zrychlilo proces inventur</strong>. Na každou položku na skladě byly umístěny <strong>RFID štítky</strong>, které umožňují čtečkám (Alien, Kathrein, Impinj) rychle skenovat celé místnosti nebo části skladu. Díky tomu je možné <strong>sledovat pohyb zboží</strong> na skladě, <strong>počítat aktuální počet zboží</strong> a <strong>upozorňovat na chybějící zboží</strong>. Výrazně se tímto <strong>zkrátil čas potřebný pro inventuru</strong>, protože systém <strong>automaticky identifikoval položky</strong>, aniž by bylo nutné je <strong>ručně skenovat</strong>.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]RFID_inventory_management_diagram.svg\" alt=\"Schéma fungování RFID systému ve skladu.\" /></div>\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n    <li>RFID čtečka (Alien, Kathrein, Impinj)</li>\n</ul>\n', 'cs', 9),
(21, 'rfid-for-inventory-management', 'RFID for Inventory Management', 'RFID technology for inventory management streamlines and speeds up the inventory process in large warehouses. Automatic RFID tag scanning eliminates the need for manual scanning and locating items.', 'RFID for Inventory Management', 'Automating inventory management with RFID technology speeds up and enhances the accuracy of inventories, reducing errors and improving stock visibility.', 'RFID technology for inventory management streamlines and speeds up the inventory process in large warehouses. Automatic RFID tag scanning eliminates the need for manual scanning and locating items.', '<p>Conducting <strong>inventory</strong> was <strong>time-consuming</strong> and <strong>error-prone</strong>, especially in <strong>large warehouses</strong> with thousands of items. Traditional <strong>barcode systems</strong>, which required <strong>manual scanning</strong>, proved to be <strong>inefficient</strong> and slow. Moreover, workers had to <strong>physically locate</strong> and <strong>identify each item</strong>, further slowing down the process and increasing the risk of <strong>errors</strong>.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]RFID_inventory_management.jpg\" alt=\"Reducing errors and speeding up inventory with RFID technology.\" /></div>\n<p>We implemented a solution that significantly simplified and <strong>sped up the inventory process</strong>. <strong>RFID tags</strong> were placed on every item in the warehouse, allowing readers (Alien, Kathrein, Impinj) to quickly scan entire rooms or sections of the warehouse. This made it possible to <strong>track the movement of goods</strong> in the warehouse, <strong>count the current number of items</strong>, and <strong>alert to missing goods</strong>. The time required for inventory was greatly reduced because the system <strong>automatically identified items</strong> without the need for <strong>manual scanning</strong>.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]RFID_inventory_management_diagram.svg\" alt=\"Diagram showing the RFID system functionality in a warehouse.\" /></div>\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n    <li>RFID readers (Alien, Kathrein, Impinj)</li>\n</ul>\n', 'en', 9),
(22, 'isdoc-generovani-faktur', 'ISDOC - generování faktur', 'Elektronická fakturace podle standardu ISDOC zajišťuje efektivní generování faktur ve formátu XML s podporou pro PDF/A-3a. Systém FileMaker s podporou PHP a XML.', 'ISDOC - generování faktur', 'Generování faktur dle standardu ISDOC s podporou XML, PDF/A-3a a technologií FileMaker, PHP a Ghostscript.', 'Elektronická fakturace podle standardu ISDOC zajišťuje efektivní generování faktur ve formátu XML s podporou pro PDF/A-3a. Systém FileMaker s podporou PHP a XML.', '<p>Cílem bylo pro zákazníka zajistit <strong>elektronickou fakturaci</strong> podle <strong>standardu ISDOC</strong> (Information System Document - je standard pro elektronickou fakturaci v ČR) do stávajícího interního systému.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Generation_invoices_using_XML.jpg\" alt=\"Generování faktur podle standardu ISDOC.\" /></div>\r\n<p>V rámci stávajícího procesu <strong>ukládání faktury do PDF</strong> dochází k vygenerování <strong>souboru ISDOC</strong> (technicky se jedná o <strong>formát XML</strong>). Soubor může být jako součást PDF souboru (příloha) nebo jako samostatný soubor.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Generation_invoices_using_XML_diagram.svg\" alt=\"Schéma generování faktur pomocí XML a ISDOC.\" /></div>\r\n<p>Největší výzvou bylo při <strong>převodu dat z formátu JSON do formátu XML</strong> zajistit správné pořadí jednotlivých elementů, protože v <strong>JSON</strong> není technicky zaručeno pořadí elementů v objektech.</p>\r\n<p>Nyní proces zahrnuje <strong>generování dat ve formátu JSON</strong> nativně ve <strong>FileMakeru</strong>. Pomocí <strong>PHP skriptu</strong> je převeden do formátu <strong>XML</strong> a validován pomocí <strong>XSD souboru</strong> (který definuje strukturu a pravidla XML dokumentu). <strong>Soubor XML</strong> s příponou .ISDOC je použit jako <strong>příloha PDF</strong> za pomoci <strong>bash skriptu</strong> (software <strong>Ghostscript</strong> pro práci s PDF soubory). V rámci spojení dochází ke kontrole a převodu souboru do <strong>standardu PDF/A-3a</strong>.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n    <li><a href=\"https://www.php.net\" target=\"_blank\">PHP</a></li>\r\n    <li>Bash - software <a href=\"https://www.ghostscript.com/blog/zugferd.html\" target=\"_blank\">Ghostscript</a></li>\r\n    <li><a href=\"https://cs.wikipedia.org/wiki/Extensible_Markup_Language\" target=\"_blank\">XML</a></li>\r\n    <li><a href=\"https://isdoc.org\" target=\"_blank\">ISDOC</a></li>\r\n</ul>\r\n', 'cs', 10),
(23, 'isdoc-invoice-generation', 'Electronic Invoicing According to ISDOC Standard', 'Electronic invoicing according to the ISDOC standard ensures efficient generation of invoices in XML format with PDF/A-3a support. The system is powered by FileMaker, PHP, and XML.', 'Electronic Invoicing According to ISDOC Standard', 'Invoicing based on the ISDOC standard with support for XML, PDF/A-3a, and technologies like FileMaker, PHP, and Ghostscript.', 'Electronic invoicing according to the ISDOC standard ensures efficient generation of invoices in XML format with PDF/A-3a support. The system is powered by FileMaker, PHP, and XML.', '<p>The goal was to provide the customer with <strong>electronic invoicing</strong> according to the <strong>ISDOC standard</strong> (Information System Document - a standard for electronic invoicing in the Czech Republic) into the existing internal system.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Generation_invoices_using_XML.jpg\" alt=\"Generating invoices using the ISDOC standard.\" /></div>\r\n<p>In the current process of saving invoices to PDF, an <strong>ISDOC file</strong> is generated (technically, this is an <strong>XML format</strong>). The file can be part of a PDF file (as an attachment) or as a separate file.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Generation_invoices_using_XML_diagram.svg\" alt=\"Diagram of invoice generation using XML and ISDOC.\" /></div>\r\n<p>The biggest challenge in <strong>converting data from JSON format to XML format</strong> was ensuring the correct order of elements, as JSON does not technically guarantee the order of elements in objects.</p>\r\n<p>The process now includes <strong>generating data in JSON format</strong> natively in FileMaker. Using a <strong>PHP script</strong>, it is converted to <strong>XML format</strong> and validated using an <strong>XSD file</strong> (which defines the structure and rules of the XML document). The XML file with the .ISDOC extension is used as a <strong>PDF attachment</strong> with the help of a <strong>bash script</strong> (software <strong>Ghostscript</strong> for working with PDF files). In the process of merging, the file is also checked and converted to the <strong>PDF/A-3a standard</strong>.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n    <li><a href=\"https://www.php.net\" target=\"_blank\">PHP</a></li>\r\n    <li>Bash - software <a href=\"https://www.ghostscript.com/blog/zugferd.html\" target=\"_blank\">Ghostscript</a></li>\r\n    <li><a href=\"https://cs.wikipedia.org/wiki/Extensible_Markup_Language\" target=\"_blank\">XML</a></li>\r\n    <li><a href=\"https://isdoc.org/en/\" target=\"_blank\">ISDOC</a></li>\r\n</ul>\r\n', 'en', 10),
(24, 'slack-pro-notifikace', 'Slack pro notifikace', 'Integrace Slacku s FileMakerem umožňuje okamžité zasílání urgentních notifikací do Slack kanálů, čímž zlepšuje komunikaci a reakční dobu týmu.', 'Slack pro notifikace', 'Integrace Slacku pro zasílání notifikací z FileMakeru umožňuje lepší správu úkolů a rychlejší komunikaci.', 'Integrace Slacku s FileMakerem umožňuje okamžité zasílání urgentních notifikací do Slack kanálů, čímž zlepšuje komunikaci a reakční dobu týmu.', '<p>Společnost potřebovala efektivnější způsob, jak informovat členy týmu o <strong>naléhavých problémech</strong>, jako jsou <strong>požadavky na podporu</strong> nebo <strong>nedokončené úkoly</strong>. Stávající systém spoléhal na <strong>notifikace v rámci softwaru</strong> nebo na <strong>e-maily</strong>, které byly snadno přehlédnuté nebo doručené se zpožděním.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Slack_FileMaker_integration_illustration.jpg\" alt=\"Ilustrace integrace Slacku s FileMakerem pro zasílání notifikací.\" /></div>\n<p>Integrovali jsme <strong>Slack</strong> s řešením v <strong>FileMakeru</strong>, aby notifikace byly zasílány přímo do <strong>Slack kanálů</strong>. Tohoto jsme dosáhli konfigurací <strong>API</strong>, které umožnilo FileMakeru odesílat <strong>HTTP požadavky</strong> na Slack, čímž se automaticky posílají zprávy do příslušných kanálů. Díky této integraci jsou <strong>urgentní notifikace</strong> okamžitě viditelné pro příslušné členy týmu, což výrazně zlepšilo <strong>komunikaci</strong> a <strong>reakční dobu</strong>. Systém je navíc plně přizpůsobitelný, což uživatelům umožňuje nastavit si, jaké typy notifikací chtějí dostávat a jakým způsobem – ať už prostřednictvím <strong>Slacku</strong>, <strong>e-mailu</strong>, nebo obojího.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Slack_FileMaker_integration_diagram.svg\" alt=\"Schéma integrace Slacku s FileMakerem.\" /></div>\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n    <li><a href=\"https://slack.com\" target=\"_blank\">Slack</a></li>\n</ul>\n', 'cs', 11),
(25, 'slack-integration-for-notifications', 'Slack Integration for Notifications', 'Slack integration with FileMaker enables immediate notifications to Slack channels, improving team communication and response times.', 'Slack Integration for Notifications', 'Slack integration for sending notifications from FileMaker enhances task management and communication speed.', 'Slack integration with FileMaker enables immediate notifications to Slack channels, improving team communication and response times.', '<p>The company needed a more efficient way to inform team members about <strong>urgent issues</strong>, such as <strong>support requests</strong> or <strong>incomplete tasks</strong>. The existing system relied on <strong>in-software notifications</strong> or <strong>emails</strong>, which were easily overlooked or delivered with delays.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Slack_FileMaker_integration_illustration.jpg\" alt=\"Illustration of Slack integration with FileMaker for notifications.\" /></div>\n<p>We integrated <strong>Slack</strong> with the <strong>FileMaker solution</strong> to have notifications sent directly to <strong>Slack channels</strong>. This was achieved by configuring an <strong>API</strong> that allowed FileMaker to send <strong>HTTP requests</strong> to Slack, automatically posting messages to the appropriate channels. Thanks to this solution, <strong>urgent notifications</strong> are immediately visible to the relevant team members, significantly improving <strong>communication</strong> and <strong>response times</strong>. Furthermore, the system is fully customizable, allowing users to set which types of notifications they want to receive and how – whether through <strong>Slack</strong>, <strong>email</strong>, or both.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Slack_FileMaker_integration_diagram.svg\" alt=\"Diagram of Slack integration with FileMaker.\" /></div>\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n    <li><a href=\"https://slack.com\" target=\"_blank\">Slack</a></li>\n</ul>', 'en', 11),
(26, 'automatizace-michani', 'Automatizace míchání tabákových příchutí\r\n', 'Automatizovaný systém míchání tabákových příchutí pomocí Raspberry Pi a pump zajišťuje maximální přesnost a konzistentní kvalitu produktu.', 'Automatizace míchání tabákových příchutí\r\n', 'Automatizace míchání tabákových příchutí s Raspberry Pi, dávkovacími pumpami a systémem pro vzdálené ovládání a monitorování.', 'Automatizovaný systém míchání tabákových příchutí pomocí Raspberry Pi a pump zajišťuje maximální přesnost a konzistentní kvalitu produktu.', '<p>Cílem bylo navrhnout systém pro <strong>automatizaci míchání</strong> tabákových příchutí, který by zajišťoval <strong>maximální přesnost</strong> při kombinování různých ingrediencí. Zákazník požadoval, aby proces byl plně automatizovaný a zaručoval <strong>konzistentní kvalitu finálního produktu.</strong> Hlavní výzvou bylo <strong>přesné</strong> řízení míchání, protože různé ingredience se liší viskozitou, což mohlo ovlivnit průtok a tím i přesnost výsledné směsi.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Automatic_mixing_illustration.jpg\" alt=\"Ilustrace automatizace míchání tabákových příchutí.\" /></div>\n<p>Řešení spočívalo v použití <strong>Raspberry Pi</strong> připojeného k váze a pumpám, které tvořily jádro celého systému. Raspberry Pi bylo vybaveno webovým serverem, který umožňoval <strong>vzdálené ovládání</strong> a <strong>monitorování</strong> procesu.</p>\n<div class=\"image-preview diagram-small\"><img src=\"[[IMAGE_PATH]]Automatic_mixing_diagram.svg\" alt=\"Schéma automatizace míchání pomocí Raspberry Pi a pump.\" /></div>\n<p>Pumpami bylo možné <strong>přesně</strong> řídit rychlost a směr proudění na základě údajů z vah, což zajišťovalo správné dávkování každé ingredience ve směsi. Systém byl navržen tak, aby ke konci míchání automaticky zpomalil průtok, čímž se zvýšila <strong>přesnost dávkování</strong>. Pro bezpečnost bylo přidáno i fyzické <strong>bezpečnostní tlačítko</strong> pro zastavení. Pro zapojení pump mezi sebou jsme použili <strong>MODBUS</strong> a daisy chain zapojení pump (jeden kabel, který vede od pumpy k pumpě).</p>\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n    <li><a href=\"https://www.raspberrypi.org\" target=\"_blank\">Raspberry Pi</a></li>\n    <li><a href=\"/integrace-hardware\">Pumpy LabN6-3</a></li>\n</ul>', 'cs', 12),
(27, 'automation-of-tobacco-flavor-mixing', 'Automation of Tobacco Flavor Mixing', 'Automated tobacco flavor mixing system using Raspberry Pi and pumps ensures maximum accuracy and consistent product quality.', 'Automation of Tobacco Flavor Mixing', 'Automation of tobacco flavor mixing with Raspberry Pi, dosing pumps, and a system for remote control and monitoring.', 'Automated tobacco flavor mixing system using Raspberry Pi and pumps ensures maximum accuracy and consistent product quality.', '<p>The goal was to design a system for the <strong>automation</strong> of tobacco flavor mixing that would ensure <strong>maximum accuracy</strong> when combining various ingredients. The customer required the process to be <strong>fully automated</strong> and to guarantee <strong>consistent quality</strong> of the final product. The main challenge was the <strong>precise</strong> control of the mixing process because different ingredients vary in viscosity, which could affect the flow and thus the accuracy of the final mixture.</p>\n\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Automatic_mixing_illustration.jpg\" alt=\"System for automation of tobacco flavor mixing\" /></div>\n\n<p>The solution involved using a <strong>Raspberry Pi</strong> connected to <strong>scales</strong> and <strong>pumps</strong>, which formed the core of the system. The Raspberry Pi was equipped with a web server that allowed for <strong>remote control</strong> and <strong>monitoring</strong> of the process.</p>\n\n<div class=\"image-preview diagram-small\"><img src=\"[[IMAGE_PATH]]Automatic_mixing_diagram.svg\" alt=\"Diagram of the automated mixing system\" /></div>\n\n<p>The pumps could <strong>precisely</strong> control the <strong>speed</strong> and <strong>direction</strong> of flow based on data from the scales, ensuring the correct dosing of each ingredient in the mixture. The system was designed to automatically slow down the flow toward the end of mixing, increasing the <strong>accuracy of dosing</strong>. For safety, a physical <strong>emergency stop button</strong> was added. To connect the pumps to each other, we used <strong>MODBUS</strong> and a <strong>daisy chain</strong> configuration of the pumps (one cable running from pump to pump).</p>\n<ul>\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n    <li><a href=\"https://www.raspberrypi.org\" target=\"_blank\">Raspberry Pi</a></li>\n    <li><a href=\"/hardware-integration\">Pumpy LabN6-3</a></li>\n</ul>', 'en', 12),
(28, 'automaticke-vytvareni-objednavek', 'Automatické vytváření objednávek', 'Zefektivněte proces vytváření grafických podkladů s automatizací pomocí REST API a FileMakeru, který zajistí rychlé zadávání objednávek bez manuálních chyb.', 'Automatické vytváření objednávek', 'Automatizace zadávání objednávek pomocí REST API zrychluje a usnadňuje proces vytváření objednávek v databázi FileMaker.', 'Zefektivněte proces vytváření grafických podkladů s automatizací pomocí REST API a FileMakeru, který zajistí rychlé zadávání objednávek bez manuálních chyb.', '<p>Zákazník potřeboval zefektivnit proces zadávání objednávek na vytvoření grafických podkladů pro pravidelné sezónní reklamní bannery. Zákazník měl k dispozici tabulku v <strong>Excelu s objednávkami</strong>, které musel ručně přepisovat do FileMakeru, což bylo časově náročné a vznikaly tak i chyby. <strong>Cílem bylo proces automatizovat a urychlit</strong>.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]automatic_order_creation.jpg\" alt=\"Automatizace procesu vytváření objednávek na sezónní reklamní bannery\" /></div>\r\n<p>Implementovali jsme <strong>REST API</strong>, které přijímá data ve formátu JSON. Zákazník tedy ze svého systému přímo odesílá data ve formátu JSON do API<. Díky tomu není potřeba žádná další uživatelská akce, která by celý proces zdržovala, nebo generovala chyby. Toto API <strong>kontroluje validitu JSON souboru</strong>, ověřuje povinné údaje a následně předává ověřená data do FileMaker databáze. Po ověření dat <strong>skript automaticky vytvoří objednávky</strong> do stávající FileMaker aplikace na základě definovaných pravidel.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]automatic_order_creation_diagram.svg\" alt=\"Diagram automatického vytváření objednávek pomocí REST API\" /></div>\r\n<p>Proces, který dříve trval jednotky minut, je nyní díky automatizaci zkrácen na <strong>několik vteřin</strong>. Systém zajišťuje, že všechny objednávky jsou správně <strong>validovány</strong> a zadány do databáze bez manuálních zásahů.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n    <li><a href=\"/filemaker-konzultace\">FileMaker</a></li>\r\n    <li><a href=\"/fmrestor\">REST API</a></li>\r\n    <li><a href=\"https://www.json.org/json-en.html\" target=\"_blank\">JSON</a></li>\r\n</ul>', 'cs', 13),
(29, 'automatic-order-creation', 'Automatic Order Creation', 'Streamline the order creation process with automation using REST API and FileMaker, ensuring fast, error-free order submissions.', 'Automatic order creation', 'Automating order submissions through REST API speeds up and simplifies the process of creating orders in the FileMaker database.', 'Streamline the order creation process with automation using REST API and FileMaker, ensuring fast, error-free order submissions.', '<p>The customer needed to streamline the process of submitting orders for creating <strong>graphic materials</strong> for regular seasonal advertising banners. They had an <strong>Excel spreadsheet</strong> with orders, which had to be manually entered into <strong>FileMaker</strong>, making it time-consuming and prone to errors. The goal was to <strong>automate and speed up</strong> the process.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]automatic_order_creation.jpg\" alt=\"Automating the process of creating orders for seasonal advertising banners\" /></div>\r\n<p>We implemented a <strong>REST API</strong> that accepts data in <strong>JSON format</strong>. The customer sends data directly from their system in <strong>JSON format to the API</strong>, eliminating the need for any additional user actions that might delay the process or introduce errors. The <strong>API checks the validity of the JSON file</strong>, verifies the required fields, and then passes the validated data to the <strong>FileMaker database</strong>. After validation, a script automatically creates orders in the existing <strong>FileMaker application</strong> based on predefined rules.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]automatic_order_creation_diagram.svg\" alt=\"Diagram of automatic order creation using REST API\" /></div>\r\n<p>This process, which previously took several minutes, is now reduced to just a few seconds thanks to <strong>automation</strong>. The system ensures that all orders are properly <strong>validated</strong> and entered into the database without any manual intervention.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n    <li><a href=\"/fmrestor\">REST API</a></li>\r\n    <li><a href=\"https://www.json.org/json-en.html\" target=\"_blank\">JSON</a></li>\r\n</ul>', 'en', 13),
(30, 'chytre-rizeni-jezirka', 'Chytré řízení jezírka', 'Automatizace řízení jezírka s využitím teplotních senzorů a aplikace FileMaker umožňuje efektivní regulaci zařízení, jako jsou vodopád a UV lampa.', 'Chytré řízení jezírka', 'Řízení jezírka pomocí aplikace FileMaker, Raspberry Pi a meteostanice pro optimalizaci teploty vody a ochranu ryb.', 'Automatizace řízení jezírka s využitím teplotních senzorů a aplikace FileMaker umožňuje efektivní regulaci zařízení, jako jsou vodopád a UV lampa.', '<p>Zákazník potřeboval automatizované řešení pro řízení zařízení u zahradního jezírka, jehož hlavním cílem bylo udržení <strong>optimální teploty vody</strong>. V létě docházelo k <strong>přehřívání vody</strong>, což mělo negativní vliv na <strong>ryby v jezírku</strong>. Zařízení, jako <strong>čerpadlo pro vodopád</strong> a <strong>UV lampa</strong>, byla ovládána <strong>manuálně</strong>, což neumožňovalo efektivní a flexibilní regulaci teploty. Cílem tedy bylo vytvořit systém automatizace na základě <strong>měření teploty vody a vzduchu</strong>, který by byl snadno ovladatelný přes mobilní aplikaci.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Smart_lake_ilustration.jpg\" alt=\"Automatizace řízení jezírka\" /></div>\n<p>Vytvořili jsme aplikaci ve <strong>FileMakeru</strong>, která umožňuje automatizované řízení všech zařízení jezírka. K <strong>měření teploty vody</strong> jsme použili <strong>Raspberry Pi</strong> s externím teploměrem. Raspberry Pi bylo umístěno v šachtě u jezírka, aby mohlo sledovat i teplotu samotného zařízení a zabránit jeho poškození. Pro získání <strong>teploty vzduchu</strong> byla integrována <strong>meteostanice</strong>, která také odesílá data do <strong>FileMaker databáze</strong>.</p>\n<p>V aplikaci jsou nastavena pravidla pro <strong>automatické spouštění vodopádu</strong> tak, aby se voda ochlazovala, pokud je to potřeba. V jarních měsících se naopak vodopád spouští za účelem ohřevu vody. <strong>UV lampa</strong> je rovněž ovládána prostřednictvím aplikace a její stav je monitorován. Notifikace o zapnutí nebo vypnutí UV lampy, stejně jako upozornění na případné problémy, jsou zasílány uživateli prostřednictvím <strong>push notifikací nebo e-mailu</strong>.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Smart_lake_diagram.svg\" alt=\"Diagram chytrého řízení jezírka\" /></div>\n<p><strong>Ovládání zařízení</strong> probíhá pomocí dálkově ovládaných zásuvek, které jsou propojené s <strong>Raspberry Pi</strong>. Každých 5 až 15 minut probíhá kontrola teplotních údajů a aplikace na základě definovaných pravidel rozhoduje, zda spustit či zastavit dané zařízení. Pravidla, včetně definice akcí, které se mají provést, je možné měnit přes uživatelské rozhraní. Řešení umožňuje i <strong>manuální ovládání zařízení</strong> prostřednictvím mobilní aplikace.</p>\n<h2>Použité technologie</h2>\n<ul>\n  <li><a href=\"/fmrestor\">FileMaker</a></li>\n  <li><a href=\"https://24usoftware.com/hardware-integration\" target=\"_blank\">Raspberry Pi</a></li>\n  <li><a href=\"/xgode\">Xgode</a></li>\n  <li><a href=\"https://www.postgresql.org\" target=\"_blank\">PostgreSQL</a></li>\n  <li><a href=\"https://www.davisinstruments.com/products/vantage-vue-weather-station-with-weatherlink-console\" target=\"_blank\">Meteostanice Davis Vantage Vue</a></li>\n  <li><a href=\"https://www.analog.com/en/products/ds18b20.html\" target=\"_blank\">Teploměr - DS18B20</a></li>\n</ul>', 'cs', 14),
(31, 'smart-pond-management', 'Smart Pond Management', 'Automating pond management with temperature sensors and a FileMaker app ensures efficient control of devices like the waterfall pump and UV lamp.', 'Smart Pond Management', 'Pond management using a FileMaker app, Raspberry Pi, and weather station to optimize water temperature and protect fish.', 'Automating pond management with temperature sensors and a FileMaker app ensures efficient control of devices like the waterfall pump and UV lamp.', '<h2>Smart Pond Management</h2>\n<p>The customer needed an automated solution to manage devices in a garden pond, with the primary goal of maintaining <strong>optimal water temperature</strong>. During the summer, the water would <strong>overheat</strong>, negatively impacting the <strong>fish in the pond</strong>. Devices like the <strong>waterfall pump</strong> and <strong>UV lamp</strong> were operated <strong>manually</strong>, which didn’t allow for efficient and flexible temperature regulation. The aim was to create a system that would enable automation based on <strong>water and air temperature measurements</strong> while being easily controllable via a mobile app.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Smart_lake_ilustration.jpg\" alt=\"Automation of pond management\" /></div>\n<p>We developed an application in <strong>FileMaker</strong> that allows automated control of all pond devices. For <strong>measuring water temperature</strong>, we used a <strong>Raspberry Pi</strong> with an external thermometer. The Raspberry Pi was placed in a chamber near the pond to also monitor the temperature of the equipment and prevent damage. For gathering <strong>air temperature</strong> data, a <strong>weather station</strong> was integrated, sending data to the <strong>FileMaker database</strong>.</p>\n<p>The application is programmed to <strong>automatically start the waterfall</strong> when water cooling is needed. In the spring, the waterfall can also be activated to warm the water. The <strong>UV lamp</strong> is controlled via the app, and its status is monitored. Notifications about the UV lamp\'s activation or deactivation, as well as alerts regarding any issues, are sent to the user via <strong>push notifications or email</strong>.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Smart_lake_diagram.svg\" alt=\"Diagram of smart pond management\" /></div>\n<p><strong>The devices are controlled</strong> using remotely operated sockets connected to the <strong>Raspberry Pi</strong>. Every 5 to 15 minutes, the temperature data is checked, and the application decides, based on defined rules, whether to start or stop the respective devices. These rules, including action definitions, can be modified via the user interface. The solution also allows for <strong>manual control of the devices</strong> through the mobile app.</p>\n<h2>Used technologies</h2>\n<ul>\n  <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n  <li><a href=\"https://24usoftware.com/hardware-integration\" target=\"_blank\">Raspberry Pi</a></li>\n  <li><a href=\"/xgode\">Xgode</a></li>\n  <li><a href=\"https://www.postgresql.org\" target=\"_blank\">PostgreSQL</a></li>\n  <li><a href=\"https://www.davisinstruments.com/products/vantage-vue-weather-station-with-weatherlink-console\" target=\"_blank\">Davis Vantage Vue Weather Station</a></li>\n  <li><a href=\"https://www.analog.com/en/products/ds18b20.html\" target=\"_blank\">Thermometer - DS18B20</a></li>\n</ul>', 'en', 14),
(32, 'skladovy-modul', 'Skladový modul', 'Skladový modul integruje sledování výpůjček a spotřeby materiálu s využitím RFID štítků a schvalovacích procesů pro efektivní řízení skladu.', 'Skladový modul', 'Skladový modul s RFID čtečkami umožňuje přesné sledování výpůjček, spotřeby a vracení materiálu s integrací do mobilní aplikace.', 'Skladový modul integruje sledování výpůjček a spotřeby materiálu s využitím RFID štítků a schvalovacích procesů pro efektivní řízení skladu.', '<p>Zákazník požadoval možnost přesného sledování skladu, kdo si <strong>co vypůjčil</strong>, kolik <strong>materiálu spotřeboval</strong> a kolik <strong>vrátil</strong>. Konkrétně k evidenci výpůjček a spotřeby materiálů, jako jsou <strong>nářadí</strong>, <strong>hnojiva</strong> nebo <strong>nafta</strong>.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]warehouse_module_ilustration.jpg\" alt=\"Ilustrace skladového modulu\" /></div>\n<p>Integrovali jsme <strong>skladový modul</strong> do aplikace zákazníka spolu s naším doporučením využití <strong>RFID štítků</strong>. Modul tak zajišťuje evidenci <strong>zboží na skladě</strong>, výpůjček a spotřeby materiálu. Zahrnuje i <strong>schvalování výpůjček</strong> a <strong>objednávek vedoucími</strong>, naskladňování nového zboží a tisk RFID štítků pro snadnou identifikaci.</p>\n<p>V aplikaci jsou integrovány procesy pro <strong>příjem a výdej zboží</strong>, objednávky u externích dodavatelů a administrativní dokumenty, jako je <strong>účetnictví</strong> a <strong>schvalování nákupů</strong>. Schvalovací procesy byly nastaveny tak, aby vedoucí pracovníci byli informováni <strong>notifikací o novém požadavku na nákup</strong> a mohli jej jednoduše schválit.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]warehouse_module_diagram.svg\" alt=\"Diagram skladového modulu\" /></div>\n<p>Pro zefektivnění práce jsme integrovali <strong>RFID čtečky</strong> (Kathrein), které automaticky posílají data o pohybu zboží přímo do FileMakeru, a z těchto údajů se generují dokumenty podle toho, zda šlo o <strong>výdej nebo příjem zboží</strong>. Řešení zahrnuje také <strong>aplikaci pro mobilní zařízení</strong> s možností <strong>skenování QR kódů</strong> z dokumentů pro zobrazení dokumentu v mobilní aplikaci, kde následně potvrzujeme vydání nebo vrácení materiálu.</p>\n<h2>Použité technologie</h2>\n<ul>\n  <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n  <li><a href=\"/integrace-hardware\">RFID čtečka</a></li>\n  <li><a href=\"/xgode\">Xgode</a></li>\n  <li><a href=\"/tracksy\">Tracksy</a></li>\n</ul>', 'cs', 15),
(33, 'warehouse-module', 'Warehouse Module', 'The warehouse module integrates inventory tracking, loans, and material consumption using RFID tags and approval workflows for efficient warehouse management.', 'Warehouse module', 'The warehouse module with RFID readers enables precise tracking of loans, material consumption, and returns with integration into a mobile application.', 'The warehouse module integrates inventory tracking, loans, and material consumption using RFID tags and approval workflows for efficient warehouse management.', '<p>The customer required the ability to precisely track <strong>warehouse activities</strong>, including <strong>who borrowed what</strong>, how much <strong>material was consumed</strong>, and how much <strong>was returned</strong>. This was specifically needed for the recording of <strong>loans and consumption</strong> of materials such as <strong>tools</strong>, <strong>fertilizers</strong>, and <strong>fuel</strong>.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]warehouse_module_ilustration.jpg\" alt=\"Warehouse module illustration\" /></div>\n<p>We integrated a <strong>warehouse module</strong> into the customer’s application, along with our recommendation to use <strong>RFID tags</strong>. The module ensures the tracking of <strong>inventory, loans, and material consumption</strong>. It also includes <strong>approval workflows for loans and orders</strong> by managers, as well as <strong>restocking new items</strong> and printing RFID tags for easy identification.</p>\n<p>The application integrates processes for <strong>receiving and dispatching goods</strong>, ordering from external suppliers, and managing administrative documents, such as <strong>accounting</strong> and <strong>purchase approvals</strong>. Approval workflows were set up so that managers are notified of <strong>new purchase requests</strong> and can easily approve them.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]warehouse_module_diagram.svg\" alt=\"Warehouse module diagram\" /></div>\n<p>To improve efficiency, we integrated <strong>RFID readers</strong> (Kathrein) that automatically send data about <strong>goods movement</strong> directly into FileMaker, where documents are generated based on whether it involves dispatching or receiving goods. The solution also includes a <strong>mobile application</strong> with the ability to <strong>scan QR codes</strong> from documents, displaying them in the mobile app, where <strong>material issuance or returns</strong> can then be confirmed.</p>\n<h2>Used technologies</h2>\n<ul>\n  <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n  <li><a href=\"/hardware-integration\">RFID reader</a></li>\n  <li><a href=\"/xgode\">Xgode</a></li>\n  <li><a href=\"/tracksy\">Tracksy</a></li>\n</ul>', 'en', 15),
(34, 'monitorovani-novych-inzeratu', 'Monitorování nových inzerátů', 'Efektivní aplikace pro monitorování nových inzerátů pomocí XML RSS feedu, s možností automatického filtrování a rychlého upozornění uživatele.', 'Monitorování nových inzerátů', 'Automatizovaná aplikace pro sledování nových inzerátů a zasílání notifikací při nalezení odpovídajících nabídek.', 'Efektivní aplikace pro monitorování nových inzerátů pomocí XML RSS feedu, s možností automatického filtrování a rychlého upozornění uživatele.', '<p>Zákazník potřeboval efektivní způsob, jak <strong>sledovat nové inzeráty</strong> na internetovém serveru. (Server nabízí <strong>XML RSS feed</strong>, což umožňuje automatizované stahování dat v reálně čitelném formátu). Úkolem bylo vyvinout aplikaci, která bude pravidelně kontrolovat nové inzeráty, porovnávat je s požadovanými kritérii, a v případě nalezení odpovídajícího inzerátu informovat uživatele prostřednictvím e-mailu nebo push notifikace.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Monitoring_advertisements_illustration.jpg\" alt=\"Ilustrace monitorování inzerátů\" /></div>\n<p>Vzhledem k tomu, že zákazník již využíval <strong>FileMaker Server</strong> a chtěl data z prodejů dále analyzovat. Vyvinuli jsme aplikaci, která běží právě na <strong>FileMaker Serveru</strong> a pravidelně, každou minutu, načítá <strong>RSS feed</strong> z webové stránky pomocí HTTP požadavků.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Monitoring_advertisements_diagram.svg\" alt=\"Diagram monitorování inzerátů\" /></div>\n<p>Aplikace automaticky zpracovává <strong>XML data</strong>, filtruje je podle uživatelem zadaných kritérií ve <strong>FileMakeru</strong>, jako jsou cena, lokalita a popis zboží. Pokud je nalezen nový inzerát splňující tyto podmínky, okamžitě odešle notifikaci uživateli. Notifikace jsou doručovány buď prostřednictvím e-mailu, nebo služby <strong>Pushover</strong> pro mobilní zařízení, což zajišťuje rychlé upozornění, a tím i větší šanci na včasný kontakt s prodejcem.</p>\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/konzultace-filemaker\">FileMaker Server</a></li>\n    <li><a href=\"https://cs.wikipedia.org/wiki/Extensible_Markup_Language\" target=\"_blank\">XML</a></li>\n</ul>', 'cs', 16),
(35, 'monitoring-new-advertisements', 'Monitoring New Advertisements', 'Efficient application for monitoring new advertisements using XML RSS feed, with automated filtering and quick user notifications.', 'Monitoring New Advertisements', 'Automated application to track new ads and send notifications when matching offers are found.', 'Efficient application for monitoring new advertisements using XML RSS feed, with automated filtering and quick user notifications.', '<p>A customer needed an efficient way to <strong>track new advertisements</strong> on an online server. (The server offers an <strong>XML RSS feed</strong>, enabling automated data downloads in a readable format). The task was to develop an application that would regularly check for new ads, compare them against specified criteria, and notify the user via email or push notification if a matching ad was found.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Monitoring_advertisements_illustration.jpg\" alt=\"Illustration of monitoring advertisements\" /></div>\n<p>Since the customer was already using <strong>FileMaker Server</strong> and wanted to analyze sales data further, we developed an application that runs on <strong>FileMaker Server</strong> and regularly pulls the <strong>RSS feed</strong> from the website every minute using HTTP requests.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Monitoring_advertisements_diagram.svg\" alt=\"Diagram of monitoring advertisements\" /></div>\n<p>The application automatically processes <strong>XML data</strong>, filtering it based on user-specified criteria in <strong>FileMaker</strong>, such as price, location, and product description. If a new ad meeting these conditions is found, it immediately sends a notification to the user. Notifications are delivered either via email or the <strong>Pushover</strong> service for mobile devices, ensuring quick alerts and a better chance to promptly contact the seller.</p>\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"/filemaker-consulting\">FileMaker Server</a></li>\n    <li><a href=\"https://cs.wikipedia.org/wiki/Extensible_Markup_Language\" target=\"_blank\">XML</a></li>\n</ul>', 'en', 16),
(36, 'integrace-e-fakturace-se-statnim-systemem', 'Integrace e-fakturace se státním systémem', 'Efektivní integrace e-fakturace pro státní elektronický systém s podporou SOAP a REST API.', 'Integrace e-fakturace se státním systémem', 'Efektivní integrace e-fakturace pro státní elektronický systém s podporou SOAP a REST API.', 'Efektivní integrace e-fakturace pro státní elektronický systém s podporou SOAP a REST API.', '<p>Zákazník spravuje tisíce faktur ročně a kvůli povinnosti v jeho zemi zasílat všechny faktury do <strong>státního elektronického fakturačního systému</strong> bylo třeba vyvinout řešení pro automatizaci procesu odesílání a stahování faktur. Ruční zadávání vedlo ke <strong>zpožděním</strong> a <strong>chybám</strong>. Stávající systém založený na platformě FileMaker neumožňoval v době zadání přímou integraci zejména kvůli technickým požadavkům na autentizaci.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]e-Invoicing_illustration.jpg\" alt=\"Ilustrace integrace e-fakturace\" /></div>\r\n<p>Vyvinuli jsme proto integrační komponentu v <strong>Javě 8</strong>, která umožnila bezpečné připojení k centrálnímu systému prostřednictvím specifické autentizace pomocí privátních klíčů. Její podpora pro <strong>SOAP</strong> navíc usnadnila generování a zpracování datových zpráv ve formátu <strong>XML</strong>. První verze stahovala nepropracované faktury, což umožnilo jejich automatické zpracování v zákazníkově systému. Museli jsme zajistit i podporu pro složité fakturační struktury, jako např. více faktur se stejným číslem, přílohy, opravy faktur apod.</p>\r\n<p>Pro komunikaci mezi <strong>FileMaker Serverem</strong> a integrační komponentou jsme vytvořili jednoúčelový HTTP server v jazyce <strong>Python</strong>, který komponentu napsanou v Javě volá jako command-line nástroj. Aby byla integrace bezpečnější, komunikaci s integrační komponentou jsme realizovali skrze <strong>šifrované spojení</strong>. Citlivé údaje komponenta dostává skrze parametry, aby nedošlo k jejich uložení na disk v nezašifrované podobě, a to ani dočasně.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]e-Invoicing_diagram.svg\" alt=\"Diagram integrace e-fakturace\" /></div>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n    <li><a href=\"https://www.java.com/en/\" target=\"_blank\">Java</a></li>\r\n    <li><a href=\"/fmrestor\">REST API</a></li>\r\n    <li><a href=\"https://www.json.org/json-en.html\" target=\"_blank\">JSON</a></li>\r\n</ul>', 'cs', 17),
(37, 'integration-of-e-invoicing-with-government-system', 'Integration of e-Invoicing with Government System', 'Automated e-invoicing integration solution using FileMaker, Java 8, and encrypted communication, tailored to government requirements.', 'Integration of e-Invoicing with Government System', 'Efficient e-invoicing integration for the government system with SOAP and REST API support.', 'Automated e-invoicing integration solution using FileMaker, Java 8, and encrypted communication, tailored to government requirements.', '<p>The customer processes thousands of invoices annually and, due to a regulatory requirement in their country to submit all invoices to the <strong>government’s electronic invoicing system</strong>, needed a solution for automating the process of sending and retrieving invoices. Manual entry led to <strong>delays</strong> and <strong>errors</strong>, while their existing FileMaker-based system initially lacked direct integration due to technical authentication requirements.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]e-Invoicing_illustration.jpg\" alt=\"Illustration of e-invoicing integration\" /></div>\r\n<p>To address this, we developed an integration component in <strong>Java 8</strong> that provided secure access to the central system using authentication with private keys. The component’s support for <strong>SOAP</strong> also facilitated data message generation and <strong>XML</strong> format processing. The first version downloaded unprocessed invoices, enabling automatic handling within the customer’s system. We further ensured compatibility with complex invoicing structures (e.g., multiple invoices with the same number, attachments, and corrections).</p>\r\n<p>For communication between the <strong>FileMaker Server</strong> and the integration component, we implemented a dedicated HTTP server in <strong>Python</strong>, which invoked the Java-written component as a command-line tool. To enhance security, we used <strong>encrypted communication</strong>, with sensitive data passed through parameters to avoid storing unencrypted information on disk, even temporarily.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]e-Invoicing_diagram.svg\" alt=\"Diagram of e-invoicing integration\" /></div>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n    <li><a href=\"https://www.java.com/en/\" target=\"_blank\">Java</a></li>\r\n    <li><a href=\"/fmrestor\">REST API</a></li>\r\n    <li><a href=\"https://www.json.org/json-en.html\" target=\"_blank\">JSON</a></li>\r\n</ul>', 'en', 17);
INSERT INTO `skill_content` (`id`, `url`, `title`, `description`, `og_title`, `og_description`, `preview_text`, `html_content`, `id_lang`, `id_skill`) VALUES
(38, 'battery-charging-control-for-e-bikes', 'Battery Charging Control for E-bikes', 'E-bike battery charging management solution using Raspberry Pi and FileMaker to improve battery lifespan and prevent degradation.', 'Battery Charging Control for E-bikes', 'E-bike charging control system designed to enhance battery lifespan through advanced management and monitoring.', 'E-bike battery charging management solution using Raspberry Pi and FileMaker to improve battery lifespan and prevent degradation.', '<p>The customer faced a problem with <strong>battery degradation</strong> in e-bikes due to incorrect charging practices. If batteries were charged to 100% and left fully charged for extended periods, they deteriorated, leading to costly replacements. The objective was to create a system that would automatically stop charging at a preset level, usually around 80%, to <strong>extend battery life</strong>. Additionally, the system required easy monitoring and control of charging, both locally and remotely, to prevent charging beyond daily limits.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Charging_ebike_illustration.jpg\" alt=\"Illustration of e-bike charging control\" /></div>\r\n<p>We developed a battery charging management system combining hardware and software elements. The core of the system is <strong>Raspberry Pi</strong> with a 433 MHz radio module, simulating remote control of outlets to start and stop charging. We integrated this system into the customer’s <strong>FileMaker</strong> application, where users can set charging schedules or stop charging early, preventing overcharging. The Raspberry Pi acts as a <strong>web server</strong>, receiving HTTP requests from FileMaker, which then sends signals to smart outlets that control the charging.</p>\r\n<p>For hardware control, a <strong>push-button switch</strong> was placed on the charger to start charging without needing a mobile device or computer. Additionally, a safety feature was implemented to automatically stop charging daily at a predefined time unless the user provides a different command.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Charging_ebike_diagram.svg\" alt=\"Diagram of the charging management system\" /></div>\r\n<p>The system also logs all charging activities for <strong>battery health</strong> monitoring, allowing the customer to track charging frequency and duration, which can then be compared with battery performance over time. After a year of use, the system demonstrated a significant improvement in <strong>battery lifespan</strong>, confirming that proper charging management effectively prevented degradation.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n    <li><a href=\"/hardware-integration\">Raspberry Pi</a></li>\r\n</ul>', 'en', 18),
(39, 'ovladani-nabijeni-akumulatoru-pro-elektrokola', 'Ovládání nabíjení akumulátorů pro elektrokola', 'Řešení pro řízení nabíjení akumulátorů elektrokol s Raspberry Pi a FileMakerem, které zlepšuje životnost baterií a zabraňuje jejich degradaci.', 'Ovládání nabíjení akumulátorů pro elektrokola', 'Řízení nabíjení akumulátorů elektrokol, které prodlužuje životnost baterií díky pokročilé správě a monitorování.', 'Řešení pro řízení nabíjení akumulátorů elektrokol s Raspberry Pi a FileMakerem, které zlepšuje životnost baterií a zabraňuje jejich degradaci.', '<p>Zákazník se potýkal s problémem <strong>degradace baterií elektrokol</strong> kvůli nesprávnému nabíjení. Pokud byly baterie nabíjeny na 100 % a ponechány v tomto stavu dlouhodobě, docházelo k jejich poškození, což vedlo k nutnosti drahých výměn. Cílem bylo vytvořit systém, který by automaticky zastavil nabíjení při dosažení nastavené úrovně, obvykle okolo 80 %, čímž by se <strong>prodloužila životnost baterie</strong>. Zároveň bylo nutné zajistit snadnou kontrolu nabíjení jak hardwarově, tak na dálku, aby nedocházelo k nabíjení nad rámec denního limitu.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Charging_ebike_illustration.jpg\" alt=\"Ilustrace řízení nabíjení elektrokol\" /></div>\r\n<p>Vyvinuli jsme systém pro řízení nabíjení, který kombinuje hardwarové a softwarové prvky. Základem systému je <strong>Raspberry Pi</strong> s rádiovým modulem na frekvenci 433 MHz, který simuluje dálkové ovládání zásuvek pro zapínání a vypínání nabíjení. Tento systém jsme integrovali do zákazníkovy aplikace ve <strong>FileMakeru</strong>. V této aplikaci může zákazník nastavit čas nabíjení nebo jej předčasně zastavit, čímž se zabrání přebíjení. Raspberry Pi obsahuje <strong>webový server</strong>, který přijímá příkazy z FileMakeru prostřednictvím HTTP požadavků a následně vysílá signály do chytrých zásuvek, které ovládají nabíjení.</p>\r\n<p>Pro hardwarové ovládání byl u nabíječky umístěn <strong>tlačítkový spínač</strong>, který umožňuje spuštění nabíjení bez nutnosti používat mobilní zařízení nebo počítač. Dále byla zavedena ochrana, která automaticky zastaví nabíjení v předem nastavený čas každý den, pokud uživatel nezadá jiný příkaz.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Charging_ebike_diagram.svg\" alt=\"Diagram systému řízení nabíjení\" /></div>\r\n<p>Systém také loguje všechny aktivity spojené s nabíjením pro účely monitorování <strong>zdraví baterie</strong>. Zákazník tak může sledovat, jak dlouho a jak často se baterie nabíjela, a porovnávat to s výkonem baterie v čase. Po ročním používání systém prokázal výrazné zlepšení <strong>životnosti baterií</strong>, čímž se potvrdilo, že správná správa nabíjení účinně zabránila jejich degradaci.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n    <li><a href=\"/hardware-integration\">Raspberry Pi</a></li>\r\n</ul>', 'cs', 18),
(40, 'integrace-ezidebit-do-systemu-spravy-clenstvi', 'Integrace Ezidebit do systému správy členství', 'Integrace Ezidebit do systému správy gymnastických klubů s automatizovaným ověřováním plateb a podporou jednorázových i opakovaných transakcí.', 'Integrace Ezidebit do systému správy členství', 'Flexibilní správa plateb členství s integrací Ezidebit API do systému pro správu gymnastických klubů.', 'Integrace Ezidebit do systému správy gymnastických klubů s automatizovaným ověřováním plateb a podporou jednorázových i opakovaných transakcí.', '<p>Zákazník potřeboval do svého systému pro správu gymnastických klubů integrovat platební službu <strong>Ezidebit</strong> společně s požadavkem na automatizované ověřování stavu plateb. Cílem bylo zjednodušit platby pro členy, kteří si mohli zvolit mezi jednorázovými platbami nebo pravidelnými transakcemi.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Ezidebit_integration_illustration.jpg\" alt=\"Ilustrace integrace Ezidebit\" /></div>\r\n<p>Pro tuto integraci jsme použili <strong>Ezidebit API</strong>, které umožňuje přijímat požadavky na platby přímo z aplikace. Uživatelská aplikace nyní nabízí možnost otevřít formulář pro zadání platby, nebo automaticky zaregistrovat a spravovat opakované platby. Systém zároveň pravidelně kontroluje stav plateb a aktualizuje databázi podle toho, zda byly platby úspěšně dokončeny.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Ezidebit_integration_diagram.svg\" alt=\"Diagram integrace Ezidebit\" /></div>\r\n<p>Tato integrace usnadnila správu plateb a umožnila zákazníkovi flexibilně pracovat s finančními transakcemi přímo v jejich systému.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n    <li><a href=\"https://www.ezidebit.com/en-au/software-integrations/developers\" target=\"_blank\">Ezidebit API</a></li>\r\n</ul>', 'cs', 19),
(41, 'ezidebit-integration-into-membership-management-system', 'Ezidebit Integration into Membership Management System', 'Integration of Ezidebit into a gymnastics club management system with automated payment verification, supporting one-time and recurring transactions.', 'Ezidebit Integration into Membership Management System', 'Flexible membership payment management with Ezidebit API integration into the gymnastics club management system.', 'Integration of Ezidebit into a gymnastics club management system with automated payment verification, supporting one-time and recurring transactions.', '<p>The customer needed to integrate the <strong>Ezidebit</strong> payment service into their gymnastics club management system, along with automated payment status verification. The goal was to simplify payments for members, allowing them to choose between one-time payments or recurring transactions.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Ezidebit_integration_illustration.jpg\" alt=\"Illustration of Ezidebit integration\" /></div>\r\n<p>For this integration, we used the <strong>Ezidebit API</strong>, which allows payment requests to be processed directly from the application. The user-facing app now offers the option to open a payment form or automatically register and manage recurring payments. The system also regularly checks the status of payments and updates the database based on whether payments were successfully completed.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Ezidebit_integration_diagram.svg\" alt=\"Diagram of Ezidebit integration\" /></div>\r\n<p>This integration streamlined payment management and enabled the customer to handle financial transactions more flexibly within their own system.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n    <li><a href=\"https://www.ezidebit.com/en-au/software-integrations/developers\" target=\"_blank\">Ezidebit API</a></li>\r\n</ul>', 'en', 19),
(42, 'active-directory-integration', 'Active Directory Integration', 'Integration of software with Microsoft Active Directory and Azure AD (EntraID) to retrieve and replicate organizational structures without rebuilding them.', 'Active Directory Integration', 'Efficient integration of Active Directory and Azure AD using Python for scalable and flexible management of organizational structures.', 'Integration of software with Microsoft Active Directory and Azure AD (EntraID) to retrieve and replicate organizational structures without rebuilding them.', '<p>The customer needed to integrate their software with organizational structures stored in <strong>Microsoft Active Directory</strong> and <strong>Azure AD</strong> (now EntraID). The goal was to retrieve and replicate data from these directory services so that customers would not have to recreate the organizational structure in the new software. The main challenge was that Active Directory does not strictly enforce a specific structure, meaning each customer has a different setup.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Active_directory_integration.jpg\" alt=\"Illustration of Active Directory integration\" /></div>\r\n<p>For the first version, we used <strong>C#</strong> and <strong>.NET</strong>, as both technologies provide direct support for Active Directory and Azure AD. This application was called from FileMaker via the Toolbox plugin and ran on Windows. However, due to limitations such as the requirement to run on the Windows platform and the slow data transfer from Active Directory, we decided to improve the solution.</p>\r\n<p>The second version of the application was rewritten in <strong>Python</strong>, which brought significant advantages. Python allowed the application to run on various platforms, including Windows, macOS, Linux, and also under Docker, improving scalability and deployment flexibility. Multiple instances of the service can be run on a single server, making it easier to handle a larger number of requests.</p>\r\n<p>A key part of the solution is the field mapping between Active Directory and FileMaker, which is part of our integration call. This mapping ensures the correct transfer of data. The implementation for Azure AD is currently in development, while the integration for Active Directory has already been successfully deployed. Thanks to the transition to Python, the integration now works not only faster and across more platforms but also responds more flexibly to the specific needs of the customer.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Active_directory_integration.svg\" alt=\"Diagram of Active Directory integration\" /></div>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n    <li><a href=\"https://learn.microsoft.com/en-us/windows-server/identity/ad-ds/get-started/virtual-dc/active-directory-domain-services-overview\" target=\"_blank\">Microsoft Active Directory</a></li>\r\n    <li><a href=\"https://www.microsoft.com/en-us/security/business/identity-access/microsoft-entra-id\" target=\"_blank\">EntraID (Azure AD)</a></li>\r\n</ul>', 'en', 20),
(43, 'integrace-active-directory', 'Integrace Active Directory', 'Integrace softwaru s Microsoft Active Directory a Azure AD (EntraID) pro načítání a replikaci organizačních struktur bez nutnosti jejich opětovného vytváření.', 'Integrace Active Directory', 'Efektivní integrace Active Directory a Azure AD s použitím Pythonu, pro škálovatelnější a flexibilnější správu organizačních struktur.', 'Integrace softwaru s Microsoft Active Directory a Azure AD (EntraID) pro načítání a replikaci organizačních struktur bez nutnosti jejich opětovného vytváření.', '<p>Zákazník potřeboval integrovat svůj software s organizačními strukturami uloženými v <strong>Microsoft Active Directory</strong> a <strong>Azure AD</strong> (nyní EntraID). Cílem bylo načítat a replikovat data z těchto adresářových služeb, aby zákazníci nemuseli znovu vytvářet organizační strukturu v novém softwaru. Hlavní výzvou bylo to, že Active Directory nediktuje striktně strukturu, takže ji každý zákazník může mít odlišnou.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Active_directory_integration.jpg\" alt=\"Ilustrace integrace Active Directory\" /></div>\r\n<p>Pro první verzi jsme využili <strong>C#</strong> a <strong>.NET</strong>, protože obě technologie poskytují přímou podporu pro Active Directory i Azure AD. Tato aplikace byla volána z FileMakeru přes Toolbox plugin a běžela na Windows. Nicméně kvůli omezením, jako je nutnost Windows platformy a pomalý přenos dat z Active Directory, jsme se rozhodli řešení vylepšit.</p>\r\n<p>Druhá verze aplikace byla přepsána do <strong>Pythonu</strong>, což přineslo významné výhody. Python nám umožnil, aby aplikace běžela na různých platformách, včetně Windows, macOS i Linuxu, a také pod Dockerem, což zlepšilo škálovatelnost a flexibilitu nasazení. Na jednom serveru lze spustit více instancí služby, což usnadňuje zpracování většího počtu požadavků.</p>\r\n<p>Klíčovou součástí řešení je mapování polí mezi Active Directory a FileMakerem, které je součástí volání naší integrace. Toto mapování zajišťuje správný přenos dat. Implementace pro Azure AD je aktuálně v plánu, zatímco integrace pro Active Directory již byla úspěšně nasazena. Díky přechodu na Python jsme dosáhli toho, že integrace nyní funguje nejen rychleji a na více platformách, ale také flexibilněji reaguje na specifické potřeby zákazníka.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Active_directory_integration.svg\" alt=\"Diagram integrace Active Directory\" /></div>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n    <li><a href=\"https://learn.microsoft.com/en-us/windows-server/identity/ad-ds/get-started/virtual-dc/active-directory-domain-services-overview\" target=\"_blank\">Microsoft Active Directory</a></li>\r\n    <li><a href=\"https://www.microsoft.com/en-us/security/business/identity-access/microsoft-entra-id\" target=\"_blank\">EntraID (Azure AD)</a></li>\r\n</ul>', 'cs', 20),
(44, 'rychly-dotaznik-pro-navstevniky-muzea', 'Rychlý dotazník pro návštěvníky muzea', 'Rychlé a jednoduché řešení dotazníků pro návštěvníky muzea pomocí Xgode a Google Spreadsheet s možností offline ukládání a reálné analýzy dat.', 'Rychlý dotazník pro návštěvníky muzea', 'Efektivní sběr zpětné vazby od návštěvníků muzea s použitím technologie FileMaker a Google Spreadsheet.', 'Rychlé a jednoduché řešení dotazníků pro návštěvníky muzea pomocí Xgode a Google Spreadsheet s možností offline ukládání a reálné analýzy dat.', '<p>Muzeum se na nás obrátilo s požadavkem na vytvoření jednoduchého a rychlého dotazníku, který by návštěvníci mohli snadno vyplňovat na místě po zhlédnutí nových expozic. Cílem bylo získat okamžitý feedback na expozice a data rychle a přehledně zpracovat. Hlavním kritériem byla <strong>jednoduchost použití</strong> a <strong>rychlé nasazení</strong> řešení, které mělo být připraveno do jednoho měsíce.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Museum_survey_illustration.jpg\" alt=\"Ilustrace dotazníku pro muzeum\" /></div>\n<p>Vytvořili jsme jednoduchou aplikaci zbuildovanou nástrojem <strong>Xgode</strong>, která běží na iPadech nainstalovaných v jednotlivých místnostech muzea. Aplikace byla postavena na platformě <strong>FileMaker</strong> a běžela v kiosk módu, což zajistilo snadné ovládání pro návštěvníky. Dotazník obsahoval 5–6 obrazovek s tlačítky pro odpovědi na otázky týkající se expozic. Pokud návštěvník vyplnění dotazníku nedokončil, po uplynutí nastavené časové lhůty se aplikace automaticky vrátila na úvodní obrazovku, aby byla připravena na dalšího návštěvníka.</p>\n<p>V případě, že iPad dočasně ztratil připojené k síti, aplikace uchovávala odpovědi offline. Jakmile bylo zařízení opět online, data se automaticky odesílala do <strong>Google Spreadsheet</strong>, kde měli pracovníci muzea okamžitý přístup k výsledkům v reálném čase. Tento přístup přes sdílený dokument umožnil pracovníkům snadno sledovat a analyzovat data bez nutnosti vlastního serverového řešení.</p>\n<div class=\"image-preview diagram-small\"><img src=\"[[IMAGE_PATH]]Museum_survey_diagram.svg\" alt=\"Diagram řešení dotazníku pro muzeum\" /></div>\n<p>Toto řešení poskytlo muzeu rychlý a snadný způsob, jak získávat zpětnou vazbu od návštěvníků, s možností okamžité analýzy dat, bez nutnosti instalovat a spravovat komplikované serverové řešení.</p>\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n    <li><a href=\"/cs/xgode\">Xgode</a></li>\n    <li><a href=\"https://workspace.google.com/products/sheets/\" target=\"_blank\">Google Spreadsheet</a></li>\n</ul>', 'cs', 21),
(45, 'quick-survey-for-museum-visitors', 'Quick Survey for Museum Visitors', 'Fast and simple survey solution for museum visitors using Xgode and Google Spreadsheet with offline storage and real-time data analysis.', 'Quick Survey for Museum Visitors', 'Efficient visitor feedback collection for museums using FileMaker and Google Spreadsheet technology.', 'Fast and simple survey solution for museum visitors using Xgode and Google Spreadsheet with offline storage and real-time data analysis.', '<p>A museum approached us with a request to create a simple and quick survey that visitors could easily complete on-site after viewing new exhibitions. The goal was to collect immediate feedback on the exhibits and quickly and clearly process the data. The main criteria were <strong>ease of use</strong> and <strong>fast deployment</strong>, with the solution to be ready within one month.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Museum_survey_illustration.jpg\" alt=\"Illustration of museum survey\" /></div>\n<p>We developed a simple application using the <strong>Xgode</strong> tool, which runs on iPads installed in various museum rooms. The app was built on the <strong>FileMaker</strong> platform and operated in kiosk mode, ensuring easy control for visitors. The survey contained 5–6 screens with buttons for answering questions about the exhibitions. If a visitor did not complete the survey, the app automatically returned to the home screen after a set time limit, preparing it for the next visitor.</p>\n<p>If the iPad temporarily lost its network connection, the app stored the answers offline. Once back online, the data was automatically sent to <strong>Google Spreadsheet</strong>, where museum staff had immediate real-time access to the results. This shared document approach allowed staff to easily monitor and analyze data without needing their own server solution.</p>\n<div class=\"image-preview diagram-small\"><img src=\"[[IMAGE_PATH]]Museum_survey_diagram.svg\" alt=\"Diagram of museum survey solution\" /></div>\n<p>This solution provided the museum with a fast and convenient way to collect visitor feedback, with the ability to analyze data immediately, without the need for a complex server setup.</p>\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n    <li><a href=\"/xgode\">Xgode</a></li>\n    <li><a href=\"https://workspace.google.com/products/sheets/\" target=\"_blank\">Google Spreadsheet</a></li>\n</ul>', 'en', 21),
(46, 'providing-access-to-paid-content', 'Providing Access to Paid Content', 'Paid access system for educational materials for teachers, integrated with FileMaker, Vimeo, and AI-powered smart search.', 'Providing access to paid content', 'Providing access to educational content for teachers via a portal with easy content management and automated membership renewal.', 'Paid access system for educational materials for teachers, integrated with FileMaker, Vimeo, and AI-powered smart search.', '<p>The customer had educational content for teachers that was not being fully utilized. The goal was to make use of the existing content by creating a system for <strong>paid access</strong> to these materials, either for a symbolic fee or free access via a coupon. The “portal” was designed to include both a web component for registration and access to the videos, and a <strong>FileMaker</strong> component for content administration and management.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Providing_access_to_paid_content.jpg\" alt=\"Illustration of providing access to paid content\" /></div>\r\n<p>We developed a \"portal\" for the customer with functionality on both the web and in FileMaker. Users, primarily schools, can register through a web form where they have the option to enter a coupon for free membership. The form data is automatically stored in the FileMaker database, where coupons, user access, and content are managed.</p>\r\n<p>On the website, all visitors have access to <strong>free sample videos</strong>. If they want full access to the content, they have two options: either their school registers using a coupon for free access, or they can purchase access for a symbolic fee.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Providing_access_to_paid_content_diagram.svg\" alt=\"Diagram of providing access to paid content\" /></div>\r\n<p>Membership is valid for one year, and one month before its expiration, the system automatically generates an email offering a membership renewal. The platform is integrated with <strong>Vimeo</strong>, where videos are managed, categorized, and supplemented with transcripts, making the content easier to search. Additionally, each school receives a unique code that can be shared with teachers for easy access to the videos.</p>\r\n<p>The system also sends automatic notifications about the upcoming membership expiration, ensuring the process is fully automated and user-friendly. As part of the solution, there is also <strong>AI-powered smart search</strong>, which allows for efficient searching across the educational content.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n    <li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n    <li><a href=\"https://24usoftware.com\">Web</a></li>\r\n    <li><a href=\"https://vimeo.com/watch\" target=\"_blank\">Vimeo</a></li>\r\n</ul>', 'en', 22),
(47, 'zpristupneni-placeneho-obsahu', 'Zpřístupnění placeného obsahu', 'Systém placeného přístupu k vzdělávacím materiálům pro učitele s integrací FileMakeru, Vimeo a AI chytrého vyhledávání.', 'Zpřístupnění placeného obsahu', 'Zpřístupnění vzdělávacího obsahu pro učitele pomocí portálu s jednoduchou správou obsahu a automatickým prodloužením členství.', 'Systém placeného přístupu k vzdělávacím materiálům pro učitele s integrací FileMakeru, Vimeo a AI chytrého vyhledávání.', '<p>Zákazník disponoval vzdělávacím obsahem pro učitele, který s nimi neměl možnost jednoduše sdílet. Cílem bylo využít existující obsah a vytvořit systém <strong>placeného přístupu</strong> k těmto materiálům za symbolickou částku nebo přístup zdarma pomocí kuponu. „Portál“ měl zahrnovat jak webovou část pro registraci a samotný přístup k videím, tak část <strong>FileMakeru</strong> pro administraci a správu obsahu.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Providing_access_to_paid_content.jpg\" alt=\"Ilustrace zpřístupnění placeného obsahu\" /></div>\r\n<p>Pro zákazníka jsme vyvinuli „portál“ s funkcionalitou jak na webu, tak ve FileMakeru. Uživatelé, zejména zaměstnanci škol, se mohou registrovat prostřednictvím webového formuláře, kde mají možnost zadat kupon pro členství zdarma. Data z formuláře jsou automaticky ukládána do FileMaker databáze, kde se spravují kupony, přístupy uživatelů a poskytovaný obsah.</p>\r\n<p>Na webu mají všichni návštěvníci k dispozici <strong>ukázková videa zdarma</strong>. Pokud mají zájem o plný přístup k obsahu, mají dvě možnosti: buď se jejich škola zaregistruje pomocí kuponu a získá přístup zdarma, nebo si mohou přístup zakoupit za symbolickou částku.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Providing_access_to_paid_content_diagram.svg\" alt=\"Diagram zpřístupnění placeného obsahu\" /></div>\r\n<p>Členství je platné jeden rok, a měsíc před jeho expirací systém automaticky generuje e-mail s nabídkou prodloužení členství. Platforma je propojena s <strong>Vimeo</strong>, kde se videa spravují, kategorizují a doplňují o transcripty, což zjednodušuje prohledávání obsahu. Každá škola navíc získá unikátní kód, který mohou sdílet učitelům pro snadný přístup k videím.</p>\r\n<p>Systém automaticky zasílá upozornění na blížící se expiraci členství, čímž se zajišťuje, že je celý proces plně automatizovaný a uživatelsky přívětivý. Součástí řešení je i <strong>chytré vyhledávání pomocí AI</strong>, které umožňuje efektivní prohledávání vzdělávacího obsahu.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n    <li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n    <li><a href=\"https://24usoftware.com\">Web</a></li>\r\n    <li><a href=\"https://vimeo.com/watch\" target=\"_blank\">Vimeo</a></li>\r\n</ul>', 'cs', 22),
(48, 'webova-aplikace-pro-sledovani-casu', 'Webová aplikace pro sledování času', 'Webová aplikace pro sledování času externích pracovníků, integrovaná s FileMakerem přes Data API, s nezávislostí na licencích a snadným používáním.', 'Webová aplikace pro sledování času', 'Řešení pro sledování času stráveného na projektech, které poskytuje nezávislost na cloudových službách a přizpůsobení na míru.', 'Webová aplikace pro sledování času externích pracovníků, integrovaná s FileMakerem přes Data API, s nezávislostí na licencích a snadným používáním.', '<p>Zákazník, který již využívá <strong>FileMaker</strong> pro správu projektů, chtěl vytvořit vlastní webovou aplikaci pro sledování času stráveného na úkolech externími pracovníky, jako jsou grafici. Původně používali komerční cloudové řešení <strong>Clockify</strong>, které však nabízelo zbytečně více funkcí, než bylo potřeba, navíc bylo finančně nákladné kvůli měsíčním licenčním poplatkům. Hlavním cílem tedy bylo vytvořit vlastní aplikaci, která by poskytla nezávislost na licencích, a zjednodušit používání omezením jen na nezbytné funkce.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]timetracking_illustration.jpg\" alt=\"Ilustrace sledování času\" /></div>\n<p>Navrhli jsme webovou aplikaci propojenou přímo s FileMakerem přes <strong>Data API</strong>, která umožňuje uživatelům zaznamenávat čas strávený na jednotlivých projektech. Aplikace využívá <strong>responzivní design</strong>, takže je přístupná z jakéhokoliv zařízení a nezávislá na operačním systému. V FileMakeru jsou projekty spravovány, a externí pracovníci jako grafici mohou přes webovou aplikaci zaznamenávat čas strávený na přidělených projektech.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]timetracking_diagram.svg\" alt=\"Diagram řešení sledování času\" /></div>\n<p>Toto řešení výrazně zjednodušilo sledování stráveného času a přineslo úspory, protože zákazník se vyhnul nákladným licencím a získal aplikaci šitou na míru jeho potřebám.</p>\n<h2>Použité technologie</h2>\n<ul>\n    <li><a href=\"/konzultace-filemaker\">FileMaker Server</a></li>\n</ul>', 'cs', 23),
(49, 'web-application-for-time-tracking', 'Web Application for Time Tracking', 'A web application for tracking time spent by external workers, integrated with FileMaker via Data API, offering independence from licenses and ease of use.', 'Web Application for Time Tracking', 'A time tracking solution for project tasks providing independence from cloud services and tailored functionality.', 'A web application for tracking time spent by external workers, integrated with FileMaker via Data API, offering independence from licenses and ease of use.', '<p>A customer who already uses <strong>FileMaker</strong> for project management wanted to create a custom web application for tracking the time external workers, such as graphic designers, spend on tasks. Initially, they used the commercial cloud solution <strong>Clockify</strong>, which offered more features than necessary and was costly due to monthly licensing fees. The main goal was to create a custom application to ensure independence from licenses and simplify usage by focusing only on essential features.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]timetracking_illustration.jpg\" alt=\"Illustration of time tracking\" /></div>\n<p>We designed a web application directly connected to FileMaker via the <strong>Data API</strong>, enabling users to log time spent on individual projects. The application uses a <strong>responsive design</strong>, making it accessible from any device and independent of the operating system. Projects are managed in FileMaker, and external workers, like graphic designers, can log their time spent on assigned projects through the web application.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]timetracking_diagram.svg\" alt=\"Diagram of the time tracking solution\" /></div>\n<p>This solution significantly simplified time tracking and led to savings, as the customer avoided costly licenses and gained an application tailored to their needs.</p>\n<h2>Used technologies</h2>\n<ul>\n    <li><a href=\"/filemaker-consulting\">FileMaker Server</a></li>\n</ul>', 'en', 23),
(50, 'integrace-telefonniho-systemu-s-filemakerem', 'Integrace telefonního systému s FileMakerem', 'Zákazník z prostředí zdravotnictví hledal způsob, jak zefektivnit práci svého callcentra, které slouží hlavně pro objednávání pacientů na vyšetření. Při příchozích hovorech zaměstnanci museli ručně vyhledávat karty pacientů v databázi, což bylo zdlouhavé.', 'Integrace telefonního systému s FileMakerem', 'Automatizace callcentra pomocí pluginu Phone Companion pro FileMaker. Připojení telefonní ústředny k databázi pacientů a automatické vyhledávání volajících.', 'Zákazník z prostředí zdravotnictví hledal způsob, jak zefektivnit práci svého callcentra, které slouží hlavně pro objednávání pacientů na vyšetření. Při příchozích hovorech zaměstnanci museli ručně vyhledávat karty pacientů v databázi, což bylo zdlouhavé.', '<p>Zákazník z prostředí zdravotnictví hledal způsob, jak zefektivnit práci svého callcentra, které slouží hlavně pro objednávání pacientů na vyšetření. Při příchozích hovorech zaměstnanci museli ručně vyhledávat karty pacientů v databázi, což bylo zdlouhavé.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Integration_callcentrum_illustration.jpeg\" alt=\"Telefonní systém integrovaný s FileMakerem pro rychlé vyhledání pacientů.\" /></div>\n<p>Pro řešení jsme použili vlastní plugin <strong>Phone Companion</strong> pro FileMaker, který zajišťuje obousměrnou komunikaci mezi telefonní ústřednou a databází pacientů. Při příchozím hovoru ústředna předává telefonní číslo plug-inu. Ten spustí skript ve FileMakeru, který zjistí, zda číslo odpovídá pacientovi v databázi. Pokud je nalezena shoda, systém zobrazí jméno pacienta a telefonní číslo s možností přijmout hovor a zároveň jedním kliknutím otevřít detailní kartu pacienta.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Integration_callcentrum_diagram.svg\" alt=\"Diagram integrace telefonního systému s FileMakerem.\" /></div>\n<p>V detailu pacienta jsou informace o pacientovi a tlačítko, které umožňuje zavolat pacientovi. Plugin prostřednictvím aplikace <strong>3CX Softphone</strong> předává informace o volaném čísle zpět ústředně, která hovor zprostředkuje. Celé řešení jsme zrealizovali pro Windows, kde je aplikace 3CX plně kompatibilní.</p>\n<p>Díky této integraci již zaměstnanci nemusí manuálně vyhledávat čísla, což zrychlilo a zjednodušilo jejich práci.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n<li><a href=\"https://www.3cx.com\" target=\"_blank\">3CX Softphone</a></li>\n<li><a href=\"/phonecompanion\">Phone Companion</a></li>\n</ul>', 'cs', 24),
(51, 'integration-of-a-telephone-system-with-filemaker', 'Integration of a Telephone System with FileMaker', 'A healthcare customer sought a way to streamline their call center operations, primarily used for scheduling patient appointments.', 'Integration of a Telephone System with FileMaker', 'Automating a call center with the Phone Companion plugin for FileMaker.', 'A healthcare customer sought a way to streamline their call center operations, primarily used for scheduling patient appointments.', '<p>A healthcare customer sought a way to streamline their call center operations, primarily used for scheduling patient appointments.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Integration_callcentrum_illustration.jpeg\" alt=\"Telephone system integrated with FileMaker for quick patient lookup.\" /></div>\r\n<p>To address this, we implemented a custom <strong>Phone Companion</strong> plugin for FileMaker, enabling two-way communication between the phone system and the patient database. When an incoming call is received, the phone system sends the caller\'s phone number to the plugin. The plugin triggers a script in FileMaker to check if the number matches a patient record in the database. If a match is found, the system displays the patient\'s name and phone number, allowing the employee to answer the call and open the patient\'s detailed record with a single click.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Integration_callcentrum_diagram.svg\" alt=\"Diagram of telephone system integration with FileMaker.\" /></div>\r\n<p>The patient record provides detailed information about the patient and includes a button to call the patient directly. The plugin, via the <strong>3CX Softphone</strong> application, sends the recipient\'s phone number back to the phone system, which facilitates the call. This solution was implemented for Windows, where the 3CX application is fully compatible.</p>\r\n<p>This integration eliminated the need for manual number searches, significantly speeding up and simplifying the workflow for employees.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n<li><a href=\"https://www.3cx.com\" target=\"_blank\">3CX Softphone</a></li>\r\n<li><a href=\"/phonecompanion\">Phone Companion</a></li>\r\n</ul>', 'en', 24),
(52, 'casove-ovladani-zasuvek', 'Časové ovládání zásuvek', 'Automatizace ovládání zásuvek pomocí Raspberry Pi a FileMakeru. Řešení pro spolehlivé plánování zapínání a vypínání zařízení.', 'Časové ovládání zásuvek', 'Automatizované ovládání zásuvek s využitím FileMakeru a Raspberry Pi. Webová aplikace pro správu časového rozvrhu.', 'Automatizace ovládání zásuvek pomocí Raspberry Pi a FileMakeru. Řešení pro spolehlivé plánování zapínání a vypínání zařízení.', '<p><strong>Zákazník měl potřebu automatizovat ovládání zásuvek</strong> na určité časy. Využívání tradičních digitálních časovačů nebylo spolehlivé, zvláště při výpadcích elektřiny, kdy se nastavení resetovalo a proto chtěl pro ukládání aktuálního nastavení zásuvek použít FileMakerovou databázi. Dalším požadavkem bylo vytvořit webovou aplikaci, která umožní vzdálené přizpůsobení rozvrhu zapínání a vypínání zařízení.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Smart_sockets_illustration.jpg\" alt=\"Ilustrace chytrých zásuvek ovládaných přes Raspberry Pi.\" /></div>\n<p>Pro tento projekt jsme zvolili řešení pomocí <strong>dálkově ovládaných zásuvek na frekvenci 433 MHz</strong>, které umožňují ovládání přes Raspberry Pi s nainstalovaným vysílačem a přijímačem. Nejprve jsme naprogramovali Raspberry Pi tak, aby dokázalo rozpoznat signály z původního dálkového ovladače. Následně jsme vytvořili webovou aplikaci, která umožňuje zadávat příkazy přímo z rozhraní a na dálku spouštět a vypínat zásuvky dle nastavených časů.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Smart_sockets_diagram.svg\" alt=\"Diagram integrace chytrých zásuvek s Raspberry Pi.\" /></div>\n<p><strong>Každá zásuvka byla konfigurována jako záznam v databázi</strong> s přiřazeným časovým plánem, podle kterého dochází k automatizovanému spouštění a vypínání podle předem definovaných časů. Aby se zajistila spolehlivost, tak je na FileMaker serveru každou minutu spouštěna úloha, která kontroluje aktuální plnění nastaveného rozvrhu. Díky námi vytvořené webové aplikaci je možné tento rozvrh odkudkoliv měnit.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n<li><a href=\"/integrace-hardware\">Raspberry Pi</a></li>\n<li><a href=\"/integrace-hardware\">Komunikační moduly</a></li>\n<li><a href=\"/konzultace-filemaker\">PHP</a></li>\n</ul>', 'cs', 25),
(53, 'timed-control-of-power-outlets', 'Timed control of power outlets', 'Automating power outlet control using Raspberry Pi and FileMaker. A reliable solution for scheduling device activation and deactivation.', 'Timed control of power outlets', 'Automated power outlet control with FileMaker and Raspberry Pi. A web application for managing schedules remotely.', 'Automating power outlet control using Raspberry Pi and FileMaker. A reliable solution for scheduling device activation and deactivation.', '<p><strong>The customer needed to automate the control of power outlets</strong> at specific times. Traditional digital timers proved unreliable, especially during power outages, as their settings would reset. Therefore, the customer wanted to use a FileMaker database to store the current outlet settings. Another requirement was the creation of a web application that would allow remote customization of the schedule for turning devices on and off.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Smart_sockets_illustration.jpg\" alt=\"Illustration of smart sockets controlled via Raspberry Pi.\" /></div>\n<p>For this project, we implemented a solution using <strong>remotely controlled outlets operating on the 433 MHz frequency</strong>, which can be controlled via a Raspberry Pi equipped with a transmitter and receiver. First, we programmed the Raspberry Pi to recognize signals from the original remote control. Next, we developed a web application that allows users to input commands directly from the interface and remotely turn the outlets on or off according to the configured schedules.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Smart_sockets_diagram.svg\" alt=\"Diagram of smart socket integration with Raspberry Pi.\" /></div>\n<p><strong>Each outlet was configured as a record in the database</strong> with an assigned schedule, enabling automated activation and deactivation at predefined times. To ensure reliability, a task runs every minute on the FileMaker server to check the current adherence to the set schedule. Thanks to the web application we developed, this schedule can be modified from anywhere.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n<li><a href=\"/hardware-integration\">Raspberry Pi</a></li>\n<li><a href=\"/hardware-integration\">Communication modules</a></li>\n<li><a href=\"/filemaker-consulting\">PHP</a></li>\n</ul>', 'en', 25),
(54, 'komunikace-pomoci-protokolu-dicom', 'Komunikace pomocí protokolu DICOM', 'Automatizované propojení zdravotnických zařízení s databází FileMaker prostřednictvím protokolu DICOM.', 'Komunikace pomocí protokolu DICOM', 'Automatizované propojení zdravotnických zařízení s FileMakerem pro rychlé a bezchybné sdílení dat přes DICOM protokol.', 'Automatizované propojení zdravotnických zařízení s databází FileMaker prostřednictvím protokolu DICOM.', '<p><strong>Zákazník hledal způsob, jak umožnit zdravotnickým zařízením</strong> (např. rentgenům, mamografům, CT) přistupovat k informacím o pacientech a plánovaných vyšetřeních uložených ve FileMakerové databázi.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Downloading_dicom_illustration.jpg\" alt=\"Ilustrace komunikace zdravotnických zařízení pomocí DICOM protokolu.\" /></div>\r\n<p>K řešení jsme použili námi vyvinutý plugin <strong>SimpleTalk</strong> rozšířený o podporu protokolu DICOM.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Downloading_dicom_diagram.svg\" alt=\"Diagram komunikace přes DICOM protokol s FileMakerem.\" /></div>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n<li><a href=\"/cs/simpletalk\">SimpleTalk</a></li>\r\n<li><a href=\"/konzultace-filemaker\">DICOM protokol</a></li>\r\n</ul>', 'cs', 26),
(55, 'communication-via-the-dicom-protocol', 'Communication via the DICOM protocol', 'Automated integration of medical devices with a FileMaker database using the DICOM protocol.', 'Communication via the DICOM protocol', 'Seamless communication between medical devices and FileMaker for fast and error-free data exchange using the DICOM protocol.', 'Automated integration of medical devices with a FileMaker database using the DICOM protocol.', '<p><strong>The customer sought a way to enable medical devices</strong> (e.g., X-rays, mammography machines, CT scanners) to access patient information and scheduled examinations stored in a FileMaker database.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Downloading_dicom_illustration.jpg\" alt=\"Illustration of medical device communication using the DICOM protocol.\" /></div>\r\n<p>We implemented the solution using our custom plugin <strong>SimpleTalk</strong>, extended with DICOM protocol support.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Downloading_dicom_diagram.svg\" alt=\"Diagram of communication using the DICOM protocol with FileMaker.\" /></div>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n<li><a href=\"/simpletalk\">SimpleTalk</a></li>\r\n<li><a href=\"/filemaker-consulting\">DICOM protocol</a></li>\r\n</ul>', 'en', 26),
(56, 'sdileni-vysledku-vysetreni-dicom', 'Sdílení výsledků vyšetření (DICOM)', 'Umožnění pacientům přístupu k výsledkům vyšetření pomocí dočasných přihlašovacích údajů generovaných ve FileMakeru.', 'Sdílení výsledků vyšetření (DICOM)', 'Dočasný přístup k výsledkům vyšetření přes QR kód a FileMaker, bez nutnosti složitého přihlašování.', 'Umožnění pacientům přístupu k výsledkům vyšetření pomocí dočasných přihlašovacích údajů generovaných ve FileMakeru.', '<p><strong>Zákazník hledal způsob, jak zpřístupnit výsledky vyšetření pacientům</strong>, kteří nemají přístup do pacientského portálu, nebo nejsou schopni přihlášení kvůli věku či technickým obtížím. Pacientům bylo třeba zajistit přístup, který umožní sdílení výsledků s ošetřujícím lékařem či dalším zdravotnickým personálem bez nutnosti složitého přihlašování do pacientského portálu.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Exam_sharing_illustration.jpg\" alt=\"Ilustrace sdílení výsledků vyšetření pomocí QR kódu.\" /></div>\r\n<p>Vyvinuli jsme <strong>dočasný přístup pomocí automaticky generovaného jména a hesla</strong>, které může uživatel jednoduše načíst pomocí QR kódu např. svým mobilním telefonem. Ten je generován ve formátu PDF ve FileMakerové databázi obsahující pacientská data pomocí námi vyvinuté custom funkce.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Exam_sharing_diagram.svg\" alt=\"Diagram sdílení výsledků vyšetření pomocí QR kódu.\" /></div>\r\n<p>Toto PDF obsahuje kromě QR kódu také URL adresu pacientského portálu a dočasně vygenerované přihlašovací údaje, pomocí nichž je možné se dostat k vyšetření buď automatickým přihlášením přes QR kód, nebo ručním zadáním údajů do portálu.</p>\r\n<p>Tento přístup má <strong>omezenou platnost</strong>, kterou lze nastavit (například 14 dní) a v případě potřeby i předčasně ukončit. Veškerá logika generování PDF a přístupových údajů je implementována za použití nativních funkcí FileMakeru bez jakékoliv externí aplikace, funkce či QR generátoru, čímž je zajištěna rychlost, bezpečnost a jednoduchost celého procesu.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n<li><a href=\"https://24usw.com/pdfbarcodes\" target=\"_blank\">Custom funkce na generování QR</a></li>\r\n</ul>', 'cs', 27),
(57, 'sharing-examination-results-dicom', 'Sharing examination results (DICOM)', 'Providing patients with temporary access to examination results using login credentials generated in FileMaker.', 'Sharing examination results (DICOM)', 'Temporary access to examination results via QR code and FileMaker, without complex login requirements.', 'Providing patients with temporary access to examination results using login credentials generated in FileMaker.', '<p><strong>The customer needed a way to provide patients access to their examination results</strong>, especially for those who lacked access to the patient portal or faced difficulties logging in due to age or technical challenges. The goal was to create a solution that would enable patients to share their results with their attending physician or other medical staff without requiring complex authentication through the patient portal.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Exam_sharing_illustration.jpg\" alt=\"Illustration of sharing examination results using QR codes.\" /></div>\r\n<p>We developed a <strong>temporary access solution using automatically generated usernames and passwords</strong>, which users can easily retrieve via a QR code, for example, with their mobile phones. The QR code is generated in PDF format within the FileMaker database containing patient data, utilizing a custom function we created specifically for this purpose.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Exam_sharing_diagram.svg\" alt=\"Diagram of sharing examination results using QR code.\" /></div>\r\n<p>The PDF includes not only the QR code but also the URL of the patient portal and the temporarily generated login credentials.</p>\r\n<p>This access is <strong>time-limited</strong>, with a configurable validity period (e.g., 14 days) and can be revoked early if necessary. All logic for generating the PDF and access credentials is implemented using native FileMaker functions without any external applications, tools, or QR generators, ensuring speed, security, and simplicity throughout the process.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n<li><a href=\"https://24usw.com/pdfbarcodes\" target=\"_blank\">Custom function for QR code generation</a></li>\r\n</ul>', 'en', 27);
INSERT INTO `skill_content` (`id`, `url`, `title`, `description`, `og_title`, `og_description`, `preview_text`, `html_content`, `id_lang`, `id_skill`) VALUES
(58, 'integrace-flightbridge-a-traqpak-api-do-filemakeru', 'Integrace FlightBridge a TRAQPak API do FileMakeru', 'Automatizované propojení FlightBridge a TRAQPak API s FileMakerem pro efektivní plánování pohybu letadel.', 'Integrace FlightBridge a TRAQPak API do FileMakeru', 'Real-time synchronizace příletů a odletů letadel mezi FlightBridge, TRAQPak a FileMakerem pomocí Claris Connect.', 'Automatizované propojení FlightBridge a TRAQPak API s FileMakerem pro efektivní plánování pohybu letadel.', '<p><strong>Zákazník disponuje FileMaker aplikací</strong> pro plánování umístění letadel na letišti. V tomto případě slouží FileMaker aplikace jako backend pro JAVA aplikaci, která slouží jako uživatelské prostředí. Pro zefektivnění práce potřeboval vědět o každém letadle, kdy přiletí a kdy odletí. Hlavním cílem tedy bylo integrovat tato data do systému zákazníka.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Integration_flightbridge_illustration.jpeg\" alt=\"Ilustrace integrace FlightBridge a TRAQPak API s FileMakerem.\" /></div>\n<p>Pro naše řešení jsme implementovali <strong>sychronizaci s FlightBridge rezervační služby</strong>. Pro realizaci jsme využili Claris Connect, který slouží jako mezičlánek mezi FlightBridge API a FileMaker databází. Claris Connect flow pravidelně, každou hodinu, kontroluje data ve FlightBridge API a stahuje potřebné informace o plánovaných příletech a službách pouze pro letiště, kam má FlightBridge přístup, a posílá je do FileMakeru. Systém tak zajišťuje, že uživatelé mají aktuální informace o příletech a mohou efektivně alokovat hangárová místa a potřebné služby pro letadla.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Integration_flightbridge_diagram.svg\" alt=\"Diagram synchronizace FlightBridge a TRAQPak API s FileMakerem.\" /></div>\n<p>Integrace jsme v následující iteraci <strong>rozšířili o další zdroj dat, službu TRAQPak</strong>, což poskytlo ještě širší spektrum informací o letadlech a rezervacích. Claris Connect i zde funguje jako prostředník mezi jednotlivými API a FileMakerovou databází, což umožňuje, že zákazník má vždy přístup k aktuálním a přesným informacím.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n<li><a href=\"https://www.claris.com/connect/\" target=\"_blank\">Claris Connect</a></li>\n</ul>', 'cs', 28),
(59, 'integration-of-flightbridge-and-traqpak-apis-into-filemaker', 'Integration of FlightBridge and TRAQPak APIs into FileMaker', 'Automated integration of FlightBridge and TRAQPak APIs with FileMaker for efficient aircraft movement planning.', 'Integration of FlightBridge and TRAQPak APIs into FileMaker', 'Real-time synchronization of aircraft arrivals and departures between FlightBridge, TRAQPak, and FileMaker using Claris Connect.', 'Automated integration of FlightBridge and TRAQPak APIs with FileMaker for efficient aircraft movement planning.', '<p><strong>The customer uses a FileMaker application</strong> for planning the allocation of aircraft at an airport. In this setup, the FileMaker application acts as a backend for a Java application serving as the user interface. To streamline operations, the customer needed real-time information about aircraft arrivals and departures. The primary objective was to integrate this data into their system.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Integration_flightbridge_illustration.jpeg\" alt=\"Illustration of FlightBridge and TRAQPak API integration with FileMaker.\" /></div>\n<p>For our solution, we implemented <strong>synchronization with the FlightBridge reservation service</strong>. Using Claris Connect as an intermediary between the FlightBridge API and the FileMaker database, we developed a flow that checks FlightBridge API data every hour. It retrieves information about planned arrivals and services exclusively for airports where FlightBridge has access, sending the data to FileMaker. This ensures users have up-to-date information about arrivals and can efficiently allocate hangar spaces and necessary services for aircraft.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Integration_flightbridge_diagram.svg\" alt=\"Diagram of FlightBridge and TRAQPak API synchronization with FileMaker.\" /></div>\n<p>In the subsequent iteration, we <strong>extended the integration to include an additional data source, the TRAQPak service</strong>, providing an even broader range of information about aircraft and reservations. Here too, Claris Connect acts as a bridge between the APIs and the FileMaker database, ensuring the customer always has access to current and accurate data.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n<li><a href=\"https://www.claris.com/connect/\" target=\"_blank\">Claris Connect</a></li>\n</ul>', 'en', 28),
(60, 'integrace-google-ad-manager-s-filemakerem', 'Integrace Google Ad Manager s FileMakerem', 'Automatizované propojení FileMakeru s Google Ad Manager API pro snadné získávání dat o reklamních kampaních.', 'Integrace Google Ad Manager s FileMakerem', 'Automatická synchronizace reklamních reportů mezi Google Ad Manager API a FileMakerem pro efektivní správu inzerce.', 'Automatizované propojení FileMakeru s Google Ad Manager API pro snadné získávání dat o reklamních kampaních.', '<p><strong>Zákazník, který prodává inzerci pro časopisy i online reklamní plochy</strong>, potřeboval automatizovat proces získávání dat o reklamních kampaních z Google Ad Manager (GAM). Hlavním cílem bylo získávat reporty o počtu zobrazení (impresí) a jejich rozložení mezi weby, a to pravidelně a bez manuálního zásahu.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Integration_gam_illustration.jpeg\" alt=\"Ilustrace integrace Google Ad Manager s FileMakerem.\" /></div>\n<p>Řešení jsme zrealizovali <strong>integrací GAM API do FileMakeru</strong>. Vytvořili jsme skript, který umožňuje pravidelný import reportů o kampaních jednou týdně a ruční stahování dat na vyžádání.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Integration_gam_diagram.svg\" alt=\"Diagram automatizace importu dat z Google Ad Manager do FileMakeru.\" /></div>\n<p>Proces začíná <strong>požadavkem na report z FileMakeru do GAM</strong> prostřednictvím webové služby (SOAP). Skládá se z několika volání. První volání je vygenerování samotného reportu s požadovanými parametry. Ve druhém volání se kontroluje, zda je report vygenerovaný. Po vygenerování nám služba vrátí URL reportu, který zpracujeme a data automaticky importujeme do FileMakeru. Tato data jsou rozčleněna podle jednotlivých webů a počtu impresí. Systém tak sleduje splnění klientských požadavků na slíbený počet impresí a jejich rozdělení mezi různé weby.</p>\n<p><strong>Tímto řešením jsme eliminovali manuální práci</strong> a zlepšili tak efektivitu zpracování dat.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n<li><a href=\"https://developers.google.com/ad-manager/api/start\" target=\"_blank\">Google Ad Manager API</a></li>\n</ul>', 'cs', 29),
(61, 'integration-of-google-ad-manager-with-filemaker', 'Integration of Google Ad Manager with FileMaker', 'Automated integration of FileMaker with Google Ad Manager API for easy retrieval of advertising campaign data.', 'Integration of Google Ad Manager with FileMaker', 'Automatic synchronization of advertising reports between Google Ad Manager API and FileMaker for efficient ad management.', 'Automated integration of FileMaker with Google Ad Manager API for easy retrieval of advertising campaign data.', '<p><strong>A customer, who sells advertising for magazines and online ad spaces</strong>, needed to automate the process of retrieving advertising campaign data from Google Ad Manager (GAM). The primary goal was to regularly obtain reports on the number of impressions and their distribution across websites without manual intervention.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Integration_gam_illustration.jpeg\" alt=\"Illustration of Google Ad Manager integration with FileMaker.\" /></div>\n<p>We implemented the solution by <strong>integrating the GAM API with FileMaker</strong>. We created a script that enables the regular import of campaign reports on a weekly basis, as well as manual data downloads on demand.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Integration_gam_diagram.svg\" alt=\"Diagram of automated data import from Google Ad Manager to FileMaker.\" /></div>\n<p>The process starts with a <strong>report request from FileMaker to GAM</strong> via a web service (SOAP). It consists of several steps. The first step is generating the report with the required parameters. In the second step, the system checks whether the report has been generated. Once the report is ready, the service returns a report URL, which is processed, and the data is automatically imported into FileMaker. The data is then broken down by individual websites and the number of impressions. This allows the system to monitor whether client requirements for the promised number of impressions and their distribution across different websites are being met.</p>\n<p><strong>This solution eliminated manual work</strong> and significantly improved the efficiency of data processing.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n<li><a href=\"https://developers.google.com/ad-manager/api/start\" target=\"_blank\">Google Ad Manager API</a></li>\n</ul>', 'en', 29),
(62, 'automatizace-fakturace-ve-filemakeru-s-prenosem-do-helios', 'Automatizace fakturace ve FileMakeru s přenosem do Heliosu', 'Automatizovaný přenos faktur z FileMakeru do účetního systému Helios bez nutnosti manuálního zásahu.', 'Automatizace fakturace ve FileMakeru s přenosem do Heliosu', 'Bezchybný přenos faktur z FileMakeru do Heliosu pomocí SQL synchronizace a automatického zpracování.', 'Automatizovaný přenos faktur z FileMakeru do účetního systému Helios bez nutnosti manuálního zásahu.', '<p><strong>Zákazník ve svém řešení prováděl přenos faktur mezi svou aplikací a Heliosem</strong> (standardizovaný účetní systém) ručně, což vedlo k častým chybám. Firma tedy požadovala řešení, které by zcela eliminovalo nutnost ručního přepisu faktur mezi systémy a zajistilo přenesení dat.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Helios_integration_illustration.jpeg\" alt=\"Ilustrace integrace fakturace ve FileMakeru s Heliosem.\" /></div>\n<p>Ve FileMakeru jsme vytvořili úlohu, která <strong>každou hodinu kontroluje uzavřené faktury</strong>. Tyto faktury jsou následně zapsány do pomocné SQL databáze. Pomocí nativní funkce FileMakeru, ExecuteSQL, je v SQL databázi volána SQL metoda, která faktury zpracovává a přenese je do Heliosu. Po zpracování faktur se výsledek propíše zpět do FileMakeru a pokud zpracování faktur neproběhne v pořádku, tak je správce informován emailem.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Helios_integration_diagram.svg\" alt=\"Diagram procesu fakturace mezi FileMakerem a Heliosem.\" /></div>\n<p><strong>Díky tomuto řešení se výrazně snížila chybovost</strong> a celý proces fakturace se zefektivnil.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n</ul>', 'cs', 30),
(63, 'automated-invoicing-in-filemaker-with-integration-to-helios', 'Automated Invoicing in FileMaker with Integration to Helios', 'Automated invoice transfer from FileMaker to the Helios accounting system without manual intervention.', 'Automated Invoicing in FileMaker with Integration to Helios', 'Error-free invoice synchronization from FileMaker to Helios using SQL automation.', 'Automated invoice transfer from FileMaker to the Helios accounting system without manual intervention.', '<p><strong>The customer previously transferred invoices between their application and Helios</strong> (a standardized accounting system) manually, leading to frequent errors. The company requested a solution to completely eliminate the need for manual data entry and ensure seamless data transfer.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Helios_integration_illustration.jpeg\" alt=\"Illustration of invoice integration in FileMaker with Helios.\" /></div>\n<p>In FileMaker, we developed a task that <strong>checks for finalized invoices every hour</strong>. These invoices are written into an auxiliary SQL database. Using FileMaker\'s native ExecuteSQL function, an SQL method is called within the database to process the invoices and transfer them to Helios. Once processed, the results are synchronized back to FileMaker, and in case of any processing errors, the administrator is notified via email.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Helios_integration_diagram.svg\" alt=\"Diagram of invoice processing between FileMaker and Helios.\" /></div>\n<p><strong>This solution significantly reduced errors</strong> and streamlined the entire invoicing process.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n</ul>', 'en', 30),
(65, 'integrace-s-terralab', 'Integrace s TerraLab', 'Automatizované propojení FileMakeru s laboratorním systémem TerraLab pro efektivní přenos požadavků na vyšetření a jejich výsledků.', 'Integrace s TerraLab', 'Napojení FileMakeru na laboratorní systém TerraLab pomocí API pro automatizované zpracování testů.', 'Automatizované propojení FileMakeru s laboratorním systémem TerraLab pro efektivní přenos požadavků na vyšetření a jejich výsledků.', '<p><strong>Zákazník měl dvě aplikace pro různé procesy</strong>, z nichž jedna sloužila jako databázový systém pro zdravotnické úkony a druhá aplikace, TerraLab, byla využívána v laboratorním prostředí. Zákazník potřeboval tyto systémy propojit, aby zefektivnil předávání požadavků na laboratorní vyšetření do TerraLabu a výsledků vyšetření zpět do databázového systému, což bylo do té doby prováděno ručně.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Terralab_integration_illustration.jpg\" alt=\"Ilustrace integrace laboratorního systému TerraLab s FileMakerem.\" /></div>\n<p>Na základě specifikací dodaných firmou, která vyvinula aplikaci TerraLab, jsme <strong>integrovali jejich API rozhraní</strong>. Když ve FileMaker databázi vytvoří doktor požadavek na laboratorní vyšetření, jako je například krevní test, požadavek je automaticky přidán do fronty ke zpracování a odeslání do TerraLabu skrze API. V rámci requestu jsou přeneseny informace potřebné pro laboratorní test, včetně údajů o pacientovi.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Terralab_integration_diagram.svg\" alt=\"Diagram propojení FileMakeru a TerraLabu pomocí API.\" /></div>\n<p>Po dokončení vyšetření v laboratoři <strong>TerraLab zavolá adresu API systému</strong> a předá výsledky. Tyto výsledky se automaticky uloží do databáze, což umožňuje lékaři ihned zobrazit a vyhotovit zprávu pro pacienta. TerraLab spouští PHP skript na webovém serveru, který následně prostřednictvím <a href=\"/konzultace-filemaker\">Data API</a> zapisuje výsledky přímo do databáze.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n<li><a href=\"/konzultace-filemaker\">Data API</a></li>\n<li><a href=\"/konzultace-filemaker\">PHP</a></li>\n<li><a href=\"/konzultace-filemaker\">TerraLab</a></li>\n</ul>', 'cs', 31),
(66, 'integration-with-terralab', 'Integration with TerraLab', 'Automated integration of FileMaker with the TerraLab laboratory system for efficient transfer of test requests and results.', 'Integration with TerraLab', 'Connecting FileMaker to the TerraLab laboratory system via API for automated test processing.', 'Automated integration of FileMaker with the TerraLab laboratory system for efficient transfer of test requests and results.', '<p><strong>The customer had two applications for different processes</strong>, one served as a database system for medical procedures, while the other, TerraLab, was used in a laboratory environment. The customer needed to connect these systems to streamline the transfer of laboratory test requests to TerraLab and the subsequent return of test results to the database system, a process that had previously been done manually.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Terralab_integration_illustration.jpg\" alt=\"Illustration of TerraLab laboratory system integration with FileMaker.\" /></div>\n<p>Based on specifications provided by the company that developed the TerraLab application, we <strong>integrated their API interface</strong>. When a doctor creates a laboratory test request, such as a blood test, in the FileMaker database, the request is automatically added to a processing queue and sent to TerraLab via the API. The request includes all the necessary information for the laboratory test, including patient details.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Terralab_integration_diagram.svg\" alt=\"Diagram of FileMaker and TerraLab API integration.\" /></div>\n<p>Upon completion of the laboratory tests, <strong>TerraLab calls the system\'\'s API endpoint</strong> and transmits the results. These results are automatically saved in the database, allowing the doctor to immediately view them and prepare a report for the patient. TerraLab triggers a PHP script on a web server, which then uses <a href=\"/filemaker-consulting\">Data API</a> to write the results directly into the database.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n<li><a href=\"/filemaker-consulting\">Data API</a></li>\n<li><a href=\"/filemaker-consulting\">PHP</a></li>\n<li><a href=\"/filemaker-consulting\">TerraLab</a></li>\n</ul>', 'en', 31),
(67, 'offline-sprava-merenych-hodnot-z-tovaren', 'Offline správa měřených hodnot z továren', 'Umožnění pracovníkům zadávat měřené hodnoty v místech bez internetu pomocí offline databáze ve FileMakeru.', 'Offline správa měřených hodnot z továren', 'Práce s databází ve FileMakeru bez nutnosti připojení k internetu a následná synchronizace dat.', 'Umožnění pracovníkům zadávat měřené hodnoty v místech bez internetu pomocí offline databáze ve FileMakeru.', '<p><strong>Zákazník potřeboval do svého řešení zakomponovat systém</strong>, který by umožnil jeho pracovníkům zadávat měřené hodnoty v továrnách i na místech bez přístupu k internetu, což doposud nebylo možné kvůli otevírání databáze ze serveru, kde je potřeba připojení k internetu.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Offline_updater.jpeg\" alt=\"Ilustrace offline správy měřených hodnot v továrnách pomocí FileMakeru.\" /></div>\r\n<p>Vytvořili jsme systém, který umožňuje pracovníkům <strong>ráno stáhnout kopii databáze s aktuálními daty</strong>, se kterou následně pracují během dne lokálně. Večer, když se pracovník vrátí do místa s přístupem k internetu, všechna aktualizovaná data nahraje zpět na server.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Offline_updater_diagram.svg\" alt=\"Diagram synchronizace offline databáze s online verzí.\" /></div>\r\n<p>Serverová databáze je synchronizována pomocí <strong>Bash skriptů a FileMakeru</strong>, které spravují zálohy a přenášejí data do správných složek. Upload je realizován přes FileMaker skript v lokální offline databázi s novými daty. Volá pomocí HTTP požadavku <a href=\"/toolbox\">Data API</a> na straně online verze, kam následně data propisuje.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n<li><a href=\"/toolbox\">Bash skripty</a></li>\r\n</ul>', 'cs', 32),
(68, 'offline-management-of-measured-values', 'Offline Management of Measured Values', 'Enabling workers to input measured values in locations without internet access using an offline FileMaker database.', 'Offline Management of Measured Values', 'Work with a FileMaker database without an internet connection and synchronize data afterward.', 'Enabling workers to input measured values in locations without internet access using an offline FileMaker database.', '<p><strong>The customer needed a system integrated into their solution</strong> that would enable their workers to input measured values in factories, even in locations without internet access. Previously, this was not possible due to the need to open the database directly from the server, which required an internet connection.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Offline_updater.jpeg\" alt=\"Illustration of offline management of measured values in factories using FileMaker.\" /></div>\r\n<p>We developed a system that allows workers to <strong>download a copy of the database with the latest data in the morning</strong>. They can then work locally with this database throughout the day. In the evening, when the worker returns to a location with internet access, all updated data is uploaded back to the server.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Offline_updater_diagram.svg\" alt=\"Diagram of offline database synchronization with the online version.\" /></div>\r\n<p>The server database is synchronized using <strong>Bash scripts and FileMaker</strong>, which manage backups and transfer data to the correct folders. The upload process is handled by a FileMaker script in the local offline database containing the new data. This script uses an HTTP request to the <a href=\"/toolbox\">Data API</a> in the online version to upload the data.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n<li><a href=\"/toolbox\">Bash scripts</a></li>\r\n</ul>', 'en', 32),
(69, 'integrace-power-bi', 'Integrace Power BI', 'Automatizovaný přenos dat z FileMakeru do Power BI pro efektivní analýzu a reporting.', 'Integrace Power BI', 'Bezpečný a efektivní přenos dat mezi FileMakerem a Power BI pomocí API a tokenové autentizace.', 'Automatizovaný přenos dat z FileMakeru do Power BI pro efektivní analýzu a reporting.', '<p><strong>Řetězec restaurací produkující vlastní koření</strong> potřeboval zefektivnit dohled nad procesy nákupu papriček, ze kterých je koření vyráběno. Vedení společnosti chtělo mít přístup k přesným a včasným reportům o objemech skoupených papriček a finančních transakcích. Tyto informace jsou evidovány pomocí FileMakerové aplikace JOGS, která je používána v každé lokaci, odkud jsou papričky skupovány. Jako hlavní reportovací nástroj si zákazník vybral <strong>Power BI</strong>.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Chilli_peppers_illustration.jpg\" alt=\"Ilustrace přenosu dat mezi FileMakerem a Power BI.\" /></div>\r\n<p>Pro synchronizaci dat jsme navrhli aplikaci, která <strong>každou noc shromažďuje nové informace</strong> z jednotlivých serverů a ukládá je na centrální server. Díky cachování je urychlen přístup k datům - není nutné pokaždé načítat živá data. Přístup k datům je zabezpečen pomocí <a href=\"/konzultace-filemaker\">tokenové autentizace</a> a samotná data jsou přenášena ve formátu <a href=\"/konzultace-filemaker\">JSON</a>, což umožňuje bezpečný a standardizovaný přístup pouze oprávněným uživatelům.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Chilli_peppers_diagram.svg\" alt=\"Diagram propojení FileMakeru s Power BI pomocí API.\" /></div>\r\n<p>Power BI přistupuje k datům prostřednictvím <strong>API námi vytvořené aplikace</strong>. API zpracuje každý požadavek podle předem definovaných parametrů a podle nastavení vrací buď předcachovaná data, nebo v případě potřeby živá data z jednotlivých lokalit. Tímto způsobem se Power BI napojuje na aktuální souhrnné informace a zobrazuje klíčové reporty managementu.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n<li><a href=\"/konzultace-filemaker\">JSON</a></li>\r\n<li><a href=\"/konzultace-filemaker\">Autentizace pomocí tokenů</a></li>\r\n<li><a href=\"/konzultace-filemaker\">Power BI</a></li>\r\n</ul>', 'cs', 33),
(70, 'integration-with-power-bi', 'Integration with Power BI', 'Automated data transfer from FileMaker to Power BI for efficient analysis and reporting.', 'Integration with Power BI', 'Secure and efficient data transfer between FileMaker and Power BI using API and token-based authentication.', 'Automated data transfer from FileMaker to Power BI for efficient analysis and reporting.', '<p><strong>A restaurant chain producing its own spices</strong> needed to streamline oversight of the purchasing processes for the peppers used in spice production. The company\'s management wanted access to accurate and timely reports on the volumes of peppers purchased and related financial transactions. This information was recorded using a FileMaker application, JOGS, deployed at each location where peppers were purchased. <strong>Power BI</strong> was chosen as the primary reporting tool.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Chilli_peppers_illustration.jpg\" alt=\"Illustration of data transfer between FileMaker and Power BI.\" /></div>\r\n<p>For data synchronization, we designed an application that <strong>collects new information every night</strong> from individual servers and stores it on a central server. Caching accelerates data access, eliminating the need to load live data for every request. Data access is secured using <a href=\"/filemaker-consulting\">token-based authentication</a>, and the data itself is transmitted in <a href=\"/filemaker-consulting\">JSON</a> format. This ensures secure and standardized access to the data for authorized users only.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Chilli_peppers_diagram.svg\" alt=\"Diagram of FileMaker and Power BI integration using API.\" /></div>\r\n<p>Power BI accesses the data through an <strong>API provided by our custom application</strong>. The API processes each request based on predefined parameters and returns either cached data or, if necessary, live data from individual locations. This approach enables Power BI to connect to up-to-date aggregate information and display key reports for management.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n<li><a href=\"/filemaker-consulting\">JSON</a></li>\r\n<li><a href=\"/filemaker-consulting\">Token-based authentication</a></li>\r\n<li><a href=\"/filemaker-consulting\">Power BI</a></li>\r\n</ul>', 'en', 33),
(71, 'sber-dat-z-meteostanice', 'Sběr dat z meteostanice', 'Automatizovaný sběr a zpracování meteorologických dat z meteostanice Davis Vantage Vue pomocí Raspberry Pi a FileMakeru.', 'Sběr dat z meteostanice', 'Nezávislý systém pro sběr a správu dat z meteostanice propojený s databázemi SQLite, PostgreSQL a FileMakerem.', 'Automatizovaný sběr a zpracování meteorologických dat z meteostanice Davis Vantage Vue pomocí Raspberry Pi a FileMakeru.', '<p><strong>Kolega nás oslovil s potřebou nezávislého meteorologického systému</strong>, který by sbíral aktuální data z lokální meteostanice. Tato data by sloužila k řízení několika propojených aplikací, včetně automatizovaného ovládání čerpadel zahradního jezírka podle venkovní teploty.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Weather_station_illustration.jpg\" alt=\"Ilustrace systému sběru dat z meteostanice pomocí Raspberry Pi a FileMakeru.\" /></div>\r\n<p>Pro sběr a správu dat jsme vytvořili komplexní systém využívající <strong>bezdrátovou meteostanici Davis Vantage Vue</strong> propojenou přes USB kabel s Raspberry Pi. Raspberry Pi pravidelně získává data z meteostanice a ukládá je lokálně do <a href=\"/hardware-integration\">SQLite databáze</a>. Tato data se každých pět minut přepisují do <a href=\"/hardware-integration\">PostgreSQL databáze</a> na vzdáleném serveru.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Weather_station_diagram.svg\" alt=\"Diagram integrace meteostanice s Raspberry Pi, FileMakerem a PostgreSQL.\" /></div>\r\n<p>Vyvinuli jsme <strong>univerzální FileMakerovou databázi</strong>, do které jsou data z PostgreSQL zapisována pomocí <a href=\"/hardware-integration\">ODBC ovladače</a>. Tato databáze propojuje různé senzory, poskytuje komplexní přehled o aktuálních podmínkách a zajišťuje efektivní řízení propojených zařízení.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n<li><a href=\"/hardware-integration\">Raspberry Pi</a></li>\r\n<li><a href=\"/hardware-integration\">SQLite databáze</a></li>\r\n<li><a href=\"/hardware-integration\">PostgreSQL databáze</a></li>\r\n<li><a href=\"/hardware-integration\">Meteostanice Davis Vantage Vue</a></li>\r\n</ul>', 'cs', 34),
(72, 'data-collection-from-a-weather-station', 'Data collection from a weather station', 'Automated collection and processing of meteorological data from a Davis Vantage Vue weather station using Raspberry Pi and FileMaker.', 'Data collection from a weather station', 'An independent system for collecting and managing weather station data integrated with SQLite, PostgreSQL, and FileMaker.', 'Automated collection and processing of meteorological data from a Davis Vantage Vue weather station using Raspberry Pi and FileMaker.', '<p><strong>A colleague approached us with the need for an independent meteorological system</strong> to collect real-time data from a local weather station. This data would be used to manage several interconnected applications, including the automated control of garden pond pumps based on outdoor temperatures.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Weather_station_illustration.jpg\" alt=\"Illustration of a weather station data collection system using Raspberry Pi and FileMaker.\" /></div>\n<p>To collect and manage data, we developed a comprehensive system utilizing a <strong>wireless Davis Vantage Vue weather station</strong> connected via USB cable to a Raspberry Pi. The Raspberry Pi regularly retrieves data from the weather station and stores it locally in an <a href=\"/hardware-integration\">SQLite database</a>. Every five minutes, this data is transferred to a <a href=\"/hardware-integration\">PostgreSQL database</a> hosted on a remote server.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Weather_station_diagram.svg\" alt=\"Diagram of integrating a weather station with Raspberry Pi, FileMaker, and PostgreSQL.\" /></div>\n<p>We developed a <strong>universal FileMaker database</strong>, where data from PostgreSQL is written using an <a href=\"/hardware-integration\">ODBC driver</a>. This database integrates various sensors, providing a comprehensive overview of current conditions and enabling efficient management of connected devices.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n<li><a href=\"/hardware-integration\">Raspberry Pi</a></li>\n<li><a href=\"/hardware-integration\">SQLite database</a></li>\n<li><a href=\"/hardware-integration\">PostgreSQL database</a></li>\n<li><a href=\"/hardware-integration\">Davis Vantage Vue weather station</a></li>\n</ul>', 'en', 34),
(73, 'reseni-pro-sledovani-ridicu-a-planovani-tras', 'Řešení pro sledování řidičů a plánování tras', 'Optimalizace tras doručovacích vozů a sledování jejich polohy v reálném čase pomocí FileMakeru a OpenStreetMap.', 'Řešení pro sledování řidičů a plánování tras', 'Sledování polohy vozů na mapě a efektivní plánování tras pomocí OpenStreetMap a Graphhopper API.', 'Optimalizace tras doručovacích vozů a sledování jejich polohy v reálném čase pomocí FileMakeru a OpenStreetMap.', '<p><strong>Zákazník potřeboval řešení pro zefektivnění tras řidičů</strong>, aby za co nejméně času stihli rozvést co nejvíce balíků. Součástí požadovaného řešení mělo být i sledování polohy řidičů na mapě a umožnění dispečerům zadávat trasy pro doručení zásilek. Cílem řešení bylo tento proces zefektivnit.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Driver_tracking_illustration.jpeg\" alt=\"Ilustrace sledování polohy řidičů na mapě a plánování tras pomocí FileMakeru.\" /></div>\r\n<p>Navrhli jsme aplikaci, která <strong>sbírá GPS souřadnice z iPadů</strong> umístěných v každém doručovacím vozu. Vytvořili jsme aplikaci ve FileMakeru a pomocí <a href=\"/cs/xgode\">Xgode</a> ji převedli na nativní aplikaci. Nativní aplikace je propojená s <a href=\"https://www.openstreetmap.org/#map=8/49.817/15.478\" target=\"_blank\">OpenStreetMap</a>, kde se zobrazuje poloha jednotlivých řidičů.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Driver_tracking_diagram.svg\" alt=\"Diagram sledování polohy vozidel a plánování tras pomocí OpenStreetMap a FileMakeru.\" /></div>\r\n<p>Dispečeři mohou <strong>zadávat trasy</strong>, v reálném čase sledovat polohu všech vozů a mít přehled o aktuálním průběhu doručení. Pro plánování tras bylo využito <a href=\"https://www.graphhopper.com\" target=\"_blank\">Graphhopper API</a>, které optimalizuje trasu doručování tak, aby řidiči urazili co nejméně kilometrů a nedocházelo ke zbytečnému vracení.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n<li><a href=\"https://www.openstreetmap.org/#map=8/49.817/15.478\" target=\"_blank\">OpenStreetMap</a></li>\r\n<li><a href=\"https://www.php.net\" target=\"_blank\">PHP</a></li>\r\n<li><a href=\"https://www.graphhopper.com\" target=\"_blank\">Graphhopper API</a></li>\r\n<li><a href=\"/cs/xgode\">Xgode</a></li>\r\n</ul>', 'cs', 35),
(74, 'solution-for-driver-tracking-and-route-planning', 'Solution for Driver Tracking and Route Planning', 'Optimizing delivery vehicle routes and tracking their locations in real time using FileMaker and OpenStreetMap.', 'Solution for Driver Tracking and Route Planning', 'Tracking vehicle locations on a map and efficiently planning routes using OpenStreetMap and Graphhopper API.', 'Optimizing delivery vehicle routes and tracking their locations in real time using FileMaker and OpenStreetMap.', '<p><strong>The customer required a solution to optimize driver routes</strong> so that they could deliver the maximum number of packages in the shortest time possible. The desired solution also needed to include driver location tracking on a map and enable dispatchers to assign delivery routes. The goal of the solution was to streamline this process.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Driver_tracking_illustration.jpeg\" alt=\"Illustration of driver tracking and route planning using FileMaker and OpenStreetMap.\" /></div>\n<p>We designed an application that <strong>collects GPS coordinates from iPads</strong> installed in each delivery vehicle. We developed the application in FileMaker and converted it into a native app using <a href=\"/cs/xgode\">Xgode</a>. The native app is integrated with <a href=\"https://www.openstreetmap.org/#map=8/49.817/15.478\" target=\"_blank\">OpenStreetMap</a>, where the locations of individual drivers are displayed.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Driver_tracking_diagram.svg\" alt=\"Diagram of vehicle tracking and route planning using OpenStreetMap and FileMaker.\" /></div>\n<p>Dispatchers can <strong>assign routes</strong>, track the location of all vehicles in real time, and monitor the current progress of deliveries. For route planning, <a href=\"https://www.graphhopper.com\" target=\"_blank\">Graphhopper API</a> was used to optimize delivery routes, minimizing the distance driven by the drivers and avoiding unnecessary backtracking.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n<li><a href=\"https://www.openstreetmap.org/#map=8/49.817/15.478\" target=\"_blank\">OpenStreetMap</a></li>\n<li><a href=\"https://www.php.net\" target=\"_blank\">PHP</a></li>\n<li><a href=\"https://www.graphhopper.com\" target=\"_blank\">Graphhopper API</a></li>\n<li><a href=\"/xgode\">Xgode</a></li>\n</ul>', 'en', 35),
(75, 'upozorneni-na-vyluky-vlaku', 'Upozornění na výluky vlaků', 'Systém automatického upozornění na výluky vlaků pomocí FileMaker Serveru a Pushover notifikací.', 'Upozornění na výluky vlaků', 'Automatizované sledování plánovaných výluk na trase a včasné notifikace na mobilní zařízení.', 'Systém automatického upozornění na výluky vlaků pomocí FileMaker Serveru a Pushover notifikací.', '<p><strong>Náš vývojář čelil problému</strong>, kdy často zjistil až na nástupišti, že jeho vlak má výluku, což způsobovalo zpoždění na cestě do práce. Rozhodl se proto vytvořit systém, který by dopředu upozorňoval na plánované výluky na konkrétní trase, aby mohl včas reagovat a případně přizpůsobit svůj plán cesty.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Traffic_disruptions_illustration.jpeg\" alt=\"Ilustrace automatického upozornění na výluky vlaků pomocí FileMaker Serveru.\" /></div>\n<p>Každý večer probíhá úloha na serveru, která pomocí funkce <strong>Insert from URL</strong> načte HTML stránku s informacemi o výlukách na zadané trase. HTML data jsou následně parsována, aby se zjistilo, zda jsou na dané trase naplánované výluky.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Traffic_disruptions_diagram.svg\" alt=\"Diagram automatizovaného systému upozornění na výluky vlaků.\" /></div>\n<p>V případě nalezení výluky na sledované trase je <strong>odeslána notifikace přes Pushover</strong> s odkazem na detailní informace o výluce, aby byl uživatel včas informován na svém mobilním zařízení.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker Server</a></li>\n<li><a href=\"https://pushover.net\" target=\"_blank\">Pushover</a></li>\n</ul>', 'cs', 36),
(76, 'train-disruption-alerts', 'Train Disruption Alerts', 'An automated train disruption alert system using FileMaker Server and Pushover notifications.', 'Train Disruption Alerts', 'Automated tracking of planned route disruptions and timely notifications to mobile devices.', 'An automated train disruption alert system using FileMaker Server and Pushover notifications.', '<p><strong>Our developer faced a recurring issue</strong> where he would only discover train disruptions upon arriving at the platform, causing delays on his way to work. To solve this, he developed a system that proactively notifies users of planned disruptions on specific routes, allowing them to adjust their travel plans accordingly.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Traffic_disruptions_illustration.jpeg\" alt=\"Illustration of an automated train disruption alert system using FileMaker Server.\" /></div>\n<p>Each evening, a server task uses the <strong>Insert from URL</strong> function to retrieve an HTML page containing disruption information for a specified route. The HTML data is then parsed to identify any planned disruptions on that route.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Traffic_disruptions_diagram.svg\" alt=\"Diagram of the automated train disruption alert system.\" /></div>\n<p>If a disruption is detected on the monitored route, a <strong>notification is sent via Pushover</strong> including a link to detailed information about the disruption, ensuring the user is informed in advance directly on their mobile device.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/filemaker-consulting\">FileMaker Server</a></li>\n<li><a href=\"https://pushover.net\" target=\"_blank\">Pushover</a></li>\n</ul>', 'en', 36),
(77, 'optimalizace-softwaru-pro-evidenci-techniky', 'Optimalizace softwaru pro evidenci techniky', 'Díky vlastním pluginům pro FileMaker jsme optimalizovali software pro evidenci techniky, čímž jsme dosáhli zrychlení výpočtů až tisícinásobně a výrazně zlepšili uživatelskou zkušenost.', 'Optimalizace softwaru pro evidenci techniky', 'Díky vlastním pluginům pro FileMaker jsme optimalizovali software pro evidenci techniky, čímž jsme dosáhli zrychlení výpočtů až tisícinásobně a výrazně zlepšili uživatelskou zkušenost.', 'Díky vlastním pluginům pro FileMaker jsme optimalizovali software pro evidenci techniky, čímž jsme dosáhli zrychlení výpočtů až tisícinásobně a výrazně zlepšili uživatelskou zkušenost.', '<p>Zákazník čelil problému s pomalým vyhodnocováním dostupnosti audiovizuální techniky v jejich specializovaném softwaru ve FileMakeru. Především v situaci, kdy bylo třeba rychle zjistit dostupnost zařízení na specifické období, software vykazoval časy výpočtů v řádu minut až desítek minut.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Optimization_of_software_illustration.jpg\" alt=\"Zákazník čelil problému s pomalým vyhodnocováním dostupnosti audiovizuální techniky\" /></div>\n<p>Navrhli jsme a implementovali <strong>vlastní plugin pro FileMaker</strong>, který optimalizoval klíčovou část výpočtu dostupnosti techniky. Namísto standardních metod výpočtů přímo v prostředí FileMakeru byl tento náročný proces přesunut do našeho plug-inu, který byl vyvinut a optimalizován speciálně pro tento typ výpočtů.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Optimization_of_software_diagram.svg\" alt=\"Vlastní plugin pro FileMaker optimalizoval klíčovou část výpočtu dostupnosti\" /></div>\n<p>Dosáhli jsme změny, která umožnila zobrazit výsledky <strong>téměř v reálném čase</strong>. Kromě původní optimalizace jsme v průběhu let plugin dále rozšiřovali o nové funkce a vylepšení, což vedlo k dalšímu zrychlení procesů. <strong>Celkové zlepšení dosáhlo tisícinásobného zrychlení</strong> oproti původní verzi.</p>\n<p>Toto řešení poskytlo zákazníkovi nejen technické zrychlení, ale také <strong>lepší uživatelskou zkušenost</strong>, protože software se stal intuitivnějším a flexibilnějším při práci s velkými objemy dat.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n<li><a href=\"/cs/tools\">FileMaker Plug-In SDK</a></li>\n</ul>', 'cs', 37),
(78, 'optimization-of-software-for-equipment-records', 'Optimization of Software for Equipment Records', 'We optimized a specialized FileMaker-based software for audiovisual equipment management, resulting in up to 1,000x faster calculations and a significantly improved user experience.', 'Optimization of Software for Equipment Records', 'We optimized a specialized FileMaker-based software for audiovisual equipment management, resulting in up to 1,000x faster calculations and a significantly improved user experience.', 'We optimized a specialized FileMaker-based software for audiovisual equipment management, resulting in up to 1,000x faster calculations and a significantly improved user experience.', '<p>The customer faced issues with slow evaluation of audiovisual equipment availability in their specialized FileMaker-based software. When checking device availability for a specific period, the system\'s calculation times ranged from minutes to tens of minutes, significantly slowing down operations.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Optimization_of_software_illustration.jpg\" alt=\"The customer faced issues with slow evaluation of audiovisual equipment availability\" /></div>\n<p>We designed and implemented a <strong>custom FileMaker plug-in</strong> to optimize the critical part of the availability calculation. Instead of using FileMaker’s standard methods, we offloaded the resource-intensive process to our plug-in, which was specifically developed and optimized for this type of computation.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Optimization_of_software_diagram.svg\" alt=\"Custom FileMaker plug-in to optimize availability calculation\" /></div>\n<p>This resulted in <strong>real-time availability results</strong>, significantly improving performance. Over the years, we further expanded the plug-in with new features and enhancements, achieving even greater speed improvements. <strong>Overall, the process was accelerated by a factor of 1,000</strong> compared to the original version.</p>\n<p>Beyond the technical speed-up, this solution enhanced the user experience, making the software more <strong>intuitive and flexible</strong> when handling large data volumes.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n<li><a href=\"/cs/tools\">FileMaker Plug-In SDK</a></li>\n</ul>', 'en', 37),
(79, 'integrace-a-propojeni-softwaru-pro-soukromou-skolu', 'Integrace a propojení softwarů pro soukromou školu', 'Integrací FileMaker, Daylight CRM, MoneyWorks a FreshBooks jsme propojili studijní, komunikační a účetní agendu soukromé školy, čímž jsme zefektivnili administrativu a snížili chybovost.', 'Integrace a propojení softwarů pro soukromou školu', 'Integrací FileMaker, Daylight CRM, MoneyWorks a FreshBooks jsme propojili studijní, komunikační a účetní agendu soukromé školy, čímž jsme zefektivnili administrativu a snížili chybovost.', 'Integrací FileMaker, Daylight CRM, MoneyWorks a FreshBooks jsme propojili studijní, komunikační a účetní agendu soukromé školy, čímž jsme zefektivnili administrativu a snížili chybovost.', '<p>Soukromá škola používala FileMaker pro evidenci rozvrhů, známek a studijních výsledků, CRM systém Daylight pro komunikaci a správu kontaktů, MoneyWorks pro účetnictví a FreshBooks pro fakturaci. Naším úkolem bylo tyto systémy propojit za účelem zefektivnění procesů.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Integration_of_software_for_school_illustration.jpg\" alt=\"Propojení studijních, komunikačních a účetních systémů soukromé školy\" /></div>\r\n<p>Navrhli jsme a implementovali <strong>integraci všech systémů do jedné databáze FileMaker</strong>, která slouží jako centrální bod pro veškerá data o studentech. Propojení s CRM Daylight umožňuje <strong>automatické přenášení e-mailové komunikace a kontaktů</strong> ke konkrétním studentům, takže je ve FileMakeru viditelné, co studijní oddělení řešilo a s kým.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Integration_of_software_for_school_diagram.svg\" alt=\"Synchronizace dat o platbách a fakturaci mezi MoneyWorks a FreshBooks\" /></div>\r\n<p>Synchronizace s účetním softwarem MoneyWorks zajistila, že škola měla vždy aktuální přehled o platbách studentů – informace o zaplacených i nezaplacených školních poplatcích se automaticky používají pro generování faktur na základě dat z FileMakeru. Faktury se automaticky vytvářejí pomocí API přímo ve FreshBooks, zatímco jejich obsah je generován ve FileMakeru.</p>\r\n<p>Díky této integraci má škola veškeré potřebné informace o studentech na jednom místě a eliminovala se i možnost zanášení chyb při ručním kopírování.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n<li><a href=\"https://www.marketcircle.com/daylite/\" target=\"_blank\">Daylight CRM</a></li>\r\n<li><a href=\"https://www.cognito.co.nz/\" target=\"_blank\">MoneyWorks (účetní software)</a></li>\r\n<li><a href=\"https://www.freshbooks.com/\" target=\"_blank\">FreshBooks (fakturační software)</a></li>\r\n</ul>', 'cs', 38);
INSERT INTO `skill_content` (`id`, `url`, `title`, `description`, `og_title`, `og_description`, `preview_text`, `html_content`, `id_lang`, `id_skill`) VALUES
(80, 'integration-and-connectivity-of-software-for-a-private-school', 'Integration and Connectivity of Software for a Private School', 'By integrating FileMaker, Daylight CRM, MoneyWorks, and FreshBooks, we streamlined private school operations, improved administration, and eliminated errors caused by manual data entry.', 'Integration and Connectivity of Software for a Private School', 'By integrating FileMaker, Daylight CRM, MoneyWorks, and FreshBooks, we streamlined private school operations, improved administration, and eliminated errors caused by manual data entry.', 'By integrating FileMaker, Daylight CRM, MoneyWorks, and FreshBooks, we streamlined private school operations, improved administration, and eliminated errors caused by manual data entry.', '<p>A private school used FileMaker for schedules and academic records, Daylight CRM for communication and contact management, MoneyWorks for accounting, and FreshBooks for invoicing. The challenge was to integrate these systems to streamline processes and eliminate manual data entry.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Integration_of_software_for_school_illustration.jpg\" alt=\"Integration of scheduling, communication, and accounting systems\" /></div>\r\n<p>We designed and implemented a <strong>central FileMaker database</strong> to unify all student-related data. The integration with Daylight CRM enables <strong>automatic synchronization of email communication and contacts</strong>, ensuring that all interactions with students are visible in FileMaker.</p>\r\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Integration_of_software_for_school_diagram.svg\" alt=\"Real-time synchronization of payments and invoicing between MoneyWorks and FreshBooks\" /></div>\r\n<p>MoneyWorks integration provides real-time visibility into student payments—paid and outstanding fees are automatically processed in FileMaker to generate invoices. These invoices are then created via API directly in FreshBooks, while their content is managed within FileMaker.</p>\r\n<p>This seamless integration has allowed the school to keep all student data in one place, reducing errors from manual data entry and improving administrative efficiency.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n<li><a href=\"https://www.marketcircle.com/daylite/\" target=\"_blank\">Daylight CRM</a></li>\r\n<li><a href=\"https://www.cognito.co.nz/\" target=\"_blank\">MoneyWorks (accounting software)</a></li>\r\n<li><a href=\"https://www.freshbooks.com/\" target=\"_blank\">FreshBooks (invoicing software)</a></li>\r\n</ul>', 'en', 38),
(81, 'automatizace-zakladani-prepravnich-objednavek', 'Automatizace zakládání přepravních objednávek', 'Automatizací procesu pomocí FileMaker a plug-inu ToolBox jsme eliminovali ruční přepisování přepravních objednávek a zjednodušili administrativu logistické firmy.', 'Automatizace zakládání přepravních objednávek', 'Automatizací procesu pomocí FileMaker a plug-inu ToolBox jsme eliminovali ruční přepisování přepravních objednávek a zjednodušili administrativu logistické firmy.', 'Automatizací procesu pomocí FileMaker a plug-inu ToolBox jsme eliminovali ruční přepisování přepravních objednávek a zjednodušili administrativu logistické firmy.', '<p>Zákazník požadoval <strong>automatizaci procesu zadávání přepravních objednávek</strong> od různých partnerů. Dříve bylo nutné objednávky ručně přepisovat do systému, což bylo časově náročné a náchylné k chybám. Cílem bylo vytvořit systém, který by automaticky získával data od partnerů.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Automated_order_creation_illustration.jpg\" alt=\"Automatizace procesu zadávání přepravních objednávek od různých partnerů\" /></div>\n<p>Vyvinuli jsme <strong>automatizovaný systém</strong>, který v pravidelných intervalech kontroluje FTP servery partnerů. FileMaker skript se díky našemu plug-inu ToolBox přihlásí k FTP, analyzuje soubory a parsuje jejich obsah podle pevně stanoveného formátu Fortras. Každá nová objednávka se automaticky vytvoří do systému bez nutnosti manuálního zadávání.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Automated_order_creation_diagram.svg\" alt=\"Systém analyzuje FTP servery a automaticky zakládá přepravní objednávky\" /></div>\n<p>Tento systém výrazně zjednodušil administrativu a <strong>eliminoval lidské chyby</strong>. Partneři nyní pouze nahrají soubor na svůj FTP server a systém se postará o zbytek.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n<li><a href=\"/cs/toolbox\">Toolbox</a></li>\n<!--<li>Fortras</li>-->\n</ul>', 'cs', 39),
(82, 'automation-of-transport-order-creation', 'Automation of Transport Order Creation', 'With an automated system based on FileMaker and the ToolBox plug-in, we eliminated manual order input and simplified the administration of a logistics company.', 'Automation of Transport Order Creation', 'With an automated system based on FileMaker and the ToolBox plug-in, we eliminated manual order input and simplified the administration of a logistics company.', 'With an automated system based on FileMaker and the ToolBox plug-in, we eliminated manual order input and simplified the administration of a logistics company.', '<p>The customer needed to <strong>automate the process of entering transport orders</strong> from various partners. Previously, orders had to be manually retyped into the system, which was time-consuming and error-prone. The goal was to create a system that would automatically retrieve order data from partners.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Automated_order_creation_illustration.jpg\" alt=\"Automating the transport order input from various partners\" /></div>\n<p>We developed an <strong>automated system</strong> that regularly checks partner FTP servers. Using our ToolBox plug-in, a FileMaker script logs into the FTP, analyzes the files, and parses their content according to the predefined Fortras format. Each new order is then automatically created in the system without manual input.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Automated_order_creation_diagram.svg\" alt=\"FTP analysis and automated transport order creation\" /></div>\n<p>This solution greatly simplified administration and <strong>eliminated human errors</strong>. Now, partners simply upload a file to their FTP server, and the system takes care of the rest.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n<li><a href=\"/cs/toolbox\">Toolbox</a></li>\n<!--<li>Fortras</li>-->\n</ul>', 'en', 39),
(83, 'automatizace-zakladani-tiketu-pomoci-api', 'Automatizace zakládání tiketů pomocí API', 'Automatizovali jsme proces zakládání tiketů z FileMakeru do Jitbitu pomocí API, čímž jsme odstranili nutnost ručního zadávání ID a zrychlili celý proces.', 'Automatizace zakládání tiketů pomocí API', 'Automatizovali jsme proces zakládání tiketů z FileMakeru do Jitbitu pomocí API, čímž jsme odstranili nutnost ručního zadávání ID a zrychlili celý proces.', 'Automatizovali jsme proces zakládání tiketů z FileMakeru do Jitbitu pomocí API, čímž jsme odstranili nutnost ručního zadávání ID a zrychlili celý proces.', '<p>Zákazník potřeboval <strong>automatizovat proces zakládání tiketů</strong> z FileMakeru do tiketovacího systému JitBit. Původní řešení spoléhá na poloautomatický proces, kde se tikety zakládaly pomocí e-mailu odeslaného z FileMakeru. Zákazník chtěl aplikovat možnosti API a nahradit e-mailové zakládání tiketů přímou komunikací mezi FileMakerem a tiketovacím systémem.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Automated_ticket_creation_illustration.jpg\" alt=\"Automatizovat proces zakládání tiketů mezi FileMakerem a JitBitem\" /></div>\r\n<p>Implementovali jsme <strong>Jitbit API integraci</strong> mezi FileMakerem a tiketovacím systémem Jitbit, která umožňuje automatické zakládání tiketů a přidávání komentářů přímo z FileMakeru. Při založení nového tiketu ve FileMakeru je zavoláno API, aby vytvořilo tiket přímo v systému. ID nově vytvořeného tiketu je automaticky vráceno a uloženo do FileMaker databáze. Díky tomuto propojení už není nutné ID tiketů zadávat ručně.</p>\r\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Automated_ticket_creation_diagram.svg\" alt=\"Automatické zakládání a aktualizace tiketů pomocí Jitbit API\" /></div>\r\n<p>Při aktualizaci stavu nebo při potřebě přidat komentář k existujícímu tiketu se opět využívá API, které zajistí, že komentář je přiřazen k odpovídajícímu tiketu podle jeho ID. Tento proces je plně automatizovaný a eliminuje nutnost zasílání e-mailů.</p>\r\n<p>Zákazník si přál do budoucna zcela eliminovat zakládání tiketů přes e-mail, protože API poskytuje spolehlivější a rychlejší řešení. Tato integrace představovala první krok v tomto směru.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\r\n<li><a href=\"https://www.jitbit.com\" target=\"_blank\">Jitbit</a></li>\r\n</ul>', 'cs', 40),
(84, 'automation-of-ticket-creation-via-api', 'Automation of Ticket Creation via API', 'We automated ticket creation from FileMaker into JitBit via API, eliminating manual ID entry and significantly speeding up the ticketing process.', 'Automation of Ticket Creation via API', 'We automated ticket creation from FileMaker into JitBit via API, eliminating manual ID entry and significantly speeding up the ticketing process.', 'We automated ticket creation from FileMaker into JitBit via API, eliminating manual ID entry and significantly speeding up the ticketing process.', '<p>The customer needed to <strong>automate the process of creating tickets</strong> from FileMaker into the JitBit ticketing system. The original solution relied on a semi-automatic process where tickets were created by sending an email from FileMaker. The customer wanted to leverage the JitBit API to replace email-based ticket creation with direct communication between FileMaker and JitBit.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Automated_ticket_creation_illustration.jpg\" alt=\"Automate ticket creation between FileMaker and JitBit\" /></div>\r\n<p>We implemented a <strong>JitBit API integration</strong> between FileMaker and JitBit, enabling automatic ticket creation and comment updates directly from FileMaker. When a new ticket is created in FileMaker, the system calls the API to generate a ticket directly in JitBit, and the newly created ticket’s ID is automatically returned and stored in the FileMaker database, eliminating the need for manual ID entry.</p>\r\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Automated_ticket_creation_diagram.svg\" alt=\"Automatic ticket creation and update using Jitbit API\" /></div>\r\n<p>When updating a ticket’s status or adding comments, the API ensures that comments are assigned to the correct ticket based on its ID. This fully automated process removes the need for email-based ticketing, making the workflow faster and more reliable.</p>\r\n<p>The customer’s long-term goal is to completely eliminate email-based ticket creation, and this integration was the first step toward achieving that.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\r\n<li><a href=\"https://www.jitbit.com\" target=\"_blank\">Jitbit</a></li>\r\n</ul>', 'en', 40),
(85, 'system-pro-spravu-tenderu-a-dokumentace', 'Systém pro správu tenderů a dokumentace', 'Automatizovali jsme správu tenderů včetně stahování podkladů, řízení přístupů a archivace dokumentů s využitím FileMakeru a cloudových úložišť.', 'Systém pro správu tenderů a dokumentace', 'Automatizovali jsme správu tenderů včetně stahování podkladů, řízení přístupů a archivace dokumentů s využitím FileMakeru a cloudových úložišť.', 'Automatizovali jsme správu tenderů včetně stahování podkladů, řízení přístupů a archivace dokumentů s využitím FileMakeru a cloudových úložišť.', '<p>Zákazník potřeboval <strong>aplikaci pro evidenci a správu tenderů</strong> s možností automatického stahování podkladů a řízeného sdílení dokumentů mezi členy týmu. Cílem bylo vytvořit řešení, které by umožnilo sledovat jednotlivé tendry od jejich zadání až po finální rozhodnutí. Bylo nutné zajistit, aby podklady k jednotlivým tendrům byly snadno dostupné oprávněným uživatelům, přičemž přístup k souborům musel být automaticky řízen.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Tender_and_document_management_illustration.jpg\" alt=\"Aplikace pro správu tenderů s automatizovaným stahováním a sdílením dokumentů\" /></div>\n<p>Vytvořili jsme aplikaci v prostředí FileMaker, která <strong>automaticky stahuje informace o tendrech z webového portálu</strong> prostřednictvím API a zajišťuje jejich další správu. Po stažení tendru si uživatelé mohou zvolit, zda mají o konkrétní tender zájem. V případě potvrzení aplikace automaticky vytvoří složku na cloudovém úložišti (Google Drive nebo OneDrive) a nahraje do ní všechny dostupné podklady. Složka se automaticky sdílí s uživateli, kteří jsou k tendru přiřazeni.</p>\n<p>Každý tender prochází několika stavy – od zájmu, přes přípravu nabídky, až po finální výsledek (úspěšný/neúspěšný). Po ukončení tendru se složka přesune do archivu a přístup k ní je následně omezen. Pokud je třeba složku znovu zpřístupnit, archivované soubory zůstávají na cloudu, ale mimo běžné uživatelské rozhraní.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Tender_and_document_management_diagram.svg\" alt=\"Automatická správa dokumentace a archivace tenderů\" /></div>\n<p>Aplikace zajišťuje přístup k podkladům přímo z FileMakeru, kde uživatelé mohou nahrávat vlastní dokumenty a přidávat je k tendru. Tyto dokumenty se automaticky ukládají na cloud a nezatěžují databázi.</p>\n<p>Pro komunikaci s cloudem byla implementována autentizace pomocí <strong>JSON Web Token (JWT)</strong>. V době vývoje FileMaker nativně nepodporoval tuto metodu, proto byla integrace zajištěna skriptem v PHP.</p>\n<p>Tento systém <strong>automatizuje proces správy tenderů</strong>, snižuje administrativní zátěž a zajišťuje, že podklady jsou dostupné pouze oprávněným osobám.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n<li><a href=\"/konzultace-filemaker\">Google Drive API</a></li>\n<li><a href=\"/konzultace-filemaker\">OneDrive API (Office 365)</a></li>\n<li><a href=\"/konzultace-filemaker\">JSON Web Token (JWT)</a></li>\n<li><a href=\"/konzultace-filemaker\">PHP</a></li>\n</ul>', 'cs', 41),
(86, 'tender-and-document-management-system', 'Tender and Document Management System', 'We automated tender management including document retrieval, permission control, and archiving using FileMaker and cloud storage services.', 'Tender and Document Management System', 'We automated tender management including document retrieval, permission control, and archiving using FileMaker and cloud storage services.', 'We automated tender management including document retrieval, permission control, and archiving using FileMaker and cloud storage services.', '<p>The customer needed an <strong>application for tracking and managing tenders</strong>, with automated document retrieval and controlled file sharing among team members. The goal was to streamline the tendering process from submission to final decision while ensuring that tender documents remained easily accessible to authorized users with automatically managed permissions.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Tender_and_document_management_illustration.jpg\" alt=\"Tender management application with automated document retrieval and sharing\" /></div>\n<p>We developed a FileMaker-based application that <strong>automatically retrieves tender information</strong> from a web portal via API and facilitates its management. Users can express interest in specific tenders, and upon confirmation, the system creates a dedicated folder on a cloud storage platform (Google Drive or OneDrive) and uploads all related documents. The folder is then automatically shared with assigned team members.</p>\n<p>Each tender progresses through multiple stages—from interest and proposal preparation to the final outcome (successful/unsuccessful). Completed tenders are archived, and access to their files is restricted. If needed, archived documents remain on the cloud but are hidden from regular user interfaces.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Tender_and_document_management_diagram.svg\" alt=\"Automatic document management and tender archiving\" /></div>\n<p>Users can upload their own documents directly from FileMaker, which are then automatically stored in the cloud instead of the database, preventing unnecessary storage load.</p>\n<p>To manage cloud authentication, we implemented <strong>JSON Web Token (JWT)</strong>. Since FileMaker did not natively support JWT at the time, the integration was handled via a custom PHP script.</p>\n<p>This system <strong>automates tender management</strong>, reduces administrative workload, and ensures secure document access for authorized users only.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n<li><a href=\"/filemaker-consulting\">Google Drive API</a></li>\n<li><a href=\"/filemaker-consulting\">OneDrive API (Office 365)</a></li>\n<li><a href=\"/filemaker-consulting\">JSON Web Token (JWT)</a></li>\n<li><a href=\"/filemaker-consulting\">PHP</a></li>\n</ul>', 'en', 41),
(87, 'automatizovane-sestaveni-ios-aplikaci', 'Automatizované sestavení iOS aplikací', 'Vyvinuli jsme webovou platformu, která umožňuje snadné a rychlé sestavení iOS aplikací bez nutnosti manuálních zásahů, díky integraci s Xcode a FileMaker.', 'Automatizované sestavení iOS aplikací', 'Vyvinuli jsme webovou platformu, která umožňuje snadné a rychlé sestavení iOS aplikací bez nutnosti manuálních zásahů, díky integraci s Xcode a FileMaker.', 'Vyvinuli jsme webovou platformu, která umožňuje snadné a rychlé sestavení iOS aplikací bez nutnosti manuálních zásahů, díky integraci s Xcode a FileMaker.', '<p>FileMaker iOS App SDK umožnil vývoj nativních iOS aplikací, avšak <strong>manuální proces sestavování aplikací byl zdlouhavý a komplikovaný</strong>. Vývojáři museli řešit správu Apple Developer účtů, konfiguraci Xcode, podpisy certifikátů a různé technické problémy při sestavování. Celý proces zpomaloval vývoj a vedl k chybám. Vývojáři se proto snažili sestavování aplikací minimalizovat a prováděli ho pouze v nezbytných případech.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Automated_iOS_app_build_illustration.jpg\" alt=\"Manuální proces sestavování aplikací byl zdlouhavý a komplikovaný\" /></div>\n<p>Jako řešení jsme vyvinuli <strong>webovou platformu</strong>, která umožňuje zákazníkům spravovat a sestavovat iOS aplikace prostřednictvím intuitivního uživatelského rozhraní. Frontend aplikace poskytuje možnosti pro výběr verze SDK, přidání pluginů, konfiguraci bezpečnostních nastavení a další parametry, které jsou důležité pro sestavení iOS aplikace. <strong>Celé sestavení aplikace je hotové do 15 minut</strong>.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Automated_iOS_app_build_process.png\" alt=\"Webová platforma pro sestavování iOS aplikací\" /></div>\n<p>Po výběru konfigurace systém automaticky odesílá požadavek backendu, kde běží buildovací pipeline postavená na Xcode. Backend kontroluje správnost nahraných certifikátů, provádí bezpečnostní kontroly a poté spustí buildovací proces.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Automated_iOS_app_build_diagram.svg\" alt=\"Automatická pipeline sestavení iOS aplikací\" /></div>\n<p>Celý proces běží v automatické smyčce, která čeká na nové buildy, a jakmile uživatel odešle požadavek na sestavení, pipeline zajistí kompletní sestavení aplikace, podepíše ji certifikátem a výsledný soubor uloží na server. Po úspěšném sestavení je uživatel informován e-mailem a může si aplikaci stáhnout buď přímo, nebo ji nahrát do App Store Connect. Po schválení se aplikace nahraje na App Store, kde si ji mohou stáhnout běžní uživatelé.</p>\n<p>Tento systém <strong>výrazně zjednodušil proces sestavení aplikací</strong> a eliminoval manuální zásahy.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n<li><a href=\"/cs/xgode\">Xcode</a></li>\n<li><a href=\"/cs/toolbox\">Bash</a></li>\n</ul>', 'cs', 42),
(88, 'automated-ios-app-build-process', 'Automated iOS App Build Process', 'We created a web platform for fast and fully automated iOS app builds using Xcode and FileMaker, removing the need for manual operations.', 'Automated iOS App Build Process', 'We created a web platform for fast and fully automated iOS app builds using Xcode and FileMaker, removing the need for manual operations.', 'We created a web platform for fast and fully automated iOS app builds using Xcode and FileMaker, removing the need for manual operations.', '<p>FileMaker iOS App SDK enabled the development of native iOS applications, but the <strong>manual build process was slow and complex</strong>. Developers had to manage Apple Developer accounts, Xcode configurations, certificate signing, and various technical issues. This process delayed development, led to errors, and made frequent builds impractical.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Automated_iOS_app_build_illustration.jpg\" alt=\"Manual build process was slow and complex\" /></div>\n<p>We developed a <strong>web-based platform</strong> that allows users to manage and build iOS apps through an intuitive interface. The frontend provides options to select SDK versions, add plugins, configure security settings, and adjust other essential parameters for app building. <strong>The entire process is completed within 15 minutes</strong>.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Automated_iOS_app_build_process.png\" alt=\"Web platform for iOS app building\" /></div>\n<p>After selecting the configuration, the system sends a request to the backend, where a build pipeline powered by Xcode takes over. The backend validates certificates, performs security checks, and initiates the build process.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Automated_iOS_app_build_diagram.svg\" alt=\"Automated iOS app build pipeline\" /></div>\n<p>The system runs in an automated loop, continuously waiting for new build requests. Once a user submits a request, the pipeline builds the app, signs it with a certificate, and stores the final file on the server. Upon successful completion, the user receives an email notification and can download the app directly or upload it to App Store Connect for distribution.</p>\n<p>This solution <strong>greatly simplified the app-building process</strong> and eliminated the need for manual intervention.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n<li><a href=\"/xgode\">Xcode</a></li>\n<li><a href=\"/toolbox\">Bash</a></li>\n</ul>', 'en', 42),
(90, 'digitalizace-knih-pro-apple-books', 'Digitalizace knih pro Apple Books', 'Automatizovali jsme tvorbu interaktivních e-knih ve formátu EPUB pro Apple Books pomocí FileMakeru, čímž jsme snížili náročnost ručních úprav a zvýšili kvalitu výstupu.', 'Digitalizace knih pro Apple Books', 'Automatizovali jsme tvorbu interaktivních e-knih ve formátu EPUB pro Apple Books pomocí FileMakeru, čímž jsme snížili náročnost ručních úprav a zvýšili kvalitu výstupu.', 'Automatizovali jsme tvorbu interaktivních e-knih ve formátu EPUB pro Apple Books pomocí FileMakeru, čímž jsme snížili náročnost ručních úprav a zvýšili kvalitu výstupu.', '<p>Pro zákazníky vytváříme <strong>interaktivní elektronické knihy</strong> s přidanou hodnotou určené pro vydání na Apple Books, na které máme vysoké kvalitativní požadavky. Standardní export z aplikace Pages sice vytvoří základní EPUB, ale bez interaktivních prokliků, videí či animací… Původně jsme je museli při každé změně zdrojového obsahu přidávat ručně, což bylo časově náročné. Naším cílem bylo tyto úpravy efektivně automatizovat.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Books_digitalization_illustration.jpg\" alt=\"Automatizovaná tvorba interaktivních e-knih pro Apple Books\" /></div>\n<p>Vyvinuli jsme <strong>FileMaker aplikaci</strong>, která zefektivňuje tvorbu e-knih. Uživatelé si v Pages připraví formátovaný dokument, který se následně vyexportuje do EPUB. Aplikace tento soubor rozbalí a pomocí akcí přidá obrázky, upraví formátování a vytvoří odkazy na kapitoly.</p>\n<p>Klíčovou součástí řešení je vyvinutý <strong>plugin pro rozšířené vyhledávání a nahrazování textu</strong>. Například lze definovat akce pomocí kterých se nastavuje formátování knihy, aby kniha vizuálně odpovídala požadavkům Apple Books.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Books_digitalization_diagram.svg\" alt=\"Plně automatizovaný proces generování EPUB knih\" /></div>\n<p>Jakmile jsou připraveny podklady pro knihu, serverová část aplikace provede finální generaci EPUB souboru s veškerým formátováním a optimalizací pro Apple Books. Tento proces je <strong>plně automatizovaný</strong> a může běžet několik hodin, přičemž výsledkem je finální EPUB, který je připraven k nahrání do Apple Books.</p>\n<p>S pomocí tohoto nástroje jsme už udělali desítky knih a díky kvalitě zpracování jsme se s nimi dostali mezi <strong>TOP 10 cookbooks na iBook Store</strong>.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"/konzultace-filemaker\">FileMaker</a></li>\n<li><a href=\"https://24u.cz/e-knihy\" target=\"_blank\">EPUB</a></li>\n</ul>', 'cs', 43),
(91, 'digitalization-of-books-for-apple-books', 'Digitalization of Books for Apple Books', 'We automated the creation of interactive EPUB e-books for Apple Books using FileMaker, improving output quality while minimizing manual editing effort.', 'Digitalization of Books for Apple Books', 'We automated the creation of interactive EPUB e-books for Apple Books using FileMaker, improving output quality while minimizing manual editing effort.', 'We automated the creation of interactive EPUB e-books for Apple Books using FileMaker, improving output quality while minimizing manual editing effort.', '<p>We create <strong>interactive electronic books</strong> with added value for our clients, intended for publication on Apple Books, where we maintain high-quality standards. While the standard export from the Pages application generates a basic EPUB, it lacks interactive links, videos, or animations. Originally, we had to manually add these elements every time the source content changed, which was time-consuming. Our goal was to automate these adjustments efficiently.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Books_digitalization_illustration.jpg\" alt=\"Automated creation of interactive e-books for Apple Books\" /></div>\n<p>We developed a <strong>FileMaker application</strong> that streamlines the e-book creation process. Users prepare a formatted document in Pages, which is then exported as an EPUB. The application automatically unpacks this file, adds images, adjusts formatting, and creates links to chapters.</p>\n<p>A key component of the solution is a <strong>custom plugin for advanced text search and replace</strong>. For example, actions can be defined to adjust the book’s formatting to meet Apple Book’s visual requirements.</p>\n<div class=\"image-preview diagram\"><img src=\"[[IMAGE_PATH]]Books_digitalization_diagram.svg\" alt=\"Fully automated EPUB generation process\" /></div>\n<p>Once the book materials are ready, the server-side application performs the final EPUB generation with full formatting and optimization for Apple Books. This process is <strong>fully automated</strong> and can take several hours, resulting in a final EPUB ready for upload to Apple Books.</p>\n<p>With the help of this tool, we have already created dozens of books, and thanks to the quality of our work, we have made it to the <strong>TOP 10 cookbooks on the iBook Store</strong>.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"/filemaker-consulting\">FileMaker</a></li>\n<li><a href=\"https://24u.cz/e-books\" target=\"_blank\">EPUB</a></li>\n</ul>', 'en', 43),
(92, 'hromadne-rozesilani-sms', 'Hromadné rozesílání SMS', 'Vyvinuli jsme webovou aplikaci pro hromadné rozesílání SMS s podporou SSO přihlášení, integrací se SMS bránou a možností sledování historie zpráv.', 'Hromadné rozesílání SMS', 'Vyvinuli jsme webovou aplikaci pro hromadné rozesílání SMS s podporou SSO přihlášení, integrací se SMS bránou a možností sledování historie zpráv.', 'Vyvinuli jsme webovou aplikaci pro hromadné rozesílání SMS s podporou SSO přihlášení, integrací se SMS bránou a možností sledování historie zpráv.', '<p>Zákazník potřeboval <strong>webovou aplikaci pro hromadné odesílání SMS zpráv</strong>. Cílem bylo vytvořit systém, ve kterém si uživatel snadno vybere jednotlivce nebo skupiny, kterým chce SMS odeslat, napíše zprávu a odešle ji.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Bulk_SMS_Sending_illustration.jpg\" alt=\"Webová aplikace pro hromadné odesílání SMS zpráv s výběrem skupin a příjemců\" /></div>\n<p>Vyvinuli jsme webovou aplikaci, která umožňuje uživatelům přihlášení prostřednictvím <strong>Windows Single Sign-On (SSO)</strong> a následné odesílání SMS prostřednictvím jednoduchého rozhraní. Uživatel si vybere příjemce buď jednotlivě, nebo může vybrat celou skupinu. Po zadání textu zprávy se SMS odešle prostřednictvím <strong>připojené hardwarové SMS brány</strong> umístěné v lokální síti. Tato brána obsahuje SIM kartu a umožňuje odesílání zpráv přes definované API, které jsme integrovali do aplikace. Navíc se díky SSO uživatelé přihlašují automaticky pomocí svého účtu bez nutnosti zadávat heslo.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Bulk_SMS_Sending_diagram.svg\" alt=\"Architektura systému s připojenou SMS bránou a SSO přihlášením\" /></div>\n<p>Webové rozhraní bylo navrženo tak, aby bylo přehledné a snadno použitelné. Po odeslání zprávy systém zobrazí potvrzení o úspěšném odeslání a uživatelé mají možnost procházet <strong>historii odeslaných SMS</strong>. Celé řešení je plně webové a běží na technologii <strong>Nette s SQL databází</strong> pro uchování kontaktů a záznamů o odeslaných zprávách.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"https://nette.org/cs/\" target=\"_blank\">Nette (PHP Framework)</a></li>\n<li><a href=\"/toolbox\">SQL</a></li>\n</ul>', 'cs', 44),
(93, 'bulk-sms-sending', 'Bulk SMS Sending', 'We developed a web application for bulk SMS messaging with SSO login, hardware gateway integration, and message history tracking.', 'Bulk SMS Sending', 'We developed a web application for bulk SMS messaging with SSO login, hardware gateway integration, and message history tracking.', 'We developed a web application for bulk SMS messaging with SSO login, hardware gateway integration, and message history tracking.', '<p>The client needed a <strong>web application that would allow for bulk SMS messaging</strong>. The goal was to create a system where users could easily select individuals or groups to whom they wanted to send SMS messages, write the message, and send it.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Bulk_SMS_Sending_illustration.jpg\" alt=\"Web application for bulk SMS messaging with group selection\" /></div>\n<p>We developed a web application that enables users to log in using <strong>Windows Single Sign-On (SSO)</strong> and then send SMS messages through a simple interface. Users can select recipients either individually or as an entire group. After entering the message text, the SMS is sent via a <strong>connected hardware SMS gateway</strong> located within the local network. This gateway contains a SIM card and allows message delivery through a defined API, which we integrated into the application. Thanks to SSO, users log in automatically with their account without having to enter a password.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Bulk_SMS_Sending_diagram.svg\" alt=\"System architecture with connected SMS gateway and SSO login\" /></div>\n<p>The web interface was designed to be clear and user-friendly. After sending the message, the system displays a confirmation of successful delivery, and users have the option to browse <strong>the history of sent SMS</strong>. The entire solution is fully web-based and runs on the <strong>Nette framework with an SQL database</strong> for storing contacts and records of sent messages.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"https://nette.org/en/\" target=\"_blank\">Nette (PHP Framework)</a></li>\n<li><a href=\"/toolbox\">SQL</a></li>\n</ul>', 'en', 44),
(94, 'webovy-rezervacni-portal-pro-letiste', 'Webový rezervační portál pro letiště', 'Vytvořili jsme online rezervační portál pro letiště propojený s FileMaker databází, který umožňuje snadnou rezervaci parkovacích míst pro letadla.', 'Webový rezervační portál pro letiště', 'Vytvořili jsme online rezervační portál pro letiště propojený s FileMaker databází, který umožňuje snadnou rezervaci parkovacích míst pro letadla.', 'Vytvořili jsme online rezervační portál pro letiště propojený s FileMaker databází, který umožňuje snadnou rezervaci parkovacích míst pro letadla.', '<p>Zákazník spravuje software ve FileMakeru pro řízení parkovacích míst pro letadla na letišti a hledal řešení, které by jeho klientům umožnilo <strong>jednoduchou a rychlou online rezervaci</strong>.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Web_reservation_portal_for_airport_illustration.jpg\" alt=\"Online rezervace parkovacích míst pro letadla přes jednoduchý formulář\" /></div>\r\n<p>Vyvinuli jsme webový rezervační portál, který se propojuje s FileMaker databází pomocí <strong>FileMaker Data API</strong>. Uživatelé mohou vyplnit formulář s informacemi o letu, jako je typ letadla, registrační číslo a čas příletu. Dále si mohou zaškrtnout volitelné služby, například catering nebo doplňování paliva. Pro bezproblémovou interakci FileMaker databáze a webu přes Data API jsme použily náš vlastní nástroj <strong>fmRESTor</strong>.</p>\r\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Web_reservation_portal_for_airport_diagram.svg\" alt=\"Propojení webového portálu s FileMaker databází pomocí Data API\" /></div>\r\n<p>Pokud je rezervace úspěšně zpracována, systém vygeneruje potvrzení a odešle jej e-mailem uživateli. V případě zrušení rezervace je změna okamžitě zaznamenána a uživatel dostane e-mail s potvrzením zrušení. Systém byl navržen tak, aby byl <strong>jednoduchý na používání</strong> a umožnil <strong>rychlé a bezproblémové rezervace</strong>.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n<li><a href=\"/konzultace-filemaker\">Claris FileMaker</a></li>\r\n<li><a href=\"/fmrestor\">FileMaker Data API</a></li>\r\n</ul>', 'cs', 45),
(95, 'web-reservation-portal-for-airport', 'Web Reservation Portal for Airport', 'We created an online reservation portal integrated with FileMaker, enabling aircraft parking reservations through a fast and simple interface.', 'Web Reservation Portal for Airport', 'We created an online reservation portal integrated with FileMaker, enabling aircraft parking reservations through a fast and simple interface.', 'We created an online reservation portal integrated with FileMaker, enabling aircraft parking reservations through a fast and simple interface.', '<p>The client manages a FileMaker-based software for controlling aircraft parking slots at an airport and was looking for a solution that would allow their clients to <strong>make simple and fast online reservations</strong>.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Web_reservation_portal_for_airport_illustration.jpg\" alt=\"Online reservation of aircraft parking slots through a simple form\" /></div>\r\n<p>We developed a web reservation portal integrated with the FileMaker database via the <strong>FileMaker Data API</strong>. Users can fill out a form with flight details, such as the aircraft type, registration number, and arrival time. They can also select optional services, such as catering or refueling. To ensure seamless interaction between the FileMaker database and the website through the Data API, we used our custom tool <strong>fmRESTor</strong>.</p>\r\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Web_reservation_portal_for_airport_diagram.svg\" alt=\"Integration between the web portal and FileMaker database via Data API\" /></div>\r\n<p>Once the reservation is successfully processed, the system generates a confirmation and sends it to the user by email. In case of a cancellation, the change is immediately recorded, and the user receives a cancellation confirmation via email. The system was designed to be <strong>user-friendly</strong> and enable <strong>quick and hassle-free reservations</strong>.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n<li><a href=\"/filemaker-consulting\">Claris FileMaker</a></li>\r\n<li><a href=\"/fmrestor\">FileMaker Data API</a></li>\r\n</ul>', 'en', 45),
(96, 'zefektivneni-servisniho-procesu-v-oblasti-zdravotnictvi', 'Zefektivnění servisního procesu v oblasti zdravotnictví', 'Mobilní aplikace vytvořená ve FileMakeru výrazně zjednodušila servis zdravotnických zařízení díky offline režimu, digitalizaci a automatickému zpracování dat.', 'Zefektivnění servisního procesu v oblasti zdravotnictví', 'Mobilní aplikace vytvořená ve FileMakeru výrazně zjednodušila servis zdravotnických zařízení díky offline režimu, digitalizaci a automatickému zpracování dat.', 'Mobilní aplikace vytvořená ve FileMakeru výrazně zjednodušila servis zdravotnických zařízení díky offline režimu, digitalizaci a automatickému zpracování dat.', '<p>Zákazník se zabývá <strong>servisem zdravotnických zařízení</strong>, jako jsou například dýchací přístroje, inkubátory nebo nemocniční lůžka. Technici, kteří prováděli servis přímo u zákazníků, používali papírové montážní listy, kde ručně vyplňovali informace o zákazníkovi, zařízení a provedených úkonech. Po návratu do kanceláře musely být tyto formuláře manuálně přepsány do systému, což bylo časově náročné a vedlo k častým chybám.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Streamlining_process_in_healtcare_illustration.jpg\" alt=\"Mobilní aplikace nahrazující papírové montážní listy pro zdravotnická zařízení\" /></div>\r\n<p>Vyvinuli jsme <strong>nativní mobilní aplikaci</strong>, která plně nahrazuje papírové montážní listy a zefektivňuje celý proces servisních služeb. Aplikace byla vytvořena ve FileMakeru a následně pomocí našeho nástroje Xgode zbuildována do nativní aplikace a nahrána na App Store. Technici nyní mohou veškeré servisní úkony zaznamenávat digitálně, přičemž aplikace umožňuje <strong>automatické vyplňování údajů na základě čárového kódu</strong> ze štítku nalepeného na zařízení.</p>\r\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Streamlining_process_in_healtcare_diagram.svg\" alt=\"Synchronizace dat ze servisní mobilní aplikace s účetním systémem\" /></div>\r\n<p>Aplikace také pracuje v <strong>offline režimu</strong>, což znamená, že technici mohou zadávat data i bez připojení k internetu. Jakmile se připojí k síti, může uživatel synchronizovat data se serverovou databází, kde jsou informace okamžitě dostupné účetnímu oddělení pro fakturaci. Celé rozhraní aplikace bylo navrženo tak, aby odpovídalo papírové verzi montážního listu, a technici tak nemuseli měnit své pracovní návyky. Součástí aplikace je i možnost <strong>digitálního podpisu přímo na iPadu</strong>, což usnadňuje potvrzení provedených servisních prací.</p>\r\n<p>Díky této digitalizaci se výrazně <strong>snížila chybovost</strong>, zkrátil se čas trávený technikem na místě, zrychlil se proces fakturace a technici mají vždy k dispozici <strong>aktuální data o zákaznících, zařízeních i servisní historii</strong>.</p>\r\n<h2>Použité technologie</h2>\r\n<ul>\r\n<li><a href=\"/konzultace-filemaker\">FileMaker Server</a></li>\r\n<li><a href=\"/cs/fmrestor\">Data API</a></li>\r\n<li><a href=\"/cs/xgode\">Xgode</a></li>\r\n</ul>', 'cs', 46),
(97, 'streamlining-the-service-process-in-healthcare', 'Streamlining the Service Process in Healthcare', 'A native FileMaker mobile app streamlined healthcare equipment service, supporting barcode scanning, offline mode, and instant data sync for invoicing.', 'Streamlining the Service Process in Healthcare', 'A native FileMaker mobile app streamlined healthcare equipment service, supporting barcode scanning, offline mode, and instant data sync for invoicing.', 'A native FileMaker mobile app streamlined healthcare equipment service, supporting barcode scanning, offline mode, and instant data sync for invoicing.', '<p>The client specializes in <strong>servicing medical equipment</strong> such as ventilators, incubators, or hospital beds. Technicians who performed on-site services at customer locations used paper service forms, where they manually recorded customer information, device details, and performed tasks. After returning to the office, these forms had to be manually entered into the system, which was time-consuming and often led to errors.</p>\r\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Streamlining_process_in_healtcare_illustration.jpg\" alt=\"Mobile app replacing paper service forms for medical equipment technicians\" /></div>\r\n<p>We developed a <strong>native mobile application</strong> that fully replaces paper service forms and significantly improves the entire service process. The application was created in FileMaker and then built into a native app using our Xgode tool and published on the App Store. Technicians can now record all service activities digitally. The application supports <strong>automatic data entry by scanning barcodes</strong> from device labels.</p>\r\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Streamlining_process_in_healtcare_diagram.svg\" alt=\"Data sync from mobile app to accounting system for service invoicing\" /></div>\r\n<p>The application also works in <strong>offline mode</strong>, allowing technicians to input data even without an internet connection. Once connected to the network, users can synchronize data with the server database, making the information immediately available to the accounting department for invoicing. The interface mimics the paper service form, so technicians can maintain their workflows. The app also supports <strong>digital signatures on iPad</strong>, making it easier to confirm completed service work.</p>\r\n<p>Thanks to this digitalization, <strong>errors were significantly reduced</strong>, technicians spent less time on-site, the invoicing process was accelerated, and they always have access to <strong>current data on customers, equipment, and service history</strong>.</p>\r\n<h2>Used technologies</h2>\r\n<ul>\r\n<li><a href=\"/filemaker-consulting\">FileMaker Server</a></li>\r\n<li><a href=\"/fmrestor\">Data API</a></li>\r\n<li><a href=\"/xgode\">Xgode</a></li>\r\n</ul>', 'en', 46),
(98, 'studentsky-portal-pro-spravu-studijnich-udaju', 'Studentský portál pro správu studijních údajů', 'Webový portál propojený s FileMaker databází umožňuje studentům přístup k výsledkům, rozvrhům a předmětům, čímž zefektivňuje administrativní procesy školy.', 'Studentský portál pro správu studijních údajů', 'Webový portál propojený s FileMaker databází umožňuje studentům přístup k výsledkům, rozvrhům a předmětům, čímž zefektivňuje administrativní procesy školy.', 'Webový portál propojený s FileMaker databází umožňuje studentům přístup k výsledkům, rozvrhům a předmětům, čímž zefektivňuje administrativní procesy školy.', '<p>Zákazník spravoval veškeré informace o studentech, předmětech, učitelích a studijních výsledcích v databázi FileMaker. Studenti však <strong>neměli jednoduchý způsob, jak k těmto údajům přistupovat online</strong>. Cílem bylo vytvořit webový studentský portál, který by jim toto umožnil.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Student_portal_illustration.jpg\" alt=\"Webový studentský portál s přístupem ke známkám, předmětům a rozvrhu\" /></div>\n<p>Vyvinuli jsme webovou aplikaci postavenou na frameworku <strong>Nette</strong>, která slouží jako studentský portál. Po přihlášení mají studenti přístup ke svým studijním výsledkům, aktuálním i historickým předmětům a rozvrhu hodin. Portál byl propojen s databází FileMaker prostřednictvím <strong>FileMaker PHP API</strong>, které umožňovalo přenos dat. Systém rovněž podporoval komunikaci mezi studenty a učiteli pomocí zpráv a notifikací.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Student_portal_diagram.svg\" alt=\"Architektura studentského portálu propojeného s databází FileMaker\" /></div>\n<p>V době vývoje nebylo k dispozici moderní FileMaker Data API, proto bylo využito starší propojení přes FileMaker PHP API. <strong>Celé řešení studentům usnadnilo přístup k důležitým studijním údajům</strong> a zefektivnilo administrativní procesy školy.</p>\n<h2>Použité technologie</h2>\n<ul>\n<li><a href=\"https://nette.org/cs/\" target=\"_blank\">Nette</a></li>\n<li><a href=\"/konzultace-filemaker\">Claris FileMaker</a></li>\n<li><a href=\"/fmrestor\">FileMaker PHP API</a></li>\n</ul>', 'cs', 47),
(99, 'student-portal-for-academic-data-management', 'Student Portal for Academic Data Management', 'A FileMaker-integrated web portal gives students access to grades, timetables, and subjects while streamlining school administration.', 'Student Portal for Academic Data Management', 'A FileMaker-integrated web portal gives students access to grades, timetables, and subjects while streamlining school administration.', 'A FileMaker-integrated web portal gives students access to grades, timetables, and subjects while streamlining school administration.', '<p>The client managed all information about students, courses, teachers, and academic results in a FileMaker database, but students <strong>lacked an easy way to access this information online</strong>. The goal was to develop a web-based student portal that would provide them with convenient access.</p>\n<div class=\"image-preview\"><img src=\"[[IMAGE_PATH]]Student_portal_illustration.jpg\" alt=\"Web student portal giving access to grades, subjects and schedules\" /></div>\n<p>We developed a web application based on the <strong>Nette framework</strong>, which serves as a student portal. After logging in, students can access their academic results, current and historical courses, and their class schedule. The portal was integrated with the FileMaker database using the <strong>FileMaker PHP API</strong>, enabling seamless data transfer. The system also supported communication between students and teachers via messages and notifications.</p>\n<div class=\"image-preview diagram-medium\"><img src=\"[[IMAGE_PATH]]Student_portal_diagram.svg\" alt=\"Architecture of the student portal integrated with FileMaker database\" /></div>\n<p>At the time of development, the modern FileMaker Data API was not yet available, so we used the older FileMaker PHP API integration. <strong>This solution significantly improved student access to academic data</strong> and streamlined the school’s administrative processes.</p>\n<h2>Used technologies</h2>\n<ul>\n<li><a href=\"https://nette.org/en/\" target=\"_blank\">Nette</a></li>\n<li><a href=\"/filemaker-consulting\">Claris FileMaker</a></li>\n<li><a href=\"/fmrestor\">FileMaker PHP API</a></li>\n</ul>', 'en', 47);
